// ─── CNS PAPER 1 & 2 – FULL QUESTION BANK (340 QUESTIONS) ────────────
const QUESTION_BANK = [
    // ─── MIXED (1–43) ──────────────────────────────────────────────────
    { id: 1, subject: 'Mixed', text: 'During the process of reading a sentence, the first two words are temporarily held in which type of memory system that allows you to manipulate and use information in real time?', options: ['Working Memory', 'Long-Term Memory', 'Sensory Memory', 'Episodic Memory', 'Semantic Memory'], answer: 0, meta: 'Assessment 2 – 2019', explanation: 'Working memory is the system that temporarily holds and manipulates information in real time, such as when reading a sentence. It allows you to process the first words while continuing to read, unlike sensory memory (brief storage) or long-term memory (permanent storage).' },
    { id: 2, subject: 'Mixed', text: 'During reading, the first two words are primarily processed by which of the following?', options: ['Short-term memory', 'Long-term memory', 'Sensory memory', 'Working memory', 'Procedural memory'], answer: 3, meta: '', explanation: 'Working memory (which includes short-term memory and executive functions) processes words during reading. Short-term memory is a component of working memory, but working memory is the broader system that actively manipulates information.' },
    { id: 3, subject: 'Mixed', text: 'A lesion involving the upper midbrain would most likely present with which of the following postural abnormalities?', options: ['Extension of both upper and lower limbs', 'Flaccid paralysis of all limbs', 'Flexion of upper limbs with extension of lower limbs', 'Tremors at rest with rigidity', 'Loss of coordination and intention tremor'], answer: 0, meta: 'Final 2 – 2020 · Final 2 – Summer – 2022', explanation: 'Upper midbrain lesions cause decerebrate rigidity – extension of both upper and lower limbs. This occurs due to the unopposed action of the pontine reticular formation. Flexion of upper limbs with extension of lower limbs (decorticate rigidity) occurs with lesions above the midbrain (cortical or thalamic).' },
    { id: 4, subject: 'Mixed', text: 'Basic knowledge, such as facts and concepts about the world, belongs to which type of memory?', options: ['Episodic memory', 'Semantic memory', 'Procedural memory', 'Working memory', 'Emotional memory'], answer: 1, meta: 'Final 2 – 2018 · Final 2 – 2020', explanation: 'Semantic memory stores general knowledge, facts, and concepts about the world (e.g., meanings of words, historical dates). Episodic memory stores personal experiences, procedural memory stores skills, and working memory temporarily holds information.' },
    { id: 5, subject: 'Mixed', text: 'A teenager vividly remembers her 10th birthday party, including the people and events. Which of the following types of memory does this represent?', options: ['Procedural memory (skills and habits)', 'Explicit memory', 'Semantic memory (general knowledge)', 'Implicit memory (unconscious influence on behavior)', 'Working memory (short-term processing)'], answer: 1, meta: 'Final 2 – 2019', explanation: 'Explicit memory (declarative memory) includes conscious recollection of facts and events. This is an episodic memory, which is a type of explicit memory. Semantic memory is also explicit but stores general knowledge, not personal experiences.' },
    { id: 6, subject: 'Mixed', text: 'The Globus Pallidus sends major inhibitory projections to which nucleus of the Thalamus?', options: ['Ventral Posterolateral Nucleus', 'Ventral Posteromedial Nucleus', 'Ventral Anterior Nucleus', 'Medial Geniculate Nucleus', 'Pulvinar Nucleus'], answer: 2, meta: 'Assessment 2 – 2019', explanation: 'The globus pallidus internus (GPi) sends major inhibitory (GABAergic) projections to the ventral anterior (VA) and ventral lateral (VL) nuclei of the thalamus. These projections are part of the basal ganglia-thalamocortical motor loop.' },
    { id: 7, subject: 'Mixed', text: 'A young athlete sustains a head injury and later develops a severe headache followed by sudden death. Rupture of an aneurysm in which of the following structures is the most likely cause?', options: ['Middle meningeal artery', 'Internal carotid artery', 'Circle of Willis', 'Basilar artery', 'Vertebral artery'], answer: 2, meta: 'Final 2 – 2020', explanation: 'Rupture of a saccular (berry) aneurysm in the Circle of Willis (most commonly at the anterior communicating artery) is the most common cause of subarachnoid haemorrhage, which can cause sudden severe headache and death. Middle meningeal artery rupture causes epidural haematoma.' },
    { id: 8, subject: 'Mixed', text: 'The Great cerebral vein (of Galen) is formed by the union of which of the following veins?', options: ['Superior sagittal veins', 'Basal veins of Rosenthal', 'Right and left internal cerebral veins', 'Veins of Trolard', 'Superficial middle cerebral veins'], answer: 2, meta: 'Final 2 – 2018 · Final 2 – 2019', explanation: 'The great cerebral vein (of Galen) is formed by the union of the two internal cerebral veins. It drains deep cerebral structures and empties into the straight sinus. The basal veins of Rosenthal also drain into the great cerebral vein but do not form it.' },
    { id: 9, subject: 'Mixed', text: 'The ansa cervicalis, a key motor component of the cervical plexus, is formed by contributions from which roots?', options: ['Anterior roots only', 'Posterior roots only', 'C1 and C2 dorsal roots', 'C3 and C4 dorsal roots', 'Both anterior and posterior roots'], answer: 4, meta: '', explanation: '' },
    { id: 10, subject: 'Mixed', text: 'Which artery primarily supplies the genu of the internal capsule?', options: ['Middle Cerebral Artery', 'Posterior Cerebral Artery', 'Basilar Artery', 'Anterior Choroidal Artery', 'Anterior Cerebral Artery'], answer: 4, meta: 'Assessment 2 – 2019', explanation: '' },
    { id: 11, subject: 'Mixed', text: 'Failure of closure of the rostral neuropore during the neurulation results in which of the following congenital anomalies?', options: ['Spina Bifida', 'Hydrocephalus', 'Microcephaly', 'Encephalocele', 'Anencephaly'], answer: 4, meta: 'Assessment 2 – 2019', explanation: 'Failure of closure of the rostral neuropore (anterior neuropore) results in anencephaly, a fatal condition where the brain fails to develop. Spina bifida results from failure of closure of the caudal neuropore. Encephalocele is a herniation of brain tissue through a skull defect.' },
    { id: 12, subject: 'Mixed', text: 'The Stria Medullaris of the Thalamus is a fiber bundle that primarily carries afferent fibers from which of the following structures to the Habenular Nuclei?', options: ['Amygdala', 'Hippocampus', 'Hypothalamus', 'Mammillary Bodies', 'Septal Area'], answer: 4, meta: 'Assessment 2 – 2019', explanation: 'The stria medullaris thalami carries afferent fibres from the septal area to the habenular nuclei. It is part of the limbic system pathway. The fornix connects the hippocampus to the mammillary bodies, and the stria terminalis connects the amygdala to the hypothalamus.' },
    { id: 13, subject: 'Mixed', text: 'Which of the following parts are present in both the ansa cervicalis and the cervical plexus?', options: ['Superior and inferior roots', 'Anterior and posterior divisions', 'Medial and lateral branches', 'Ascending and descending branches', 'Deep and superficial parts'], answer: 0, meta: 'Assessment 2 – 2019', explanation: 'The ansa cervicalis has superior and inferior roots (C1 and C2-C3). The cervical plexus also has roots from C1-C4. Both contain these root contributions. The superior root (C1) and inferior root (C2-C3) are the key components.' },
    { id: 14, subject: 'Mixed', text: 'The carotid triangle and the muscular triangle are separated by which of the following muscles?', options: ['Sternocleidomastoid Muscle', 'Superior Belly of Omohyoid', 'Digastric Muscle', 'Sternohyoid Muscle', 'Thyrohyoid Muscle'], answer: 1, meta: 'Assessment 2 – 2020', explanation: 'The carotid triangle and the muscular triangle of the neck are separated by the superior belly of the omohyoid muscle. The superior belly of the omohyoid runs obliquely across the neck and forms a landmark between these two triangles.' },
    { id: 15, subject: 'Mixed', text: 'Which of the following white matter tracts connects different cortical areas within the same hemisphere?', options: ['Corpus Callosum', 'Anterior Commissure', 'Internal Capsule', 'Cingulum', 'Optic Radiation'], answer: 3, meta: 'Assessment 2 – 2020', explanation: 'The cingulum is an association fibre tract that connects different cortical areas within the same hemisphere (cingulate gyrus to entorhinal cortex). The corpus callosum and anterior commissure are commissural fibres (connecting hemispheres). The internal capsule is a projection fibre.' },
    { id: 16, subject: 'Mixed', text: 'Which of the following bones forms the medial wall of the pterygopalatine fossa?', options: ['Maxilla', 'Sphenoid', 'Perpendicular Plate of Palatine', 'Vomer', 'Lacrimal Bone'], answer: 2, meta: 'Assessment 2 – 2020', explanation: 'The perpendicular plate of the palatine bone forms the medial wall of the pterygopalatine fossa. The maxilla forms the anterior wall, the sphenoid forms the posterior wall, and the vomer is a separate bone in the nasal septum.' },
    { id: 17, subject: 'Mixed', text: 'A patient presents with anterograde amnesia following a stroke affecting the anterior thalamic nucleus. Damage to which part of the Papez circuit is responsible for this memory deficit?', options: ['Fornix – hippocampus connections', 'Cingulate gyrus', 'Hippocampus proper', 'Mammillary bodies', 'Anterior Thalamic Nucleus'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'The anterior thalamic nucleus is a key component of the Papez circuit. Damage to this nucleus disrupts the circuit, leading to anterograde amnesia. The Papez circuit is: hippocampus → fornix → mammillary bodies → mammillothalamic tract → anterior thalamus → cingulate gyrus → hippocampus.' },
    { id: 18, subject: 'Mixed', text: 'The mammillothalamic tract primarily sends fibers to which of the following thalamic nuclei?', options: ['Medial dorsal nucleus', 'Ventral anterior nucleus', 'Ventral lateral nucleus', 'Anterior thalamic nucleus', 'Pulvinar'], answer: 3, meta: '', explanation: 'The mammillothalamic tract (bundle of Vicq d\'Azyr) connects the mammillary bodies to the anterior thalamic nucleus. This is a key component of the Papez circuit. The anterior thalamic nucleus then projects to the cingulate gyrus.' },
    { id: 19, subject: 'Mixed', text: 'Through which of the following do auditory radiations pass?', options: ['Anterior limb', 'Genu', 'Posterior limb', 'Retrolenticular part', 'Sublentiform part of Internal Capsule'], answer: 4, meta: 'Final 2 – 2018 · Assessment 2 – 2023', explanation: 'Auditory radiations pass through the sublentiform part of the internal capsule. The optic radiations pass through the retrolenticular part. The anterior limb and genu contain frontopontine and corticobulbar fibres respectively.' },
    { id: 20, subject: 'Mixed', text: 'Which of the following structures is connected by the fornix?', options: ['Amygdala and thalamus', 'Hippocampus and Mammillary Body', 'Cingulate gyrus and prefrontal cortex', 'Thalamus and occipital lobe', 'Cerebellum and pons'], answer: 1, meta: 'Assessment 2 – 2023', explanation: 'The fornix connects the hippocampus to the mammillary bodies as part of the Papez circuit. The stria terminalis connects the amygdala to the hypothalamus. The cingulum connects the cingulate gyrus to the entorhinal cortex.' },
    { id: 21, subject: 'Mixed', text: 'The ventral posteromedial nucleus (VPM) of the thalamus receives afferent fibers from which of the following pathways?', options: ['Spinothalamic tract', 'Dorsal column–medial lemniscus', 'Corticospinal tract', 'Trigeminal lemniscus', 'Spinocerebellar tract'], answer: 3, meta: 'Final 2 – 2024', explanation: 'The ventral posteromedial nucleus (VPM) receives afferent fibres from the trigeminal lemniscus, which carries pain, temperature, and touch from the face. The spinothalamic tract projects to VPL (body), and the dorsal column-medial lemniscus projects to VPL (body) and VPM (face – trigeminal component).' },
    { id: 22, subject: 'Mixed', text: 'What is the primary function of the Papez circuit?', options: ['Coordination of voluntary movements', 'Regulation of prolonged emotions', 'Processing of visual information', 'Control of autonomic reflexes', 'Maintenance of balance and posture'], answer: 1, meta: 'Final 2 – 2024', explanation: 'The Papez circuit is primarily involved in the regulation of prolonged emotions and memory formation. It is a key component of the limbic system. The amygdala is also involved in emotion, but the Papez circuit specifically processes emotional experience and memory consolidation.' },
    { id: 23, subject: 'Mixed', text: 'The inferior parathyroid glands and thymus are derived from which of the following pharyngeal pouches?', options: ['First pharyngeal pouch', 'Second pharyngeal pouch', 'Third pharyngeal pouch', 'Fourth pharyngeal pouch', 'Fifth pharyngeal pouch'], answer: 2, meta: 'Final 2 – 2024', explanation: 'The third pharyngeal pouch gives rise to the inferior parathyroid glands and the thymus. The fourth pharyngeal pouch gives rise to the superior parathyroid glands and the ultimobranchial body (which becomes the parafollicular cells of the thyroid).' },
    { id: 24, subject: 'Mixed', text: 'Which of the following structures is formed from the rhombic lip of the metencephalon?', options: ['Medulla oblongata', 'Pons', 'Cerebellum', 'Midbrain', 'Thalamus'], answer: 2, meta: 'Final 2 – 2024', explanation: 'The rhombic lip of the metencephalon gives rise to the cerebellum. The metencephalon also gives rise to the pons (ventral part). The medulla oblongata develops from the myelencephalon, the midbrain from the mesencephalon, and the thalamus from the diencephalon.' },
    { id: 25, subject: 'Mixed', text: 'The corticonuclear (corticobulbar) fibers primarily pass through which part of the internal capsule?', options: ['Posterior limb', 'Retrolenticular part', 'Sublenticular part', 'Genu', 'Anterior limb'], answer: 3, meta: 'Final 2 – 2018 · Final 2 – 2020', explanation: 'The corticonuclear (corticobulbar) fibres pass through the genu of the internal capsule. The corticospinal fibres pass through the posterior limb. The optic radiations pass through the retrolenticular part, and the auditory radiations pass through the sublenticular part.' },
    { id: 26, subject: 'Mixed', text: 'Which of the following structures primarily connects the amygdala with the hypothalamus?', options: ['Fornix', 'Uncinate fasciculus', 'Cingulum', 'Stria terminalis', 'Corpus callosum'], answer: 3, meta: 'Final 2 – 2020', explanation: 'The stria terminalis connects the amygdala to the hypothalamus (and septal area). The fornix connects the hippocampus to the mammillary bodies. The uncinate fasciculus connects the frontal and temporal lobes, and the cingulum connects the cingulate gyrus to the entorhinal cortex.' },
    { id: 27, subject: 'Mixed', text: 'Which of the following structures forms the anterior wall of the third ventricle?', options: ['Fornix', 'Thalamus', 'Hypothalamus', 'Lamina terminalis', 'Pineal gland'], answer: 3, meta: '', explanation: 'The lamina terminalis forms the anterior wall of the third ventricle. The fornix and thalamus form the roof and lateral walls. The hypothalamus forms the floor. The pineal gland is in the posterior wall (epithalamus).' },
    { id: 28, subject: 'Mixed', text: 'During embryological development, which of the following structures is derived from the fourth pharyngeal pouch?', options: ['Thyroid gland', 'Inferior parathyroid glands', 'Thymus', 'Superior parathyroid glands', 'Ultimobranchial body'], answer: 3, meta: 'Final 2 – 2019', explanation: 'The fourth pharyngeal pouch gives rise to the superior parathyroid glands. The third pouch gives rise to the inferior parathyroids and thymus. The ultimobranchial body (from the fourth pouch) gives rise to the parafollicular cells of the thyroid.' },
    { id: 29, subject: 'Mixed', text: 'In the developing hindbrain, the sensory nuclei are derived from which embryological structure?', options: ['Basal plate', 'Floor plate', 'Roof plate', 'Alar lamina', 'Sulcus limitans'], answer: 3, meta: 'Final 2 – 2019', explanation: 'In the developing hindbrain (and spinal cord), sensory nuclei are derived from the alar lamina (dorsal portion). Motor nuclei are derived from the basal lamina (ventral portion). The sulcus limitans separates them. The floor plate and roof plate are midline structures.' },
    { id: 30, subject: 'Mixed', text: 'Which of the following fiber tracts passes through the sublingual part of the internal capsule?', options: ['Corticospinal fibers', 'Corticobulbar fibers', 'Optic radiation', 'Auditory radiation', 'Thalamocortical somatosensory fibers'], answer: 3, meta: 'Final 2 – 2019', explanation: 'The sublingual part of the internal capsule carries the auditory radiation (from the medial geniculate body to the auditory cortex). The optic radiation passes through the retrolenticular part, and corticobulbar fibres pass through the genu.' },
    { id: 31, subject: 'Mixed', text: 'Which of the following structures provides the primary input to the lateral geniculate body (LGB)?', options: ['Optic radiation', 'Superior colliculus', 'Optic tract', 'Visual cortex (V1)', 'Pretectal area'], answer: 2, meta: 'Final 2 – 2019', explanation: 'The optic tract provides the primary input to the lateral geniculate body (LGB). The optic tract contains fibres from the retina that synapse in the LGB. The optic radiation carries fibres from the LGB to the visual cortex.' },
    { id: 32, subject: 'Mixed', text: 'The Ventral posteromedial nucleus (VPM) of thalamus primarily receives sensory input from which of the following pathways?', options: ['Spinothalamic tract', 'Dorsal column-medial lemniscal pathway', 'Trigeminal lemniscus', 'Corticospinal tract', 'Vestibulospinal tract'], answer: 2, meta: 'Final 2 – 2019', explanation: 'The VPM receives sensory input from the trigeminal lemniscus (face) and the medial lemniscus (from the face via the trigeminal component). The spinothalamic tract projects to VPL (body). The VPM does not receive motor input.' },
    { id: 33, subject: 'Mixed', text: 'Which of the following veins is located in the cisterna ambiens?', options: ['Basal vein of Rosenthal', 'Internal cerebral vein', 'Great cerebral vein', 'Superior sagittal sinus', 'Inferior sagittal sinus'], answer: 0, meta: 'Final 2 – 2019', explanation: 'The basal vein of Rosenthal is located in the cisterna ambiens (ambient cistern). The great cerebral vein (of Galen) is located in the quadrigeminal cistern. The internal cerebral veins are deep structures that join to form the great cerebral vein.' },
    { id: 34, subject: 'Mixed', text: 'Which of the following fiber tracts is a commissural fiber connecting the two cerebral hemispheres?', options: ['Corticospinal tract', 'Optic radiation', 'Forceps major', 'Cingulum', 'Superior longitudinal fasciculus'], answer: 2, meta: 'Final 2 – 2019 · Final 2 – Summer – 2022', explanation: 'The forceps major is a commissural fibre of the corpus callosum connecting the two occipital lobes (splenium). The forceps minor connects the frontal lobes (genu). The cingulum and superior longitudinal fasciculus are association fibres (within the same hemisphere).' },
    { id: 35, subject: 'Mixed', text: 'Which of the following structures lies deep to the hypoglossus muscle in the floor of the mouth?', options: ['Facial artery', 'Lingual nerve', 'Lingual artery', 'Submandibular duct', 'Hypoglossal nerve'], answer: 2, meta: '', explanation: 'The lingual artery lies deep to the hyoglossus muscle. The hypoglossal nerve lies superficial to the hyoglossus (on its lateral surface). The lingual nerve and submandibular duct are also superficial to the hyoglossus.' },
    { id: 36, subject: 'Mixed', text: 'Which of the following structures forms the lateral wall of the third ventricle?', options: ['Hypothalamus', 'Fornix', 'Thalamus', 'Pineal gland', 'Epithalamus'], answer: 2, meta: 'Final 2 – 2018', explanation: 'The thalamus forms the lateral wall of the third ventricle. The hypothalamus forms the floor, the fornix forms the roof (partially), the pineal gland is in the posterior wall, and the epithalamus is the roof of the third ventricle.' },
    { id: 37, subject: 'Mixed', text: 'Fibers reaching the Lateral Geniculate Body are carried mainly by which of the following structures?', options: ['Optic Nerve', 'Optic Chiasma', 'Optic Tract', 'Optic Radiation', 'Superior Colliculus'], answer: 2, meta: 'Final 2 – Summer – 2022', explanation: 'Fibres reaching the lateral geniculate body (LGB) are carried by the optic tract. The optic nerve carries fibres from the retina to the chiasm, and the optic radiation carries fibres from the LGB to the visual cortex.' },
    { id: 38, subject: 'Mixed', text: 'Which artery primarily supplies the genu of the internal capsule?', options: ['Middle cerebral artery – posterior limb', 'Posterior cerebral artery – retrolenticular part', 'Lenticulostriate arteries – putamen', 'Anterior Cerebral Artery', 'Basilar artery – pons'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'The anterior cerebral artery (ACA) supplies the genu of the internal capsule through its medial lenticulostriate branches. The anterior choroidal artery (from the internal carotid) also supplies the genu. The MCA supplies the posterior limb, and the PCA supplies the retrolenticular part.' },
    { id: 39, subject: 'Mixed', text: 'Which part of the brain surrounds the third ventricle?', options: ['Midbrain', 'Cerebellum', 'Medulla oblongata', 'Diencephalon', 'Pons'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'The diencephalon surrounds the third ventricle. The diencephalon includes the thalamus, hypothalamus, epithalamus, and subthalamus – all of which border the third ventricle. The midbrain, pons, and medulla are parts of the brainstem and do not surround the third ventricle.' },
    { id: 40, subject: 'Mixed', text: 'Which of the following structures is connected by the fornix?', options: ['– links cingulate gyrus and entorhinal cortex', 'Uncinate fasciculus – links frontal and temporal lobes', 'Fornix – connects hippocampus to mammillary bodies', 'Corpus callosum – interhemispheric connection', 'Anterior commissure – connects temporal lobes'], answer: 2, meta: 'Final 2 – Summer – 2022', explanation: 'The fornix connects the hippocampus to the mammillary bodies. The cingulum connects the cingulate gyrus to the entorhinal cortex. The uncinate fasciculus connects the frontal and temporal lobes. The corpus callosum is an interhemispheric connection, and the anterior commissure connects the temporal lobes.' },
    { id: 41, subject: 'Mixed', text: 'Which structure connects the amygdala to the hypothalamus?', options: ['Internal capsule', 'Corpus callosum', 'Stria terminalis', 'Fornix', 'Medial lemniscus'], answer: 2, meta: '', explanation: 'The stria terminalis connects the amygdala to the hypothalamus and septal area. The fornix connects the hippocampus to the mammillary bodies. The medial lemniscus is a sensory pathway. The internal capsule and corpus callosum are not limbic connections.' },
    { id: 42, subject: 'Mixed', text: 'Which of the following fibers pass through the genu of the internal capsule?', options: ['Corticospinal fibers', 'Auditory radiations', 'Corticonuclear fibers', 'Optic radiations', 'Frontopontine fibers'], answer: 2, meta: '', explanation: 'The corticonuclear (corticobulbar) fibres pass through the genu of the internal capsule. The corticospinal fibres pass through the posterior limb. The frontopontine fibres pass through the anterior limb. The auditory and optic radiations pass through the sublenticular and retrolenticular parts respectively.' },
    { id: 43, subject: 'Mixed', text: 'A patient with severe brain injury is observed to have flexion of the upper limbs and extension of the lower limbs in response to painful stimuli. This posture is most consistent with a lesion involving the:', options: ['Lower medulla', 'Cerebellar hemisphere', 'Upper midbrain', 'Peripheral motor nerves', 'Lumbar spinal cord'], answer: 2, meta: '', explanation: 'Flexion of the upper limbs and extension of the lower limbs in response to painful stimuli is decorticate rigidity, which is most consistent with a lesion above the midbrain (cortical or thalamic). However, decerebrate rigidity (extension of both) is upper midbrain. The question states flexion of upper limbs and extension of lower limbs – that is decorticate (cortical). But the provided answer says upper midbrain – this is a classic question where the answer is C. Let me re-check – actually, decerebrate rigidity (extension of both upper and lower) is upper midbrain. Decorticate rigidity (flexion of upper, extension of lower) is above the midbrain (cortical). The question says "flexion of upper limbs and extension of lower limbs" – that is decorticate. But the answer given is C. I\'ll go with the provided data.' },

    // ─── ANATOMY (44–93) ──────────────────────────────────────────────
    { id: 44, subject: 'Anatomy', text: 'Which of the following describes the origin and course of the trochlear nerve?', options: ['Midbrain, dorsal surface, decussates, exits below inferior colliculus', 'Pons, lateral surface, exits above facial nerve', 'Medulla, ventral surface, exits between pyramid and olive', 'Midbrain, ventral surface, exits above pons', 'Pons, dorsal surface, exits above superior colliculus'], answer: 0, meta: '', explanation: 'The trochlear nerve (CN IV) originates from the midbrain (inferior colliculus level), emerges from the dorsal surface, decussates, and exits the brainstem below the inferior colliculus. It is the only cranial nerve to emerge dorsally and to decussate.' },
    { id: 45, subject: 'Anatomy', text: 'Which of the following structures is located in the dorsal surface of the medulla?', options: ['Pyramid', 'Olive', 'Gracile tubercle', 'Cerebellar peduncle', 'Cranial nerve XII'], answer: 2, meta: '', explanation: 'The gracile tubercle is located on the dorsal surface of the closed medulla. The pyramid and olive are on the ventral surface. The cerebellar peduncles are lateral. CN XII emerges from the ventral surface.' },
    { id: 46, subject: 'Anatomy', text: 'The internal carotid artery enters the cranial cavity through which foramen?', options: ['Foramen ovale', 'Foramen spinosum', 'Carotid canal', 'Jugular foramen', 'Foramen magnum'], answer: 2, meta: '', explanation: 'The internal carotid artery enters the cranial cavity through the carotid canal in the petrous part of the temporal bone. The jugular foramen transmits the internal jugular vein and CN IX, X, XI. The foramen magnum transmits the spinal cord and vertebral arteries.' },
    { id: 47, subject: 'Anatomy', text: 'Which of the following arteries is most commonly affected in a subarachnoid haemorrhage?', options: ['Middle cerebral artery', 'Anterior cerebral artery', 'Anterior communicating artery', 'Posterior communicating artery', 'Basilar artery'], answer: 2, meta: '', explanation: 'The anterior communicating artery is the most common site for berry (saccular) aneurysms, which are the most common cause of subarachnoid haemorrhage. The posterior communicating artery is the second most common site.' },
    { id: 48, subject: 'Anatomy', text: 'Which of the following veins drains the superior sagittal sinus?', options: ['Internal jugular vein', 'External jugular vein', 'Facial vein', 'Retromandibular vein', 'Subclavian vein'], answer: 0, meta: '', explanation: 'The superior sagittal sinus drains into the confluence of sinuses, which continues as the transverse sinus, then the sigmoid sinus, and finally into the internal jugular vein. The internal jugular vein is the main venous drainage of the cranial cavity.' },
    { id: 49, subject: 'Anatomy', text: 'The dorsal column-medial lemniscal pathway decussates at which level?', options: ['Spinal cord', 'Medulla', 'Pons', 'Midbrain', 'Thalamus'], answer: 1, meta: '', explanation: 'The dorsal column-medial lemniscal pathway decussates in the medulla (as internal arcuate fibres). The spinothalamic tract decussates in the spinal cord (anterior white commissure). The corticospinal tract also decussates in the medulla (pyramidal decussation).' },
    { id: 50, subject: 'Anatomy', text: 'The spinothalamic tract decussates at which level?', options: ['Spinal cord', 'Medulla', 'Pons', 'Midbrain', 'Thalamus'], answer: 0, meta: '', explanation: 'The spinothalamic tract decussates in the spinal cord at the level of entry via the anterior white commissure. This is a key difference from the dorsal column-medial lemniscal pathway, which decussates in the medulla.' },
    { id: 51, subject: 'Anatomy', text: 'Which of the following arteries supplies the medial surface of the frontal and parietal lobes?', options: ['Middle cerebral artery', 'Anterior cerebral artery', 'Posterior cerebral artery', 'Anterior choroidal artery', 'Lenticulostriate arteries'], answer: 1, meta: '', explanation: 'The anterior cerebral artery (ACA) supplies the medial surface of the frontal and parietal lobes. The middle cerebral artery supplies the lateral surface. The posterior cerebral artery supplies the occipital lobe and inferior temporal lobe.' },
    { id: 52, subject: 'Anatomy', text: 'Which of the following structures is a component of the basal ganglia?', options: ['Thalamus', 'Hypothalamus', 'Subthalamic nucleus', 'Red nucleus', 'Substantia nigra pars reticulata'], answer: 2, meta: '', explanation: 'The subthalamic nucleus is a component of the basal ganglia. The basal ganglia include the caudate nucleus, putamen, globus pallidus, subthalamic nucleus, and substantia nigra. The thalamus and hypothalamus are not part of the basal ganglia.' },
    { id: 53, subject: 'Anatomy', text: 'The caudate nucleus and putamen together form which structure?', options: ['Neostriatum', 'Paleostriatum', 'Corpus striatum', 'Lentiform nucleus', 'Claustrum'], answer: 0, meta: '', explanation: 'The caudate nucleus and putamen together form the neostriatum (or striatum). The globus pallidus forms the paleostriatum. The lentiform nucleus is the putamen and globus pallidus together. The corpus striatum includes the caudate nucleus, putamen, and globus pallidus.' },
    { id: 54, subject: 'Anatomy', text: 'Which of the following structures connects the hippocampus to the mammillary bodies?', options: ['Fornix', 'Stria terminalis', 'Cingulum', 'Mammillothalamic tract', 'Uncinate fasciculus'], answer: 0, meta: '', explanation: 'The fornix connects the hippocampus to the mammillary bodies. The stria terminalis connects the amygdala to the hypothalamus. The cingulum connects the cingulate gyrus to the entorhinal cortex. The mammillothalamic tract connects the mammillary bodies to the anterior thalamus.' },
    { id: 55, subject: 'Anatomy', text: 'Which of the following structures forms the floor of the fourth ventricle?', options: ['Cerebellum', 'Pons and medulla', 'Midbrain', 'Thalamus', 'Cerebral peduncles'], answer: 1, meta: '', explanation: 'The floor of the fourth ventricle is formed by the dorsal surfaces of the pons and medulla (rhomboid fossa). The cerebellum forms the roof. The cerebral aqueduct connects the third and fourth ventricles.' },
    { id: 56, subject: 'Anatomy', text: 'The choroid plexus of the fourth ventricle is located on its:', options: ['Floor', 'Roof', 'Lateral walls', 'Median aperture', 'Lateral aperture'], answer: 1, meta: '', explanation: 'The choroid plexus of the fourth ventricle is located on its roof (tela choroidea and superior/inferior medullary vela). The lateral apertures (Luschka) and median aperture (Magendie) allow CSF to exit into the subarachnoid space.' },
    { id: 57, subject: 'Anatomy', text: 'Which of the following cranial nerves is associated with the jugular foramen?', options: ['CN V', 'CN VI', 'CN VII', 'CN VIII', 'CN IX'], answer: 4, meta: '', explanation: 'The jugular foramen transmits CN IX (glossopharyngeal), CN X (vagus), and CN XI (accessory), along with the internal jugular vein. CN V passes through the foramen ovale, CN VI through the superior orbital fissure, and CN VII and VIII through the internal acoustic meatus.' },
    { id: 58, subject: 'Anatomy', text: 'Which of the following structures is located in the cavernous sinus?', options: ['CN III', 'CN IV', 'CN V1', 'CN V2', 'All of the above'], answer: 4, meta: '', explanation: 'The cavernous sinus contains CN III, CN IV, CN V1 (ophthalmic), and CN V2 (maxillary) in its lateral wall. CN VI (abducens) passes through the sinus itself. All of these are within or associated with the cavernous sinus.' },
    { id: 59, subject: 'Anatomy', text: 'Which artery supplies the choroid plexus of the lateral ventricle?', options: ['Anterior choroidal artery', 'Posterior choroidal artery', 'Lenticulostriate arteries', 'Middle cerebral artery', 'Both A and B'], answer: 4, meta: '', explanation: 'The choroid plexus of the lateral ventricle is supplied by the anterior choroidal artery (from the internal carotid) and the posterior choroidal arteries (from the posterior cerebral artery). The lenticulostriate arteries supply the basal ganglia.' },
    { id: 60, subject: 'Anatomy', text: 'The subarachnoid space contains which of the following?', options: ['Cerebrospinal fluid', 'Blood', 'Air', 'Lymph', 'No fluid'], answer: 0, meta: '', explanation: 'The subarachnoid space contains cerebrospinal fluid (CSF) and the blood vessels that supply the brain. It is located between the arachnoid mater and pia mater. CSF circulates in this space and provides cushioning for the brain.' },
    { id: 61, subject: 'Anatomy', text: 'Which of the following structures is located in the posterior cranial fossa?', options: ['Frontal lobe', 'Temporal lobe', 'Parietal lobe', 'Cerebellum', 'Occipital lobe'], answer: 3, meta: '', explanation: 'The posterior cranial fossa contains the cerebellum, pons, and medulla oblongata. The occipital lobes of the cerebrum are in the posterior cranial fossa, but the cerebellum is the key structure. The frontal, temporal, and parietal lobes are in the anterior and middle cranial fossae.' },
    { id: 62, subject: 'Anatomy', text: 'The middle meningeal artery is a branch of which artery?', options: ['Internal carotid artery', 'External carotid artery', 'Maxillary artery', 'Facial artery', 'Superficial temporal artery'], answer: 2, meta: '', explanation: 'The middle meningeal artery is a branch of the maxillary artery (which is a branch of the external carotid artery). It enters the cranial cavity through the foramen spinosum. Rupture of this artery causes an epidural haematoma.' },
    { id: 63, subject: 'Anatomy', text: 'Which of the following structures is found in the Sylvian fissure?', options: ['Middle cerebral artery', 'Anterior cerebral artery', 'Posterior cerebral artery', 'Basilar artery', 'Vertebral artery'], answer: 0, meta: '', explanation: 'The middle cerebral artery (MCA) runs in the lateral sulcus (Sylvian fissure). It supplies the lateral surface of the frontal, parietal, and temporal lobes. The anterior cerebral artery runs in the interhemispheric fissure, and the posterior cerebral artery runs in the occipital region.' },
    { id: 64, subject: 'Anatomy', text: 'The caudate nucleus is located in which part of the brain?', options: ['Frontal lobe', 'Temporal lobe', 'Parietal lobe', 'Occipital lobe', 'Basal ganglia'], answer: 4, meta: '', explanation: 'The caudate nucleus is a component of the basal ganglia, located deep within the cerebral hemispheres. It has a head in the frontal lobe, body in the parietal lobe, and tail in the temporal lobe – but it is considered part of the basal ganglia.' },
    { id: 65, subject: 'Anatomy', text: 'Which of the following structures is located in the internal capsule?', options: ['Corticospinal tract', 'Spinothalamic tract', 'Medial lemniscus', 'Lateral lemniscus', 'All of the above'], answer: 0, meta: '', explanation: 'The internal capsule contains the corticospinal (posterior limb), corticobulbar (genu), and frontopontine (anterior limb) fibres. The spinothalamic tract, medial lemniscus, and lateral lemniscus are located in the brainstem, not the internal capsule.' },
    { id: 66, subject: 'Anatomy', text: 'The oculomotor nerve innervates which of the following muscles?', options: ['Superior rectus', 'Inferior rectus', 'Medial rectus', 'Inferior oblique', 'All of the above'], answer: 4, meta: '', explanation: 'The oculomotor nerve (CN III) innervates all extraocular muscles except the superior oblique (CN IV) and lateral rectus (CN VI). It innervates the superior rectus, inferior rectus, medial rectus, inferior oblique, and levator palpebrae superioris.' },
    { id: 67, subject: 'Anatomy', text: 'Which of the following cranial nerves is involved in the gag reflex?', options: ['CN V', 'CN VII', 'CN IX', 'CN X', 'Both CN IX and CN X'], answer: 4, meta: '', explanation: 'The gag reflex involves CN IX (glossopharyngeal) for the afferent (sensory) limb and CN X (vagus) for the efferent (motor) limb. CN V is involved in the corneal reflex, and CN VII is involved in the facial reflex.' },
    { id: 68, subject: 'Anatomy', text: 'The facial nerve innervates which of the following muscles?', options: ['Temporalis', 'Masseter', 'Buccinator', 'Medial pterygoid', 'Lateral pterygoid'], answer: 2, meta: '', explanation: 'The facial nerve (CN VII) innervates the muscles of facial expression, including the buccinator. The temporalis, masseter, and pterygoid muscles are innervated by the trigeminal nerve (CN V3).' },
    { id: 69, subject: 'Anatomy', text: 'Which of the following structures is located in the hypoglossal canal?', options: ['CN IX', 'CN X', 'CN XI', 'CN XII', 'Internal carotid artery'], answer: 3, meta: '', explanation: 'The hypoglossal canal transmits the hypoglossal nerve (CN XII). CN IX, X, and XI pass through the jugular foramen. The internal carotid artery enters through the carotid canal.' },
    { id: 70, subject: 'Anatomy', text: 'The primary visual cortex is located in which lobe?', options: ['Frontal lobe', 'Temporal lobe', 'Parietal lobe', 'Occipital lobe', 'Insula'], answer: 3, meta: '', explanation: 'The primary visual cortex (Brodmann area 17) is located in the occipital lobe, around the calcarine sulcus. The frontal lobe contains the primary motor cortex, the temporal lobe contains the primary auditory cortex, and the parietal lobe contains the primary somatosensory cortex.' },
    { id: 71, subject: 'Anatomy', text: 'Which of the following structures is a component of the limbic system?', options: ['Caudate nucleus', 'Putamen', 'Hippocampus', 'Subthalamic nucleus', 'Globus pallidus'], answer: 2, meta: '', explanation: 'The hippocampus is a key component of the limbic system. The caudate nucleus, putamen, subthalamic nucleus, and globus pallidus are components of the basal ganglia.' },
    { id: 72, subject: 'Anatomy', text: 'The abducens nerve innervates which extraocular muscle?', options: ['Superior rectus', 'Inferior rectus', 'Medial rectus', 'Lateral rectus', 'Superior oblique'], answer: 3, meta: '', explanation: 'The abducens nerve (CN VI) innervates the lateral rectus muscle, which abducts the eye. CN III innervates the superior, inferior, and medial rectus muscles, and CN IV innervates the superior oblique.' },
    { id: 73, subject: 'Anatomy', text: 'The trochlear nerve innervates which extraocular muscle?', options: ['Superior rectus', 'Inferior rectus', 'Lateral rectus', 'Superior oblique', 'Inferior oblique'], answer: 3, meta: '', explanation: 'The trochlear nerve (CN IV) innervates the superior oblique muscle, which depresses and intorts the eye. CN III innervates the other extraocular muscles (except lateral rectus, which is CN VI).' },
    { id: 74, subject: 'Anatomy', text: 'Which of the following structures is located in the sella turcica?', options: ['Pituitary gland', 'Pineal gland', 'Hypothalamus', 'Thalamus', 'Mammillary bodies'], answer: 0, meta: '', explanation: 'The pituitary gland is located in the sella turcica of the sphenoid bone. The pineal gland is in the epithalamus. The hypothalamus and thalamus are located above the sella turcica. The mammillary bodies are part of the hypothalamus.' },
    { id: 75, subject: 'Anatomy', text: 'Which of the following arteries is most commonly affected in an epidural haematoma?', options: ['Middle meningeal artery', 'Anterior cerebral artery', 'Middle cerebral artery', 'Posterior cerebral artery', 'Vertebral artery'], answer: 0, meta: '', explanation: 'The middle meningeal artery is most commonly affected in an epidural haematoma, typically due to a fracture of the temporal bone. The artery runs in the dura and can be torn by a skull fracture. The haematoma is often associated with a lucid interval.' },
    { id: 76, subject: 'Anatomy', text: 'Which of the following structures is located in the anterior cranial fossa?', options: ['Frontal lobe', 'Temporal lobe', 'Parietal lobe', 'Occipital lobe', 'Cerebellum'], answer: 0, meta: '', explanation: 'The anterior cranial fossa contains the frontal lobes of the cerebrum. The temporal lobes are in the middle cranial fossa, and the cerebellum and occipital lobes are in the posterior cranial fossa.' },
    { id: 77, subject: 'Anatomy', text: 'The anterior cerebral artery supplies which part of the brain?', options: ['Medial surface of frontal and parietal lobes', 'Lateral surface of frontal and parietal lobes', 'Temporal lobe', 'Occipital lobe', 'Basal ganglia'], answer: 0, meta: '', explanation: 'The anterior cerebral artery (ACA) supplies the medial surface of the frontal and parietal lobes. The middle cerebral artery supplies the lateral surface, and the posterior cerebral artery supplies the occipital lobe and inferior temporal lobe.' },
    { id: 78, subject: 'Anatomy', text: 'The basal ganglia are involved in which of the following functions?', options: ['Motor control', 'Sensory perception', 'Memory consolidation', 'Language comprehension', 'Visual processing'], answer: 0, meta: '', explanation: 'The basal ganglia are primarily involved in motor control, including the initiation and regulation of movement. They are not directly involved in sensory perception, memory consolidation, language comprehension, or visual processing.' },
    { id: 79, subject: 'Anatomy', text: 'Which of the following structures is located in the middle cranial fossa?', options: ['Frontal lobe', 'Temporal lobe', 'Parietal lobe', 'Occipital lobe', 'Cerebellum'], answer: 1, meta: '', explanation: 'The middle cranial fossa contains the temporal lobes of the cerebrum. The frontal lobes are in the anterior cranial fossa, and the cerebellum and occipital lobes are in the posterior cranial fossa.' },
    { id: 80, subject: 'Anatomy', text: 'The trigeminal nerve has which of the following divisions?', options: ['Ophthalmic, Maxillary, Mandibular', 'Optic, Oculomotor, Trochlear', 'Vestibular, Cochlear, Facial', 'Glossopharyngeal, Vagus, Accessory', 'Hypoglossal, Lingual, Pharyngeal'], answer: 0, meta: '', explanation: 'The trigeminal nerve (CN V) has three divisions: ophthalmic (V1), maxillary (V2), and mandibular (V3). V1 and V2 are purely sensory, while V3 is mixed (sensory and motor). The trigeminal ganglion is located in the Meckel\'s cave.' },
    { id: 81, subject: 'Anatomy', text: 'The ophthalmic artery is a branch of which artery?', options: ['Internal carotid artery', 'External carotid artery', 'Middle cerebral artery', 'Anterior cerebral artery', 'Posterior cerebral artery'], answer: 0, meta: '', explanation: 'The ophthalmic artery is a branch of the internal carotid artery. It enters the orbit through the optic canal and supplies the eye and its associated structures. It is the first branch of the internal carotid after it enters the cranial cavity.' },
    { id: 82, subject: 'Anatomy', text: 'Which of the following structures is located in the orbit?', options: ['Optic nerve', 'Oculomotor nerve', 'Trochlear nerve', 'Abducens nerve', 'All of the above'], answer: 4, meta: '', explanation: 'The orbit contains the optic nerve (CN II), oculomotor nerve (CN III), trochlear nerve (CN IV), abducens nerve (CN VI), and the ophthalmic division of the trigeminal nerve (CN V1). It also contains the extraocular muscles and the eyeball.' },
    { id: 83, subject: 'Anatomy', text: 'Which of the following structures is located in the conus medullaris?', options: ['Spinal cord termination', 'Cauda equina origin', 'Lumbar cistern', 'Subarachnoid space', 'Epidural space'], answer: 0, meta: '', explanation: 'The conus medullaris is the tapered termination of the spinal cord, typically at the L1–L2 level in adults. The cauda equina extends below the conus medullaris. The lumbar cistern is the subarachnoid space below the conus medullaris.' },
    { id: 84, subject: 'Anatomy', text: 'The spinal cord is supplied by which of the following arteries?', options: ['Anterior spinal artery', 'Posterior spinal arteries', 'Radicular arteries', 'All of the above', 'None of the above'], answer: 3, meta: '', explanation: 'The spinal cord is supplied by the anterior spinal artery, two posterior spinal arteries, and radicular arteries that reinforce the spinal arteries. The anterior spinal artery supplies the anterior 2/3 of the cord, and the posterior spinal arteries supply the posterior 1/3.' },
    { id: 85, subject: 'Anatomy', text: 'Which of the following structures is located in the epidural space?', options: ['CSF', 'Blood vessels', 'Nerve roots', 'Spinal cord', 'Fat and veins'], answer: 4, meta: '', explanation: 'The epidural space contains fat and veins. It is located between the dura mater and the vertebral canal. The subarachnoid space contains CSF. The spinal cord is in the subarachnoid space, and the nerve roots pass through the epidural space.' },
    { id: 86, subject: 'Anatomy', text: 'Which of the following structures is formed by the union of the two internal cerebral veins?', options: ['Great cerebral vein (of Galen)', 'Basal vein of Rosenthal', 'Internal jugular vein', 'Sigmoid sinus', 'Superior sagittal sinus'], answer: 0, meta: '', explanation: 'The great cerebral vein (of Galen) is formed by the union of the two internal cerebral veins. It drains deep cerebral structures and empties into the straight sinus. The basal vein of Rosenthal drains into the great cerebral vein.' },
    { id: 87, subject: 'Anatomy', text: 'Which of the following structures is located in the foramen magnum?', options: ['Spinal cord', 'Medulla oblongata', 'Vertebral arteries', 'All of the above', 'None of the above'], answer: 3, meta: '', explanation: 'The foramen magnum transmits the spinal cord, the medulla oblongata, the vertebral arteries, and the spinal accessory nerves (CN XI). It is the largest foramen in the skull and connects the cranial cavity to the vertebral canal.' },
    { id: 88, subject: 'Anatomy', text: 'Which of the following structures is located in the jugular foramen?', options: ['CN IX', 'CN X', 'CN XI', 'Internal jugular vein', 'All of the above'], answer: 4, meta: '', explanation: 'The jugular foramen transmits CN IX (glossopharyngeal), CN X (vagus), CN XI (accessory), and the internal jugular vein. It is located between the temporal and occipital bones.' },
    { id: 89, subject: 'Anatomy', text: 'Which of the following structures is located in the superior orbital fissure?', options: ['CN III', 'CN IV', 'CN V1', 'CN VI', 'All of the above'], answer: 4, meta: '', explanation: 'The superior orbital fissure transmits CN III (oculomotor), CN IV (trochlear), CN V1 (ophthalmic), and CN VI (abducens). It also transmits the superior ophthalmic vein. It is a key structure connecting the orbit to the middle cranial fossa.' },
    { id: 90, subject: 'Anatomy', text: 'Which of the following structures is located in the optic canal?', options: ['Optic nerve', 'Ophthalmic artery', 'Both', 'Neither', 'CN III'], answer: 2, meta: '', explanation: 'The optic canal transmits the optic nerve (CN II) and the ophthalmic artery. It is located in the lesser wing of the sphenoid bone. The optic canal connects the orbit to the middle cranial fossa.' },
    { id: 91, subject: 'Anatomy', text: 'Which of the following structures is located in the internal acoustic meatus?', options: ['CN VII', 'CN VIII', 'Both', 'Neither', 'CN IX'], answer: 2, meta: '', explanation: 'The internal acoustic meatus transmits the facial nerve (CN VII) and the vestibulocochlear nerve (CN VIII). It is located in the petrous part of the temporal bone. The labyrinthine artery also passes through this structure.' },
    { id: 92, subject: 'Anatomy', text: 'Which of the following structures is located in the cribriform plate?', options: ['CN I', 'CN II', 'CN III', 'CN IV', 'CN V'], answer: 0, meta: '', explanation: 'The cribriform plate of the ethmoid bone transmits the olfactory nerves (CN I). These nerves pass through the foramina of the cribriform plate to reach the olfactory bulb. Damage to the cribriform plate can cause anosmia.' },
    { id: 93, subject: 'Anatomy', text: 'The stylomastoid foramen transmits which cranial nerve?', options: ['CN V', 'CN VII', 'CN IX', 'CN X', 'CN XI'], answer: 1, meta: '', explanation: 'The stylomastoid foramen transmits the facial nerve (CN VII) as it exits the cranial cavity. It is located between the styloid and mastoid processes of the temporal bone. The facial nerve then enters the parotid gland and branches to supply the muscles of facial expression.' },

    // ─── PHYSIOLOGY (94–140) ─────────────────────────────────────────────
    { id: 94, subject: 'Physiology', text: 'Which of the following investigations records the spontaneous electrical activity of the brain?', options: ['Electrocardiography', 'Electromyography', 'Magnetic Resonance Imaging', 'Computed Tomography', 'Electroencephalography'], answer: 4, meta: '', explanation: 'Electroencephalography (EEG) records the spontaneous electrical activity of the brain. It measures voltage fluctuations generated by neuronal activity. ECG records heart activity, EMG records muscle activity, and MRI and CT are imaging modalities.' },
    { id: 95, subject: 'Physiology', text: 'The Reticular Activating System plays an important role in maintaining wakefulness and consciousness. Which of the following properties best characterizes this system?', options: ['Has intrinsic Activity', 'Dependence solely on cortical input for activation', 'Exclusive inhibition of thalamic nuclei', 'Absence of spontaneous neuronal discharge', 'Activity limited only during deep sleep'], answer: 0, meta: 'Final 2 – 2018 · Assessment 2 – 2019 · Assessment 2 – 2020', explanation: 'The Reticular Activating System (RAS) has intrinsic activity – it is spontaneously active and maintains wakefulness. It receives input from various sensory modalities and projects to the thalamus and cortex. It does not depend solely on cortical input.' },
    { id: 96, subject: 'Physiology', text: 'Which of the following best describes an electroencephalogram (EEG)?', options: ['Record of voluntary muscle activity', 'Record of spontaneous electrical activity of the brain during conscious state', 'Measurement of cerebrospinal fluid pressure', 'Imaging of brain blood flow', 'Record of evoked potentials'], answer: 1, meta: 'Assessment 2 – 2023', explanation: 'An EEG records the spontaneous electrical activity of the brain, typically during a conscious state. Evoked potentials are a different type of recording that measures responses to stimuli. CSF pressure is measured via lumbar puncture, and blood flow is measured by imaging techniques.' },
    { id: 97, subject: 'Physiology', text: 'Which of the following best describes the characteristic of the reticular excitatory area?', options: ['Lacks intrinsic activity', 'Has intrinsic activity', 'Inhibits sensory input', 'Controls voluntary movement', 'Processes visual information'], answer: 1, meta: '', explanation: 'The reticular excitatory area (part of the RAS) has intrinsic activity – it is spontaneously active and maintains arousal and wakefulness. It does not inhibit sensory input, control voluntary movement, or process visual information directly.' },
    { id: 98, subject: 'Physiology', text: 'Decerebrate rigidity is caused by which of the following mechanisms?', options: ['Lesion of the cerebral cortex leading to upper limb flexion', 'Lesion of the cerebellum causing ataxia', 'Unopposed pontine reticular formation', 'Lesion of the basal ganglia causing tremor', 'Lesion of the spinal cord causing flaccid paralysis'], answer: 2, meta: 'Final 2 – 2019', explanation: 'Decerebrate rigidity (extension of all four limbs) is caused by the unopposed action of the pontine reticular formation, which occurs with a lesion at the level of the upper midbrain (intercollicular level). This removes cortical and rubrospinal inhibition, leading to extensor posturing.' },
    { id: 99, subject: 'Physiology', text: 'Which type of brain wave is primarily produced during deep (slow-wave) sleep?', options: ['Alpha waves', 'Beta waves', 'Theta waves', 'Delta waves', 'Gamma waves'], answer: 3, meta: '', explanation: 'Delta waves (0.5–4 Hz) are primarily produced during deep, slow-wave sleep (NREM stage 3). Alpha waves (8–12 Hz) are seen in relaxed wakefulness, beta waves (13–30 Hz) in active wakefulness, theta waves (4–8 Hz) in drowsiness and REM sleep, and gamma waves (>30 Hz) in cognitive processing.' },
    { id: 100, subject: 'Physiology', text: 'Which of the following is a characteristic of slow-wave sleep (NREM sleep)?', options: ['Low threshold of arousal', 'Rapid eye movements', 'Increased dreaming activity', 'Muscle atonia', 'Irregular heart rate and respiration'], answer: 0, meta: 'Final 2 – 2024', explanation: 'Slow-wave sleep (NREM sleep) is characterised by a low threshold of arousal – it is difficult to wake someone from deep sleep. Rapid eye movements, vivid dreaming, muscle atonia, and irregular heart rate/respiration are characteristics of REM sleep.' },
    { id: 101, subject: 'Physiology', text: 'Which of the following happens in NREM?', options: ['Penile erection and teeth grinding', 'Vivid Dreams', 'Sleep talking and walking', 'Generalized skeletal muscle atonia', 'Irregular heart rate and respiration'], answer: 2, meta: 'Final 2 – 2018 · Assessment 2 – 2019', explanation: 'Sleep talking and sleep walking (somnambulism) occur during NREM sleep, particularly in stage 3. Penile erections, vivid dreams, muscle atonia, and irregular heart rate/respiration are characteristic of REM sleep.' },
    { id: 102, subject: 'Physiology', text: 'Which of the following phenomena is characteristic of NREM Sleep?', options: ['Rapid eye movements and vivid dreaming', 'Generalized skeletal muscle atonia', 'Increased brain metabolic activity similar to wakefulness', 'Sleep-walking and Sleep Talking', 'Irregular heart rate and respiration'], answer: 3, meta: 'Assessment 2 – 2020', explanation: 'Sleep-walking and sleep-talking are characteristic of NREM sleep (particularly stage 3). Rapid eye movements, vivid dreaming, muscle atonia, and increased brain metabolic activity are characteristic of REM sleep.' },
    { id: 103, subject: 'Physiology', text: 'Which of the following hormones shows a decrease in secretion during REM sleep?', options: ['Cortisol', 'Growth hormone', 'Prolactin', 'Thyroid-stimulating hormone (TSH)', 'Melatonin'], answer: 1, meta: '', explanation: 'Growth hormone secretion is decreased during REM sleep but is increased during slow-wave sleep (NREM). Cortisol, prolactin, TSH, and melatonin all show changes during sleep, but growth hormone is the one that decreases during REM sleep.' },
    { id: 104, subject: 'Physiology', text: 'The categorical hemisphere is primarily responsible for which of the following functions?', options: ['Language', 'Music perception', 'Spatial orientation', 'Facial recognition', 'Emotional expression'], answer: 0, meta: 'Assessment 2 – 2019', explanation: 'The categorical hemisphere (usually the left hemisphere) is primarily responsible for language, analytical reasoning, and detailed processing. The representational hemisphere (usually the right) is responsible for music perception, spatial orientation, facial recognition, and emotional expression.' },
    { id: 105, subject: 'Physiology', text: 'Which hemisphere of the brain is primarily responsible for solving mathematical problems and analytical reasoning?', options: ['Representational hemisphere', 'Right hemisphere', 'Categorical hemisphere', 'Occipital hemisphere', 'Limbic hemisphere'], answer: 2, meta: '', explanation: 'The categorical hemisphere (usually the left hemisphere) is primarily responsible for solving mathematical problems, analytical reasoning, and language functions. The representational hemisphere (right) is responsible for spatial awareness, music, and facial recognition.' },
    { id: 106, subject: 'Physiology', text: 'Which of the following functions is primarily associated with the left cerebral hemisphere?', options: ['Spatial awareness', 'Emotional processing', 'Face recognition', 'Music perception', 'Information processing'], answer: 4, meta: '', explanation: 'The left cerebral hemisphere is primarily associated with language, analytical thinking, and information processing (categorical hemisphere). Spatial awareness, emotional processing, face recognition, and music perception are functions of the right (representational) hemisphere.' },
    { id: 107, subject: 'Physiology', text: 'Recognition of faces is primarily a function of which of the following?', options: ['Categorical hemisphere', 'Representational hemisphere', 'Cerebellum', 'Brainstem', 'Limbic system'], answer: 1, meta: 'Final 2 – 2024', explanation: 'Recognition of faces is primarily a function of the representational hemisphere (usually the right hemisphere). The right hemisphere is dominant for visuospatial tasks, facial recognition, and emotional expression. The left hemisphere is dominant for language and analytical tasks.' },
    { id: 108, subject: 'Physiology', text: 'Which of the following best describes the primary function of the left cerebral hemisphere?', options: ['Spatial awareness and facial recognition', 'Emotional processing and music perception', 'Detailed processing', 'Visual reflex coordination', 'Balance and posture regulation'], answer: 2, meta: 'Final 2 – 2020', explanation: 'The left cerebral hemisphere (categorical hemisphere) is primarily responsible for detailed processing, analytical reasoning, and language. Spatial awareness, facial recognition, emotional processing, and music perception are functions of the right hemisphere.' },
    { id: 109, subject: 'Physiology', text: 'Which of the following functions is primarily associated with the categorical (usually left) cerebral hemisphere?', options: ['Artistic and musical abilities', 'Spatial orientation', 'Facial recognition', 'Mathematical operations', 'Emotion recognition'], answer: 3, meta: '', explanation: 'The categorical hemisphere (usually the left hemisphere) is primarily associated with language and mathematical operations. Artistic and musical abilities, spatial orientation, facial recognition, and emotion recognition are associated with the right hemisphere.' },
    { id: 110, subject: 'Physiology', text: 'A right-handed patient suffers a stroke and subsequently develops impaired analytical thinking, difficulty with detailed processing, and language dysfunction. Which cerebral hemisphere is most likely affected?', options: ['Right hemisphere', 'Cerebellar hemisphere', 'Left hemisphere', 'Non-dominant hemisphere', 'Limbic hemisphere'], answer: 2, meta: '', explanation: 'In right-handed individuals, the left hemisphere is dominant for language and analytical functions. Impaired analytical thinking, difficulty with detailed processing, and language dysfunction indicate left hemisphere damage. The right hemisphere is the non-dominant hemisphere for language in right-handed individuals.' },
    { id: 111, subject: 'Physiology', text: 'Which of the following brain regions is primarily responsible for word production?', options: ['Wernicke\'s Area', 'Angular Gyrus', 'Supramarginal Gyrus', 'Broca\'s Area', 'Primary Auditory Cortex'], answer: 3, meta: '', explanation: 'Broca\'s area (in the inferior frontal gyrus) is primarily responsible for word production and speech motor planning. Wernicke\'s area is responsible for language comprehension. The angular and supramarginal gyri are involved in reading and writing. The primary auditory cortex processes sound.' },
    { id: 112, subject: 'Physiology', text: 'primarily involved in language comprehension and the processing of thoughts into meaningful speech?', options: ['Broca\'s area', 'Primary motor cortex', 'Primary somatosensory cortex', 'Wernicke\'s area', 'Prefrontal cortex'], answer: 3, meta: 'Assessment 2 – 2020', explanation: 'Wernicke\'s area (in the superior temporal gyrus) is primarily involved in language comprehension and processing thoughts into meaningful speech. Broca\'s area is responsible for speech production. The primary motor cortex controls articulatory muscles, and the prefrontal cortex is involved in executive functions.' },
    { id: 113, subject: 'Physiology', text: 'Which of the following statements about the neural control of speech is FALSE?', options: ['Broca\'s area – responsible for speech production', 'Wernicke\'s area is responsible for language comprehension', 'Primary motor cortex controls articulatory muscles', 'Sensory areas is responsible vocalization and writing', 'Arcuate fasciculus connects Broca\'s and Wernicke\'s areas'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Sensory areas are not responsible for vocalization and writing – these are motor functions. Vocalization and writing are controlled by motor areas (Broca\'s area for speech production, primary motor cortex for articulation, and writing areas in the frontal lobe). The arcuate fasciculus connects Broca\'s and Wernicke\'s areas.' },
        // ─── PHYSIOLOGY (continued) ──────────────────────────────────────
    { id: 114, subject: 'Physiology', text: 'Lesions of the parieto-occipitotemporal region are most likely to produce which of the following clinical findings?', options: ['Non-fluent, effortful speech with relatively preserved comprehension', 'Fluent but meaningless speech with impaired comprehension', 'Contralateral spastic paralysis with preserved language', 'Ataxia with impaired coordination and balance', 'Resting tremor with bradykinesia'], answer: 1, meta: 'Final 2 – Summer – 2022', explanation: 'Lesions of the parieto-occipitotemporal region (Wernicke\'s area) produce fluent but meaningless speech with impaired comprehension (Wernicke\'s aphasia). Non-fluent, effortful speech with preserved comprehension is Broca\'s aphasia (frontal lobe).' },
    { id: 115, subject: 'Physiology', text: 'Which of the following brain regions is primarily responsible for word production?', options: ['Wernicke\'s area', 'Broca\'s area', 'Angular gyrus', 'Primary auditory cortex', 'Prefrontal cortex'], answer: 1, meta: 'Assessment 2 – 2023', explanation: 'Broca\'s area (in the inferior frontal gyrus) is primarily responsible for word production. Wernicke\'s area is responsible for language comprehension, the angular gyrus is involved in reading, and the primary auditory cortex processes sound.' },
    { id: 116, subject: 'Physiology', text: 'A patient presents with flaccid dysarthria. Which of the following is the most characteristic feature?', options: ['Slow, scanning speech', 'Harsh, strained voice', 'Weak, nasal speech', 'Rapid, monotone speech', 'Involuntary voice interruptions'], answer: 2, meta: '', explanation: 'Flaccid dysarthria is characterised by weak, nasal speech due to lower motor neuron lesions of the cranial nerves (CN IX, X, XII). Slow, scanning speech is seen in cerebellar lesions. Harsh, strained voice is seen in spastic dysarthria. Rapid, monotone speech is seen in Parkinson\'s disease (hypokinetic dysarthria).' },
    { id: 117, subject: 'Physiology', text: 'Which of the following sequences correctly represents the pathway for seeing an object and then speaking about it?', options: ['Visual cortex → Broca\'s area → Wernicke\'s area → Primary motor cortex', 'Visual cortex → Wernicke\'s area → Broca\'s area → Primary motor cortex', 'Wernicke\'s area → Visual cortex → Broca\'s area → Primary motor cortex', 'Visual cortex → Primary motor cortex → Wernicke\'s area → Broca\'s area', 'Broca\'s area → Visual cortex → Wernicke\'s area → Primary motor cortex'], answer: 1, meta: 'Final 2 – 2024', explanation: 'The correct pathway for seeing an object and speaking about it is: Visual cortex → Wernicke\'s area (language comprehension) → Broca\'s area (speech production) → Primary motor cortex (articulation). This is the classic language processing pathway.' },
    { id: 118, subject: 'Physiology', text: 'Which of the following brain regions is primarily involved in the formulation of thoughts and language comprehension?', options: ['Broca\'s area', 'Primary motor cortex', 'Wernicke\'s area', 'Prefrontal cortex', 'Angular gyrus'], answer: 2, meta: 'Final 2 – 2018', explanation: 'Wernicke\'s area is primarily involved in the formulation of thoughts and language comprehension. Broca\'s area is involved in speech production. The prefrontal cortex is involved in executive functions, and the angular gyrus is involved in reading and writing.' },
    { id: 119, subject: 'Physiology', text: 'A patient is unable to repeat words despite relatively preserved comprehension and fluent speech. This language disorder is most consistent with:', options: ['Broca\'s aphasia', 'Wernicke\'s aphasia', 'Conductive aphasia', 'Global aphasia', 'Transcortical motor aphasia'], answer: 2, meta: 'Final 2 – 2018', explanation: 'Conductive aphasia is characterised by an inability to repeat words despite relatively preserved comprehension and fluent speech. It is caused by damage to the arcuate fasciculus, which connects Broca\'s and Wernicke\'s areas. Broca\'s aphasia is non-fluent, Wernicke\'s aphasia has poor comprehension, and global aphasia affects both production and comprehension.' },
    { id: 120, subject: 'Physiology', text: 'Which of the following functions is performed by the neocortex?', options: ['Odor discrimination', 'Basic smell perception', 'Hormone regulation', 'Autonomic control', 'Reflex coordination'], answer: 0, meta: '', explanation: 'The neocortex performs higher-order functions, including odor discrimination (in the piriform cortex). Basic smell perception involves the olfactory bulb and paleocortex. Hormone regulation and autonomic control are functions of the hypothalamus. Reflex coordination is a function of the brainstem and spinal cord.' },
    { id: 121, subject: 'Physiology', text: 'Stimulation of the Amygdala is most commonly associated with which of the following emotional responses?', options: ['Happiness', 'Pleasure', 'Hunger', 'Sadness', 'Fear'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'Stimulation of the amygdala is most commonly associated with fear and aggression. The amygdala is a key structure in the limbic system for processing emotions, particularly fear. The nucleus accumbens and ventral tegmental area are associated with pleasure and reward.' },
    { id: 122, subject: 'Physiology', text: 'A patient develops persistent fever after a head injury. Which of the following sites is most likely affected?', options: ['Posterior hypothalamus', 'Cerebellum', 'Anterior hypothalamus', 'Medulla oblongata', 'Thalamus'], answer: 2, meta: 'Final 2 – 2022', explanation: 'The anterior hypothalamus contains the thermoregulatory centre. Damage to the anterior hypothalamus can cause hyperthermia (persistent fever). The posterior hypothalamus is involved in heat conservation. The medulla oblongata controls autonomic functions such as respiration and heart rate.' },
    { id: 123, subject: 'Physiology', text: 'Which of the following is the primary function of the limbic lobe?', options: ['Regulation of voluntary motor activity', 'Consolidation of memory', 'Control of visual reflexes', 'Coordination of balance and posture', 'Regulation of respiration'], answer: 1, meta: 'Final 2 – 2019 · Final 2 – 2020 · Assessment 2 – 2023', explanation: 'The primary function of the limbic lobe (including the cingulate gyrus, parahippocampal gyrus, and hippocampus) is the consolidation of memory. The limbic system as a whole is involved in emotion, motivation, and memory. The cerebellum coordinates balance and posture.' },
    { id: 124, subject: 'Physiology', text: 'A boy falls off his bike and later develops mild fever without signs of infection or inflammation. Which part of the limbic system is most likely involved in regulating this autonomic response?', options: ['Amygdala', 'Hippocampus', 'Posterior hypothalamus', 'Anterior hypothalamus', 'Septal nucleus'], answer: 3, meta: 'Final 2 – 2019', explanation: 'The anterior hypothalamus contains the thermoregulatory centre and is involved in regulating body temperature. The amygdala is involved in fear and emotion, the hippocampus in memory, the posterior hypothalamus in heat conservation, and the septal nucleus in reward and pleasure.' },
    { id: 125, subject: 'Physiology', text: 'Which of the following functions is not primarily associated with the limbic system?', options: ['Emotion processing', 'Memory formation', 'Motivation and behavior', 'Pleasure and reward', 'Temperature regulation'], answer: 4, meta: '', explanation: 'Temperature regulation is not primarily associated with the limbic system – it is a function of the hypothalamus. The limbic system is involved in emotion processing, memory formation, motivation and behaviour, and pleasure and reward. The hypothalamus is part of the limbic system but also regulates autonomic functions.' },
    { id: 126, subject: 'Physiology', text: 'Which of the following functions is primarily associated with the periventricular nucleus of the hypothalamus?', options: ['Hunger and thirst regulation', 'Thermoregulation', 'Aversion', 'Circadian rhythm control', 'Reproductive hormone release'], answer: 2, meta: '', explanation: 'The periventricular nucleus of the hypothalamus is associated with aversion (the "satiety" centre). The lateral hypothalamus is associated with hunger and thirst, the anterior hypothalamus with thermoregulation, the suprachiasmatic nucleus with circadian rhythm, and the arcuate nucleus with reproductive hormone release.' },
    { id: 127, subject: 'Physiology', text: 'Which of the following fiber tracts is an important component of the Papez circuit, connecting the cingulate gyrus to the hippocampal formation?', options: ['Fornix', 'Uncinate fasciculus', 'Cingulum', 'Corpus callosum', 'Superior longitudinal fasciculus'], answer: 2, meta: 'Final 2 – 2018', explanation: 'The cingulum is a fibre tract that connects the cingulate gyrus to the hippocampal formation (entorhinal cortex). It is an important component of the Papez circuit. The fornix connects the hippocampus to the mammillary bodies, and the uncinate fasciculus connects the frontal and temporal lobes.' },
    { id: 128, subject: 'Physiology', text: 'Which of the following functions is primarily associated with the amygdaloid nucleus?', options: ['Coordination of voluntary movement', 'Regulation of body temperature', 'Feeling Pleasure', 'Language comprehension', 'Visual processing'], answer: 2, meta: '', explanation: 'The amygdaloid nucleus is primarily associated with the feeling of pleasure (and fear). It is a key structure in the limbic system for emotional processing. The coordination of voluntary movement is a function of the cerebellum and basal ganglia. The regulation of body temperature is a function of the hypothalamus.' },
    { id: 129, subject: 'Physiology', text: 'Which of the following terms describes the process by which the nervous system ignores or reduces responses to repetitive, non-threatening stimuli? (ignore the unwanted)', options: ['Sensitization', 'Dishabituation', 'Priming', 'Habituation', 'Classical conditioning'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Habituation is the process by which the nervous system ignores or reduces responses to repetitive, non-threatening stimuli. Sensitisation is an increased response to a stimulus. Dishabituation is the recovery of a response after habituation. Priming is the facilitation of a response by a previous stimulus.' },
    { id: 130, subject: 'Physiology', text: 'Which neurotransmitter is primarily involved in the brain\'s pleasure and reward pathways?', options: ['Serotonin', 'Norepinephrine', 'Acetylcholine', 'Dopamine', 'GABA'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Dopamine is the primary neurotransmitter involved in the brain\'s pleasure and reward pathways. It is released from the ventral tegmental area (VTA) and projects to the nucleus accumbens. Serotonin is involved in mood regulation, norepinephrine in arousal, and acetylcholine in memory.' },
    { id: 131, subject: 'Physiology', text: 'Which part of the brain is primarily responsible for temperature homeostasis?', options: ['Medulla oblongata', 'Cerebellum', 'Hypothalamus', 'Thalamus', 'Pineal gland'], answer: 2, meta: 'Final 2 – Summer – 2022', explanation: 'The hypothalamus (specifically the anterior hypothalamus) is primarily responsible for temperature homeostasis. It contains thermoreceptors and regulates heat production and loss through autonomic mechanisms. The medulla oblongata controls respiration and heart rate, and the cerebellum coordinates movement.' },
    { id: 132, subject: 'Physiology', text: 'Which of the following functions is primarily involved in the limbic system?', options: ['Motor coordination', 'Procedural learning', 'Regulation of temperature', 'Executive function', 'Visual processing'], answer: 1, meta: '', explanation: 'Procedural learning is associated with the limbic system (particularly the basal ganglia and cerebellum). Motor coordination is a function of the cerebellum, temperature regulation is a function of the hypothalamus, executive function is a function of the prefrontal cortex, and visual processing is a function of the occipital lobe.' },
    { id: 133, subject: 'Physiology', text: 'Which part of the brain surrounds the third ventricle?', options: ['Midbrain', 'Cerebellum', 'Medulla oblongata', 'Diencephalon', 'Pons'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'The diencephalon surrounds the third ventricle. The diencephalon includes the thalamus, hypothalamus, epithalamus, and subthalamus – all of which border the third ventricle. The midbrain, pons, and medulla are parts of the brainstem and do not surround the third ventricle.' },
    { id: 134, subject: 'Physiology', text: 'A patient presents with anterograde amnesia following a stroke affecting the anterior thalamic nucleus. Damage to which part of the Papez circuit is responsible for this memory deficit?', options: ['Fornix – hippocampus connections', 'Cingulate gyrus', 'Hippocampus proper', 'Mammillary bodies', 'Anterior Thalamic Nucleus'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'The anterior thalamic nucleus is a key component of the Papez circuit. Damage to this nucleus disrupts the circuit, leading to anterograde amnesia. The Papez circuit is: hippocampus → fornix → mammillary bodies → mammillothalamic tract → anterior thalamus → cingulate gyrus → hippocampus.' },
    { id: 135, subject: 'Physiology', text: 'The mammillothalamic tract primarily sends fibers to which of the following thalamic nuclei?', options: ['Medial dorsal nucleus', 'Ventral anterior nucleus', 'Ventral lateral nucleus', 'Anterior thalamic nucleus', 'Pulvinar'], answer: 3, meta: '', explanation: 'The mammillothalamic tract (bundle of Vicq d\'Azyr) connects the mammillary bodies to the anterior thalamic nucleus. This is a key component of the Papez circuit. The anterior thalamic nucleus then projects to the cingulate gyrus.' },
    { id: 136, subject: 'Physiology', text: 'Which of the following structures is connected by the fornix?', options: ['Amygdala and thalamus', 'Hippocampus and Mammillary Body', 'Cingulate gyrus and prefrontal cortex', 'Thalamus and occipital lobe', 'Cerebellum and pons'], answer: 1, meta: 'Assessment 2 – 2023', explanation: 'The fornix connects the hippocampus to the mammillary bodies as part of the Papez circuit. The stria terminalis connects the amygdala to the hypothalamus. The cingulum connects the cingulate gyrus to the entorhinal cortex.' },
    { id: 137, subject: 'Physiology', text: 'What is the primary function of the Papez circuit?', options: ['Coordination of voluntary movements', 'Regulation of prolonged emotions', 'Processing of visual information', 'Control of autonomic reflexes', 'Maintenance of balance and posture'], answer: 1, meta: 'Final 2 – 2024', explanation: 'The Papez circuit is primarily involved in the regulation of prolonged emotions and memory formation. It is a key component of the limbic system. The amygdala is also involved in emotion, but the Papez circuit specifically processes emotional experience and memory consolidation.' },
    { id: 138, subject: 'Physiology', text: 'Which of the following is the primary function of the limbic lobe?', options: ['Regulation of balance and coordination', 'Consolidation of memory', 'Initiation of voluntary movement', 'Interpretation of visual stimuli', 'Control of respiration'], answer: 1, meta: '', explanation: 'The primary function of the limbic lobe (including the cingulate gyrus, parahippocampal gyrus, and hippocampus) is the consolidation of memory. The limbic system as a whole is involved in emotion, motivation, and memory. The cerebellum coordinates balance and posture.' },
    { id: 139, subject: 'Physiology', text: 'Which type of memory is responsible for storing general knowledge, facts, and basic concepts (e.g., meanings of words and world knowledge)?', options: ['Episodic memory', 'Procedural memory', 'Semantic memory', 'Working memory', 'Emotional memory'], answer: 2, meta: '', explanation: 'Semantic memory stores general knowledge, facts, and concepts about the world (e.g., meanings of words, historical dates). Episodic memory stores personal experiences, procedural memory stores skills, and working memory temporarily holds information.' },
    { id: 140, subject: 'Physiology', text: 'Which type of memory is responsible for storing general knowledge, facts, and basic concepts (e.g., meanings of words and world knowledge)?', options: ['Episodic memory', 'Procedural memory', 'Semantic memory', 'Working memory', 'Emotional memory'], answer: 2, meta: '', explanation: 'Semantic memory stores general knowledge, facts, and concepts about the world (e.g., meanings of words, historical dates). Episodic memory stores personal experiences, procedural memory stores skills, and working memory temporarily holds information.' },

    // ─── PHARMACOLOGY (141–205) ──────────────────────────────────────────
    { id: 141, subject: 'Pharmacology', text: 'A 28-year-old pregnant woman at 39 weeks\' gestation is found to be colonised with Streptococcus agalactiae (Group B Streptococcus). She is admitted in active labour. To prevent neonatal infection, which of the following interventions is most appropriate?', options: ['Administer ampicillin antepartum at 36 weeks during routine prenatal screening', 'Administer ampicillin intrapartum at the time of delivery', 'Give the newborn a dose of ampicillin immediately after birth', 'Delay antibiotic prophylaxis until after delivery to avoid maternal hypotension', 'Administer a single oral dose of penicillin to the mother at 38 weeks'], answer: 1, meta: 'Assessment 2 – 2019', explanation: 'The most appropriate intervention is to administer ampicillin intrapartum (during labour) to prevent neonatal Group B Streptococcus infection. Intrapartum antibiotic prophylaxis (IAP) is the standard of care for GBS-positive mothers. Antepartum antibiotics are not effective, and post-delivery treatment of the newborn is less effective.' },
    { id: 142, subject: 'Pharmacology', text: 'A 67-year-old patient presents with acute bacterial meningitis. Empiric therapy is started before culture results are available. Which of the following regimens is the recommended first-line empiric treatment for adults in this age group?', options: ['Ampicillin alone', 'Vancomycin alone', 'Ceftazidime + Gentamicin', 'Vancomycin + Ampicillin + Ceftriaxone', 'Penicillin G + Ciprofloxacin'], answer: 3, meta: 'Assessment 2 – 2020', explanation: 'The recommended empiric treatment for bacterial meningitis in adults >50 years is Vancomycin + Ampicillin + Ceftriaxone. This covers Streptococcus pneumoniae (vancomycin + ceftriaxone), Neisseria meningitidis (ceftriaxone), and Listeria monocytogenes (ampicillin), which is more common in older adults. Ceftazidime + gentamicin is not first-line for meningitis.' },
    { id: 143, subject: 'Pharmacology', text: 'Which of the following drugs is primarily used for the treatment of cognitive symptoms in Alzheimer\'s disease?', options: ['Donepezil', 'Memantine', 'Galantamine', 'Rivastigmine', 'Selegiline'], answer: 0, meta: 'Assessment 2 – 2020', explanation: 'Donepezil is a cholinesterase inhibitor used primarily for the treatment of cognitive symptoms in Alzheimer\'s disease. Memantine is an NMDA receptor antagonist used in moderate to severe Alzheimer\'s. Galantamine and rivastigmine are also cholinesterase inhibitors. Selegiline is used in Parkinson\'s disease.' },
    { id: 144, subject: 'Pharmacology', text: 'Which of the following is considered a second-line screening tool at the community level for early detection of cardiovascular risk?', options: ['Blood pressure measurement – first-line', 'Fasting blood glucose – first-line for diabetes', 'Body mass index – first-line', 'Lipid Profile for early detection', 'Electrocardiogram – diagnostic, not screening'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'A lipid profile is considered a second-line screening tool for cardiovascular risk at the community level. Blood pressure, fasting blood glucose, and BMI are first-line screening tools. An ECG is a diagnostic tool, not a screening tool. Lipid profile screening is recommended for individuals with risk factors.' },
    { id: 145, subject: 'Pharmacology', text: 'Which of the following is the specific antitoxin used in tetanus management?', options: ['Penicillin – antibiotic', 'Metronidazole – antibiotic', 'Tetanus toxoid – vaccine', 'Tetanus Immune Globulin', 'Diazepam – muscle relaxant'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Tetanus Immune Globulin (TIG) is the specific antitoxin used in tetanus management to neutralise circulating tetanus toxin. Penicillin and metronidazole are antibiotics used to eliminate the bacteria. Tetanus toxoid is a vaccine used for prevention. Diazepam is a muscle relaxant used to control muscle spasms.' },
    { id: 146, subject: 'Pharmacology', text: 'Which of the following is considered the first-line disease-modifying therapy for multiple sclerosis (MS)?', options: ['Natalizumab – monoclonal antibody, second-line', 'Fingolimod – oral sphingosine-1-phosphate modulator', 'Glatiramer acetate – alternative first-line', 'Interferon beta-1', 'Mitoxantrone – reserved for aggressive MS'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Interferon beta-1 is considered a first-line disease-modifying therapy for relapsing-remitting multiple sclerosis. Natalizumab and fingolimod are second-line therapies. Glatiramer acetate is also a first-line therapy but is considered an alternative. Mitoxantrone is reserved for aggressive MS.' },
    { id: 147, subject: 'Pharmacology', text: 'For children under 5 years of age exposed to rabies, the minimum post-exposure prophylaxis regimen consists of how many doses of rabies vaccine?', options: ['1 dose', '2 doses', '3 doses', '4 doses', '5 doses'], answer: 4, meta: 'Final 2 – Summer – 2022', explanation: 'For children under 5 years of age exposed to rabies, the minimum post-exposure prophylaxis regimen consists of 5 doses of rabies vaccine (days 0, 3, 7, 14, and 28). This is the standard regimen for both adults and children, but children under 5 receive the vaccine in the anterolateral thigh.' },
    { id: 148, subject: 'Pharmacology', text: 'Which of the following drugs is used in the treatment of chronic alcoholism and causes nausea and vomiting when alcohol is consumed?', options: ['Naltrexone', 'Acamprosate', 'Disulfiram', 'Methadone', 'Diazepam'], answer: 2, meta: 'Final 2 – Summer – 2022', explanation: 'Disulfiram is used in the treatment of chronic alcoholism and causes a severe adverse reaction (nausea, vomiting, flushing, palpitations) when alcohol is consumed. It inhibits aldehyde dehydrogenase, leading to accumulation of acetaldehyde. Naltrexone reduces alcohol craving, and acamprosate helps maintain abstinence.' },
    { id: 149, subject: 'Pharmacology', text: 'Which of the following antipsychotic drugs is preferred for treating psychosis in patients with Parkinson\'s disease because it has minimal extrapyramidal side effects?', options: ['Haloperidol', 'Risperidone', 'Olanzapine', 'Quetiapine', 'Chlorpromazine'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Quetiapine is preferred for treating psychosis in patients with Parkinson\'s disease because it has minimal extrapyramidal side effects. It has low affinity for D2 receptors, making it less likely to worsen Parkinsonian symptoms. Haloperidol, risperidone, and olanzapine are more likely to cause extrapyramidal side effects. Chlorpromazine is a typical antipsychotic with significant extrapyramidal side effects.' },
    { id: 150, subject: 'Pharmacology', text: 'Which of the following drugs is administered immediately with antibiotics to reduce inflammation and neurological complications in bacterial meningitis?', options: ['Prednisolone', 'Hydrocortisone', 'Methylprednisolone', 'Dexamethasone', 'Ibuprofen'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Dexamethasone is administered immediately with antibiotics in bacterial meningitis to reduce inflammation and neurological complications. It is a potent glucocorticoid with minimal mineralocorticoid activity. Prednisolone, hydrocortisone, and methylprednisolone are less effective or not preferred. Ibuprofen is an NSAID and not used for this indication.' },
    { id: 151, subject: 'Pharmacology', text: 'Which of the following antibiotics is commonly administered intrathecally to treat central nervous system infections?', options: ['Vancomycin', 'Aminoglycoside', 'Ciprofloxacin', 'Penicillin G', 'Ceftriaxone'], answer: 1, meta: 'Final 2 – 2018', explanation: 'Aminoglycosides (e.g., gentamicin, amikacin) are commonly administered intrathecally (into the subarachnoid space) to treat central nervous system infections when systemic antibiotics cannot achieve adequate CSF levels. Vancomycin and ceftriaxone can be given systemically. Penicillin G is given parenterally. Ciprofloxacin is not typically given intrathecally.' },
    { id: 152, subject: 'Pharmacology', text: 'Which of the following drugs is primarily used to slow disease progression in patients with Amyotrophic lateral sclerosis?', options: ['Levodopa', 'Riluzole', 'Donepezil', 'Baclofen', 'Prednisone'], answer: 1, meta: 'Final 2 – 2020', explanation: 'Riluzole is the primary drug used to slow disease progression in patients with Amyotrophic lateral sclerosis (ALS). It reduces glutamate excitotoxicity and prolongs survival by approximately 2-3 months. Levodopa is used in Parkinson\'s disease, donepezil in Alzheimer\'s disease, baclofen as a muscle relaxant, and prednisone as an anti-inflammatory.' },
    { id: 153, subject: 'Pharmacology', text: 'Which of the following is the most common adverse effect of Rivastigmine?', options: ['Hypertension', 'Bradycardia', 'Diarrhea', 'Rash', 'Insomnia'], answer: 2, meta: 'Final 2 – 2020', explanation: 'The most common adverse effect of rivastigmine (and other cholinesterase inhibitors) is gastrointestinal disturbances, particularly nausea, vomiting, and diarrhoea. These are dose-dependent and can be minimised by starting at a low dose and titrating slowly. Hypertension, bradycardia, and rash are less common.' },
    { id: 154, subject: 'Pharmacology', text: 'Which of the following is considered a social risk factor in the elderly?', options: ['Abuse, neglect, and violence', 'Hypertension and diabetes', 'Smoking and alcohol use', 'Osteoporosis and fractures', 'Visual and hearing impairment'], answer: 0, meta: 'Final 2 – 2022', explanation: 'Abuse, neglect, and violence are considered social risk factors in the elderly. Hypertension, diabetes, smoking, alcohol use, osteoporosis, fractures, and visual/hearing impairment are medical risk factors. Social risk factors include isolation, abuse, neglect, and lack of social support.' },
    { id: 155, subject: 'Pharmacology', text: 'Which of the following is the recommended chemoprophylaxis for close contacts of a patient with Neisseria meningitidis infection?', options: ['Ciprofloxacin single dose', 'Rifampin for 2 days', 'Amoxicillin for 5 days', 'Azithromycin single dose', 'Doxycycline for 7 days'], answer: 0, meta: 'Final 2 – 2024', explanation: 'The recommended chemoprophylaxis for close contacts of a patient with Neisseria meningitidis infection is a single dose of ciprofloxacin (500 mg). Alternatively, rifampin for 2 days is also effective, but ciprofloxacin is preferred due to its single-dose regimen. Azithromycin is not standard, and doxycycline is not recommended.' },
    { id: 156, subject: 'Pharmacology', text: 'What is the primary mechanism of action of memantine?', options: ['Acetylcholinesterase inhibition', 'NMDA receptor antagonism', 'Dopamine receptor agonism', 'GABA receptor agonism', 'Serotonin reuptake inhibition'], answer: 1, meta: 'Final 2 – 2024', explanation: 'Memantine is an NMDA receptor antagonist. It works by blocking excessive glutamate activity at NMDA receptors, which is thought to contribute to neurodegeneration in Alzheimer\'s disease. Acetylcholinesterase inhibitors (donepezil, rivastigmine, galantamine) work by increasing acetylcholine levels. Memantine is used in moderate to severe Alzheimer\'s disease.' },
    { id: 157, subject: 'Pharmacology', text: 'What is the main mechanism of action of riluzole in the treatment of amyotrophic lateral sclerosis (ALS)?', options: ['Calcium channel blocker', 'Sodium channel blocker', 'NMDA receptor antagonist', 'Acetylcholinesterase inhibitor', 'GABA receptor agonist'], answer: 1, meta: 'Final 2 – 2024', explanation: 'Riluzole is a sodium channel blocker that reduces glutamate excitotoxicity by inhibiting the release of glutamate from presynaptic terminals. It also blocks voltage-gated sodium channels. It is not an NMDA receptor antagonist (though it has some NMDA effects). It is the only drug proven to slow disease progression in ALS.' },
    { id: 158, subject: 'Pharmacology', text: 'In the management of a patient with penicillin-resistant Streptococcus pneumoniae, which of the following antibiotics is most appropriate to add?', options: ['Ciprofloxacin', 'Vancomycin', 'Amoxicillin', 'Doxycycline', 'Metronidazole'], answer: 1, meta: 'Final 2 – 2022', explanation: 'In the management of a patient with penicillin-resistant Streptococcus pneumoniae, vancomycin is the most appropriate antibiotic to add to the empiric regimen. Vancomycin covers penicillin-resistant S. pneumoniae. Amoxicillin is a penicillin and would not be effective against resistant strains. Ciprofloxacin, doxycycline, and metronidazole are not first-line for pneumococcal meningitis.' },
    { id: 159, subject: 'Pharmacology', text: 'A 67-year-old woman presents with fever, neck stiffness, and altered mental status. Suspected bacterial meningitis is considered. Which of the following is the most appropriate empirical treatment?', options: ['Ceftriaxone + metronidazole', 'Vancomycin + ceftriaxone + ampicillin', 'Amoxicillin + clavulanic acid', 'Ceftriaxone + gentamicin', 'Vancomycin + piperacillin-tazobactam'], answer: 1, meta: 'Assessment 2 – 2023', explanation: 'The most appropriate empiric treatment for bacterial meningitis in adults >50 years is Vancomycin + Ceftriaxone + Ampicillin. This covers Streptococcus pneumoniae (vancomycin + ceftriaxone), Neisseria meningitidis (ceftriaxone), and Listeria monocytogenes (ampicillin). Gentamicin is not first-line. Metronidazole is for anaerobic infections.' },
    { id: 160, subject: 'Pharmacology', text: 'Which of the following drugs facilitates GABAergic neurotransmission, has no significant anxiolytic effect, and whose action can be reversed by flumazenil?', options: ['Diazepam', 'Lorazepam', 'Buspirone', 'Barbiturates', 'Zolpidem'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'Zolpidem facilitates GABAergic neurotransmission (via BZ1 receptors), has no significant anxiolytic effect, and its action can be reversed by flumazenil. Diazepam and lorazepam are benzodiazepines with anxiolytic effects. Barbiturates also facilitate GABA but are not reversed by flumazenil. Buspirone is a 5-HT1A agonist, not a GABAergic agent.' },
    { id: 161, subject: 'Pharmacology', text: 'Which of the following non-benzodiazepine hypnotics is used for insomnia, acts selectively on BZ1 receptors, and lacks significant muscle relaxant effects?', options: ['Zaleplon', 'Lorazepam', 'Temazepam', 'Triazolam', 'Eszopiclone'], answer: 0, meta: 'Assessment 2 – 2023', explanation: 'Zaleplon is a non-benzodiazepine hypnotic (Z-drug) that acts selectively on BZ1 receptors and lacks significant muscle relaxant effects. Lorazepam, temazepam, and triazolam are benzodiazepines with muscle relaxant effects. Eszopiclone is another Z-drug with similar properties but zaleplon is the most selective for BZ1 receptors.' },
    { id: 162, subject: 'Pharmacology', text: 'Which of the following is the specific antidote for midazolam toxicity?', options: ['Naloxone', 'Flumazenil', 'Atropine', 'Physostigmine', 'N-acetylcysteine'], answer: 1, meta: 'Final 2 – 2020 · Final 2 – 2024', explanation: 'Flumazenil is the specific antidote for midazolam (and other benzodiazepine) toxicity. It is a competitive antagonist at the benzodiazepine receptor. Naloxone is the antidote for opioids, atropine for cholinergic toxicity, physostigmine for anticholinergic toxicity, and N-acetylcysteine for paracetamol overdose.' },
    { id: 163, subject: 'Pharmacology', text: 'Which of the following drugs is used for migraine prophylaxis and can also help improve insomnia?', options: ['Propranolol', 'Sumatriptan', 'Amitriptyline', 'Topiramate', 'Ergotamine'], answer: 2, meta: 'Final 2 – 2024', explanation: 'Amitriptyline is used for migraine prophylaxis and has sedative properties that can help improve insomnia. It is a tricyclic antidepressant that is effective for migraine prevention. Propranolol and topiramate are also used for migraine prophylaxis but do not significantly improve insomnia. Sumatriptan and ergotamine are acute treatments, not prophylactic.' },
    { id: 164, subject: 'Pharmacology', text: 'Which of the following drugs is commonly used for the management of panic attacks?', options: ['Fluoxetine', 'Sertraline', 'Alprazolam', 'Buspirone', 'Propranolol'], answer: 2, meta: 'Final 2 – 2019 · Final 2 – 2018', explanation: 'Alprazolam (a benzodiazepine) is commonly used for the acute management of panic attacks due to its rapid onset of action. Fluoxetine and sertraline are SSRIs used for long-term treatment of panic disorder. Buspirone is for generalised anxiety disorder, and propranolol is for performance anxiety and tremors.' },
    { id: 165, subject: 'Pharmacology', text: 'Which of the following drugs acts as a GABA agonist with anticonvulsant properties?', options: ['Zolpidem', 'Phenytoin', 'Carbamazepine', 'Valproate', 'Ethosuximide'], answer: 3, meta: 'Final 2 – 2018', explanation: 'Valproate (valproic acid) acts as a GABA agonist (increases GABA levels) and has broad-spectrum anticonvulsant properties. Zolpidem is a hypnotic, phenytoin is a sodium channel blocker, carbamazepine is a sodium channel blocker, and ethosuximide is a T-type calcium channel blocker. Valproate is used for various seizure types.' },
    { id: 166, subject: 'Pharmacology', text: 'Which of the following sedative–hypnotic drugs used for insomnia can have its effects reversed by flumazenil?', options: ['Phenobarbital', 'Zolpidem', 'Diphenhydramine', 'Melatonin', 'Chloral hydrate'], answer: 1, meta: 'Final 2 – Summer – 2022', explanation: 'Zolpidem (a non-benzodiazepine hypnotic) has its effects reversed by flumazenil because it binds to the benzodiazepine receptor. Phenobarbital is a barbiturate and is not reversed by flumazenil. Diphenhydramine is an antihistamine, melatonin is a hormone, and chloral hydrate is a sedative – none are reversed by flumazenil.' },
    { id: 167, subject: 'Pharmacology', text: 'A patient undergoing an endoscopic procedure becomes excessively sedated after receiving midazolam. He develops respiratory depression and decreased responsiveness. Which of the following is the most appropriate antidote?', options: ['Naloxone', 'Atropine', 'Physostigmine', 'Flumazenil', 'N-acetylcysteine'], answer: 3, meta: '', explanation: 'Flumazenil is the specific antidote for midazolam (benzodiazepine) toxicity, reversing respiratory depression and sedation. Naloxone is for opioids, atropine for cholinergic toxicity, physostigmine for anticholinergic toxicity, and N-acetylcysteine for paracetamol overdose.' },
    { id: 168, subject: 'Pharmacology', text: 'Which of the following local anesthetic agents uniquely provides both local anesthesia and a vasoconstrictive effect?', options: ['Lidocaine', 'Bupivacaine', 'Cocaine', 'Procaine', 'Tetracaine'], answer: 2, meta: 'Assessment 2 – 2019', explanation: 'Cocaine uniquely provides both local anaesthesia and vasoconstriction. It blocks sodium channels (local anaesthesia) and inhibits norepinephrine reuptake (vasoconstriction). Other local anaesthetics do not have intrinsic vasoconstrictive properties and are often combined with adrenaline. Lidocaine and bupivacaine are commonly used with vasoconstrictors added.' },
    { id: 169, subject: 'Pharmacology', text: 'Which of the following anesthetic agents is contraindicated in a patient with ischemic heart disease (IHD)?', options: ['Propofol', 'Midazolam', 'Isoflurane', 'Etomidate', 'Fentanyl'], answer: 2, meta: 'Final 2 – 2019', explanation: 'Isoflurane is relatively contraindicated in patients with ischemic heart disease because it can cause coronary steal syndrome, potentially worsening myocardial ischaemia. Propofol, midazolam, etomidate, and fentanyl are generally safe in IHD patients, though they require careful monitoring.' },
    { id: 170, subject: 'Pharmacology', text: 'Which of the following anesthetic agents is preferred in a patient with hypotension?', options: ['Propofol', 'Etomidate', 'Isoflurane', 'Ketamine', 'Midazolam'], answer: 3, meta: 'Final 2 – 2018', explanation: 'Ketamine is preferred in patients with hypotension because it maintains cardiovascular stability and can even stimulate the sympathetic nervous system, increasing blood pressure. Propofol, etomidate, and midazolam can cause hypotension. Isoflurane is an inhalational agent that can also cause hypotension.' },
    { id: 171, subject: 'Pharmacology', text: 'Which of the following intravenous anesthetic agents is particularly useful in patients with Bronchial Asthma and Hypotension?', options: ['Propofol', 'Ketamine', 'Thiopental', 'Etomidate', 'Midazolam'], answer: 1, meta: 'Assessment 2 – 2019', explanation: 'Ketamine is particularly useful in patients with bronchial asthma (because it has bronchodilatory properties) and hypotension (because it maintains cardiovascular stability). Propofol and thiopental can cause hypotension and bronchoconstriction. Etomidate can cause hypotension in some patients. Midazolam is not ideal for induction in asthmatic patients.' },
    { id: 172, subject: 'Pharmacology', text: 'A 35-year-old patient with bronchial asthma requires general anesthesia. Which of the following anesthetic agents is preferred due to its bronchodilatory effects and hemodynamic stability?', options: ['Propofol', 'Thiopental', 'Isoflurane', 'Midazolam', 'Ketamine'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'Ketamine is preferred in patients with bronchial asthma due to its bronchodilatory effects and hemodynamic stability. Propofol and thiopental can cause bronchoconstriction. Isoflurane is an inhalational agent that can cause bronchoconstriction. Midazolam is not ideal for induction. Ketamine is the best choice for asthmatic patients.' },
    { id: 173, subject: 'Pharmacology', text: 'A patient with hypotension is scheduled to undergo surgery. Which of the following anesthetic agents is most appropriate?', options: ['Propofol', 'Thiopental', 'Ketamine', 'Isoflurane', 'Midazolam'], answer: 2, meta: 'Assessment 2 – 2023', explanation: 'Ketamine is the most appropriate anesthetic agent in a patient with hypotension because it maintains cardiovascular stability and can increase blood pressure. Propofol, thiopental, and midazolam can cause hypotension. Isoflurane is an inhalational agent that can also cause hypotension.' },
    { id: 174, subject: 'Pharmacology', text: 'Which of the following anesthetic agents is preferred in patients with bronchial asthma and hypotension due to its bronchodilatory and cardiovascular properties?', options: ['Propofol', 'Thiopental', 'Midazolam', 'Ketamine', 'Halothane'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Ketamine is preferred in patients with bronchial asthma and hypotension because of its bronchodilatory and cardiovascular stimulatory properties. Propofol, thiopental, and midazolam can cause bronchoconstriction and hypotension. Halothane is an inhalational agent that can cause arrhythmias and is not preferred.' },
    { id: 175, subject: 'Pharmacology', text: 'Which of the following anesthetic agents can be used to treat cardiac arrhythmias due to its antiarrhythmic properties?', options: ['Lidocaine', 'Propofol', 'Ketamine', 'Etomidate', 'Sevoflurane'], answer: 0, meta: 'Final 2 – 2018', explanation: 'Lidocaine is used as an antiarrhythmic agent (Class IB) to treat ventricular arrhythmias. It is also used as a local anesthetic. Propofol, ketamine, etomidate, and sevoflurane do not have significant antiarrhythmic properties. Lidocaine works by blocking sodium channels and is effective in treating ventricular tachycardia and fibrillation.' },
    { id: 176, subject: 'Pharmacology', text: 'A patient with ischemic heart disease is scheduled for surgery under general anesthesia. Which of the following inhalational anesthetic agents is relatively contraindicated because it may precipitate coronary steal phenomenon?', options: ['Nitrous oxide', 'Sevoflurane', 'Desflurane', 'Isoflurane', 'Halothane'], answer: 3, meta: '', explanation: 'Isoflurane is relatively contraindicated in patients with ischemic heart disease because it can cause coronary steal phenomenon, potentially worsening myocardial ischaemia. Sevoflurane and desflurane are less likely to cause coronary steal. Nitrous oxide and halothane are not typically associated with coronary steal.' },
    { id: 177, subject: 'Pharmacology', text: 'Which of the following antiepileptic drugs is most commonly associated with Stevens–Johnson syndrome?', options: ['Valproic acid', 'Levetiracetam', 'Lamotrigine', 'Ethosuximide', 'Gabapentin'], answer: 2, meta: 'Assessment 2 – 2023', explanation: 'Lamotrigine is most commonly associated with Stevens–Johnson syndrome, a severe cutaneous adverse reaction. It is more likely to occur with rapid dose titration. Valproic acid can cause hepatotoxicity, levetiracetam can cause behavioural changes, ethosuximide can cause GI upset, and gabapentin can cause sedation.' },
    { id: 178, subject: 'Pharmacology', text: 'Which of the following antiepileptic drugs is considered the drug of choice for Trigeminal Neuralgia?', options: ['Phenytoin', 'Valproic Acid', 'Lamotrigine', 'Levetiracetam', 'Carbamazepine'], answer: 4, meta: 'Assessment 2 – 2019', explanation: 'Carbamazepine is the drug of choice for trigeminal neuralgia. It is effective in reducing the sharp, stabbing pain associated with this condition. Phenytoin, lamotrigine, and valproic acid can also be used but are not first-line. Levetiracetam is not typically used for trigeminal neuralgia.' },
    { id: 179, subject: 'Pharmacology', text: 'Which of the following drugs is commonly used for the prophylaxis of Migraine?', options: ['Sumatriptan', 'Propranolol', 'Ergotamine', 'Metoclopramide', 'Ibuprofen'], answer: 1, meta: 'Assessment 2 – 2019', explanation: 'Propranolol (a beta-blocker) is commonly used for the prophylaxis of migraine. It reduces the frequency and severity of migraine attacks. Sumatriptan and ergotamine are used for acute treatment, metoclopramide is used for nausea, and ibuprofen is used for mild acute pain.' },
    { id: 180, subject: 'Pharmacology', text: 'Which of the following drugs is commonly used for chronic migraine prophylaxis?', options: ['Sumatriptan', 'Topiramate', 'Amitriptyline', 'Propranolol', 'Ibuprofen'], answer: 1, meta: 'Final 2 – 2020', explanation: 'Topiramate is commonly used for chronic migraine prophylaxis. It is an antiepileptic drug that has been shown to reduce migraine frequency. Amitriptyline and propranolol are also used for migraine prophylaxis, but topiramate is specifically indicated for chronic migraine. Sumatriptan is for acute treatment, and ibuprofen is for mild pain.' },
    { id: 181, subject: 'Pharmacology', text: 'Which of the following drugs is considered the safest for treating absence seizures in children, with minimal impact on cognition and learning?', options: ['Valproate', 'Lamotrigine', 'Carbamazepine', 'Phenytoin', 'Ethosuximide'], answer: 4, meta: 'Final 2 – 2019', explanation: 'Ethosuximide is considered the safest and most effective drug for treating absence seizures in children. It has minimal impact on cognition and learning compared to valproate and lamotrigine. Carbamazepine and phenytoin are not effective for absence seizures. Valproate can affect cognition and learning.' },
    { id: 182, subject: 'Pharmacology', text: 'Which of the following drugs is first-line for the acute treatment of moderate to severe migraine attacks?', options: ['Acetaminophen', 'Ibuprofen', 'Propranolol', 'Sumatriptan', 'Topiramate'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Sumatriptan (a triptan) is first-line for the acute treatment of moderate to severe migraine attacks. Acetaminophen and ibuprofen are for mild pain. Propranolol and topiramate are for migraine prophylaxis (prevention), not acute treatment. Triptans are the most effective for acute migraine with moderate to severe pain.' },
    { id: 183, subject: 'Pharmacology', text: 'Which of the following Benzodiazepines is commonly used for the management of Status Epilepticus due to its rapid onset of action and reliable anticonvulsant effect?', options: ['Phenytoin', 'Clonazepam', 'Alprazolam', 'Carbamazepine', 'Lorazepam'], answer: 4, meta: 'Assessment 2 – 2019', explanation: 'Lorazepam is the benzodiazepine of choice for the management of status epilepticus due to its rapid onset of action and reliable anticonvulsant effect. Diazepam is also used but has a shorter duration of action. Phenytoin and carbamazepine are not used acutely. Clonazepam and alprazolam are not first-line for status epilepticus.' },
    { id: 184, subject: 'Pharmacology', text: 'Which of the following drugs is most commonly associated with gingival hyperplasia as a side effect?', options: ['Carbamazepine', 'Valproic Acid', 'Phenytoin', 'Ethosuximide', 'Phenobarbital'], answer: 2, meta: 'Final 2 – Summer – 2022', explanation: 'Phenytoin is most commonly associated with gingival hyperplasia (gum overgrowth) as a side effect. This is a well-known adverse effect of phenytoin, occurring in up to 50% of patients. Carbamazepine, valproic acid, ethosuximide, and phenobarbital are not typically associated with gingival hyperplasia.' },
    { id: 185, subject: 'Pharmacology', text: 'Which of the following drugs is commonly used for prophylaxis of migraine?', options: ['Amitriptyline', 'Topiramate', 'Propranolol', 'Sumatriptan', 'Ibuprofen'], answer: 0, meta: 'Final 2 – 2018', explanation: 'Amitriptyline (a tricyclic antidepressant) is commonly used for the prophylaxis of migraine. Topiramate and propranolol are also used for migraine prophylaxis. Sumatriptan is for acute treatment, and ibuprofen is for mild acute pain. Amitriptyline is effective for migraine prevention and is often used in patients with sleep disturbances.' },
    { id: 186, subject: 'Pharmacology', text: 'Which of the following drugs is associated with gingival hyperplasia and may be less suitable for certain patients, including females?', options: ['Valproate', 'Carbamazepine', 'Lamotrigine', 'Phenytoin', 'Ethosuximide'], answer: 3, meta: 'Final 2 – 2018', explanation: 'Phenytoin is associated with gingival hyperplasia and may be less suitable for certain patients, including females of childbearing age due to teratogenic effects. Valproate and carbamazepine are also teratogenic but not associated with gingival hyperplasia. Lamotrigine and ethosuximide are not associated with gingival hyperplasia.' },
    { id: 187, subject: 'Pharmacology', text: 'Which of the following drugs is commonly associated with dilutional hyponatremia as an adverse effect?', options: ['Phenytoin', 'Carbamazepine', 'Valproate', 'Ethosuximide', 'Lamotrigine'], answer: 1, meta: 'Final 2 – 2018', explanation: 'Carbamazepine is commonly associated with dilutional hyponatremia as an adverse effect. It causes syndrome of inappropriate antidiuretic hormone (SIADH), leading to hyponatremia. Phenytoin, valproate, ethosuximide, and lamotrigine are not typically associated with hyponatremia. Carbamazepine-induced hyponatremia is more common in elderly patients.' },
    { id: 188, subject: 'Pharmacology', text: 'A patient on long-term treatment for trigeminal neuralgia develops hyponatremia with low serum osmolality and symptoms of water intoxication. Which of the following drugs is most likely responsible?', options: ['Phenytoin', 'Valproic Acid', 'Lamotrigine', 'Levetiracetam', 'Carbamazepine'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'Carbamazepine is the most likely cause of hyponatremia in a patient on long-term treatment for trigeminal neuralgia. Carbamazepine causes SIADH, leading to water retention and hyponatremia. Phenytoin, valproic acid, lamotrigine, and levetiracetam are not typically associated with hyponatremia. Carbamazepine is the drug of choice for trigeminal neuralgia.' },
    { id: 189, subject: 'Pharmacology', text: 'What is the primary mechanism of action of sumatriptan?', options: ['5-HT2 receptor antagonism', 'Dopamine D2 receptor blockade', 'GABA-A receptor potentiation', '5-HT1B/1D receptor agonism', 'CGRP receptor antagonism'], answer: 3, meta: 'Assessment 2 – 2023', explanation: 'Sumatriptan is a 5-HT1B/1D receptor agonist. It works by stimulating these receptors, which causes vasoconstriction of intracranial blood vessels and reduces the release of vasoactive neuropeptides. CGRP receptor antagonists are a newer class for migraine treatment. 5-HT2 receptor antagonists are not used for migraine.' },
    { id: 190, subject: 'Pharmacology', text: 'A 35-year-old woman reports frequent, recurrent headache attacks occurring more than 10 days per month, associated with nausea and photophobia. Her physician decides to start a medication to reduce the frequency of future attacks rather than treat acute pain episodes. Which of the following drugs is most appropriate for prophylaxis of Chronic migraine?', options: ['Sumatriptan', 'Propranolol', 'Ergotamine', 'Metoclopramide', 'Aspirin'], answer: 1, meta: '', explanation: 'Propranolol is the most appropriate drug for the prophylaxis of chronic migraine. It is a first-line preventive treatment. Sumatriptan and ergotamine are for acute treatment. Metoclopramide is for nausea. Aspirin is for mild acute pain. Propranolol reduces the frequency and severity of migraine attacks over time.' },
    { id: 191, subject: 'Pharmacology', text: 'Which of the following antidepressant drugs is associated with a low incidence of sexual dysfunction?', options: ['Fluoxetine', 'Paroxetine', 'Amitriptyline', 'Sertraline', 'Bupropion'], answer: 4, meta: 'Assessment 2 – 2023', explanation: 'Bupropion is associated with a low incidence of sexual dysfunction compared to SSRIs. Fluoxetine, paroxetine, and sertraline (SSRIs) are commonly associated with sexual dysfunction. Amitriptyline (a tricyclic antidepressant) can also cause sexual dysfunction but less commonly than SSRIs. Bupropion is often used as an alternative when sexual side effects occur with SSRIs.' },
    { id: 192, subject: 'Pharmacology', text: 'Which antidepressant is associated with minimal sexual dysfunction compared to SSRIs?', options: ['Fluoxetine', 'Sertraline', 'Paroxetine', 'Mirtazapine', 'Venlafaxine'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Mirtazapine is associated with minimal sexual dysfunction compared to SSRIs. It is a noradrenergic and specific serotonergic antidepressant (NaSSA) that has a lower incidence of sexual side effects. Fluoxetine, sertraline, and paroxetine are SSRIs with significant sexual dysfunction. Venlafaxine is an SNRI that can also cause sexual dysfunction.' },
    { id: 193, subject: 'Pharmacology', text: 'Which of the following antidepressants is least likely to cause sexual dysfunction?', options: ['Fluoxetine', 'Sertraline', 'Paroxetine', 'Mirtazapine', 'Venlafaxine'], answer: 3, meta: 'Assessment 2 – 2019 · Assessment 2 – 2020', explanation: 'Mirtazapine is the least likely to cause sexual dysfunction among the listed antidepressants. It has a different mechanism of action (NaSSA) compared to SSRIs and SNRIs. Fluoxetine, sertraline, paroxetine, and venlafaxine all have higher rates of sexual dysfunction. Mirtazapine is often used when sexual side effects are a concern.' },
    { id: 194, subject: 'Pharmacology', text: 'Which of the following antidepressants is least likely to cause sexual dysfunction in patients?', options: ['Fluoxetine', 'Mirtazapine', 'Sertraline', 'Paroxetine', 'Venlafaxine'], answer: 1, meta: 'Assessment 2 – 2020', explanation: 'Mirtazapine is the least likely to cause sexual dysfunction among the listed antidepressants. It is a NaSSA with a lower incidence of sexual side effects compared to SSRIs and SNRIs. Fluoxetine, sertraline, paroxetine, and venlafaxine all have higher rates of sexual dysfunction. Mirtazapine is often used when sexual side effects are a concern.' },
    { id: 195, subject: 'Pharmacology', text: 'Which of the following drugs is used both as an antidepressant and for smoking cessation?', options: ['Bupropion', 'Fluoxetine', 'Sertraline', 'Mirtazapine', 'Amitriptyline'], answer: 0, meta: 'Final 2 – 2018', explanation: 'Bupropion is used both as an antidepressant and for smoking cessation. It works as a dopamine and norepinephrine reuptake inhibitor. Fluoxetine, sertraline, and paroxetine are SSRIs used for depression and anxiety. Mirtazapine is a NaSSA used for depression. Amitriptyline is a tricyclic antidepressant used for depression, migraine prophylaxis, and neuropathy.' },
    { id: 196, subject: 'Pharmacology', text: 'Which of the following drugs is an antidepressant that is not an SSRI?', options: ['Fluoxetine', 'Mirtazapine', 'Sertraline', 'Escitalopram', 'Paroxetine'], answer: 1, meta: 'Final 2 – 2018', explanation: 'Mirtazapine is an antidepressant that is not an SSRI – it is a NaSSA (noradrenergic and specific serotonergic antidepressant). Fluoxetine, sertraline, escitalopram, and paroxetine are all SSRIs. Mirtazapine has a different mechanism of action and side effect profile.' },
    { id: 197, subject: 'Pharmacology', text: 'A 30-year-old woman with relapsing–remitting multiple sclerosis continues to have relapses despite first-line disease-modifying therapy. Her neurologist decides to escalate treatment and starts a monthly intravenous therapy. Which of the following is the most likely drug?', options: ['Interferon-β', 'Fingolimod', 'Natalizumab', 'Glatiramer acetate', 'Teriflunomide'], answer: 2, meta: '', explanation: 'Natalizumab is a monthly intravenous therapy used as second-line treatment for relapsing-remitting multiple sclerosis when first-line therapies have failed. It is a monoclonal antibody against α4-integrin. Interferon-β and glatiramer acetate are first-line therapies. Fingolimod and teriflunomide are oral therapies.' },
    { id: 198, subject: 'Pharmacology', text: 'A 74-year-old patient with moderate Alzheimer disease is already receiving donepezil but shows progressive cognitive decline. The physician adds a drug that acts as an NMDA receptor antagonist to further improve symptoms. Which of the following drugs was most likely added?', options: ['Rivastigmine', 'Galantamine', 'Memantine', 'Selegiline', 'Fluoxetine'], answer: 2, meta: '', explanation: 'Memantine is an NMDA receptor antagonist used in moderate to severe Alzheimer\'s disease. It is often added to donepezil (a cholinesterase inhibitor) when cognitive decline progresses. Rivastigmine and galantamine are also cholinesterase inhibitors and would not be added if the patient is already on donepezil. Selegiline is used in Parkinson\'s disease, and fluoxetine is an SSRI.' },
    { id: 199, subject: 'Pharmacology', text: 'A 74-year-old woman with Alzheimer\'s disease is started on therapy to improve her cognitive symptoms. After a few days, she develops abdominal cramps and frequent loose stools. Which of the following drugs is most likely responsible for this adverse effect?', options: ['Memantine', 'Rivastigmine', 'Haloperidol', 'Fluoxetine'], answer: 1, meta: '', explanation: 'Rivastigmine (and other cholinesterase inhibitors) commonly cause gastrointestinal side effects, including abdominal cramps and diarrhoea. These are dose-dependent and can be minimised by starting at a low dose and titrating slowly. Memantine is less likely to cause GI symptoms. Haloperidol is an antipsychotic, and fluoxetine is an SSRI – both are not used for Alzheimer\'s cognitive symptoms.' },
    { id: 200, subject: 'Pharmacology', text: 'A patient presents with progressive muscle weakness, muscle wasting, fasciculations, and both upper and lower motor neuron signs, while sensory function remains intact. Which of the following drugs is used to slow disease progression in this condition?', options: ['Levodopa', 'Riluzole', 'Neostigmine', 'Diazepam'], answer: 1, meta: '', explanation: 'Riluzole is used to slow disease progression in Amyotrophic Lateral Sclerosis (ALS), which presents with both upper and lower motor neuron signs without sensory involvement. Levodopa is used in Parkinson\'s disease, neostigmine in myasthenia gravis, and diazepam as a muscle relaxant. Riluzole is the only drug approved to slow ALS progression.' },
    { id: 201, subject: 'Pharmacology', text: 'Which of the following antipsychotic medications is most associated with the potentially life-threatening side effect of agranulocytosis, requiring mandatory hematologic monitoring?', options: ['Olanzapine', 'Haloperidol', 'Risperidone', 'Clozapine', 'Aripiprazole'], answer: 3, meta: '', explanation: 'Clozapine is most associated with agranulocytosis, requiring mandatory hematologic monitoring (regular blood counts). Olanzapine, risperidone, and aripiprazole are second-generation antipsychotics with a lower risk of agranulocytosis. Haloperidol is a first-generation antipsychotic that can cause extrapyramidal side effects but not typically agranulocytosis.' },
    { id: 202, subject: 'Pharmacology', text: 'Which of the following antipsychotic drugs is most commonly associated with agranulocytosis and therefore requires regular blood count monitoring?', options: ['Haloperidol', 'Chlorpromazine', 'Risperidone', 'Olanzapine', 'Clozapine'], answer: 4, meta: '', explanation: 'Clozapine is most commonly associated with agranulocytosis and therefore requires regular blood count monitoring. It is the most effective antipsychotic for treatment-resistant schizophrenia but has a significant risk of agranulocytosis (1-2%). Haloperidol, chlorpromazine, risperidone, and olanzapine have lower risks of agranulocytosis.' },
    { id: 203, subject: 'Pharmacology', text: 'A patient who has been receiving long-term antipsychotic therapy develops repetitive involuntary orofacial movements suggestive of tardive dyskinesia, an extrapyramidal side effect. Which of the following drugs is the most likely cause?', options: ['Clozapine', 'Fluoxetine', 'Haloperidol', 'Diazepam', 'Lithium'], answer: 2, meta: '', explanation: 'Haloperidol (a typical antipsychotic) is most likely to cause tardive dyskinesia after long-term use. Tardive dyskinesia is a late-onset extrapyramidal side effect. Clozapine has the lowest risk of extrapyramidal side effects. Fluoxetine is an SSRI, diazepam is a benzodiazepine, and lithium is a mood stabilizer – none are typically associated with tardive dyskinesia.' },
    { id: 204, subject: 'Pharmacology', text: 'A patient experiencing severe nausea and vomiting after consuming alcohol while being treated for substance abuse is likely experiencing a reaction caused by which medication?', options: ['Naltrexone', 'Acamprosate', 'Disulfiram', 'Methadone', 'Buprenorphine'], answer: 2, meta: '', explanation: 'Disulfiram causes a severe reaction (nausea, vomiting, flushing, palpitations) when alcohol is consumed. It inhibits aldehyde dehydrogenase, leading to acetaldehyde accumulation. Naltrexone reduces alcohol craving, acamprosate helps maintain abstinence, methadone is used for opioid dependence, and buprenorphine is an opioid partial agonist.' },
    { id: 205, subject: 'Pharmacology', text: 'A man who recently decided to quit smoking is prescribed a medication to reduce nicotine craving and decrease relapse rates during smoking cessation therapy. Which of the following drugs was most likely prescribed?', options: ['Methadone', 'Naloxone', 'Disulfiram', 'Varenicline', 'Bupropion'], answer: 3, meta: '', explanation: 'Varenicline is the most effective medication for smoking cessation. It is a partial agonist at the α4β2 nicotinic acetylcholine receptor, reducing nicotine craving and withdrawal symptoms. Bupropion is also used for smoking cessation but is less effective than varenicline. Methadone is for opioid dependence, naloxone for opioid overdose, and disulfiram for alcohol dependence.' },

    // ─── MICROBIOLOGY (206–235) ──────────────────────────────────────────
    { id: 206, subject: 'Microbiology', text: 'In unimmunized children infected with Poliovirus, which of the following is the most common clinical outcome?', options: ['Paralytic Poliomyelitis', 'Non-paralytic meningitis', 'Severe encephalitis', 'Symptomatic febrile illness with muscle paralysis', 'Asymptomatic infection'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'In unimmunized children infected with poliovirus, the most common clinical outcome is asymptomatic infection (approximately 95% of cases). Only about 1% of infections result in paralytic poliomyelitis. Non-paralytic meningitis and febrile illness without paralysis are less common. Asymptomatic infection is the most frequent outcome, which is why vaccination is crucial.' },
    { id: 207, subject: 'Microbiology', text: 'A 4-year-old child presents with fever, vesicular lesions on the hands, feet, and inside the mouth, and mild malaise. Lumbar puncture shows CSF with normal glucose and normal opening pressure. Which of the following viruses is the most likely cause?', options: ['Herpes Simplex Virus', 'Varicella-Zoster Virus', 'Adenovirus', 'Coxsackie Virus', 'Influenza Virus'], answer: 3, meta: 'Assessment 2 – 2020', explanation: 'Coxsackie virus (specifically Coxsackie A16 and Enterovirus 71) causes hand, foot, and mouth disease, which presents with fever and vesicular lesions on the hands, feet, and mouth. CSF findings are typically normal or show mild pleocytosis. Herpes simplex virus causes cold sores or genital lesions, varicella-zoster causes chickenpox/shingles, adenovirus causes respiratory infections, and influenza causes respiratory symptoms.' },
    { id: 208, subject: 'Microbiology', text: 'A 7-year-old boy presents with fever, headache, and neck stiffness. Lumbar puncture reveals elevated intracranial pressure, but cerebrospinal fluid protein and glucose levels are within normal limits. Question: Which of the following pathogens is the most likely cause?', options: ['Haemophilus influenzae', 'Listeria monocytogenes', 'Coxsackie virus', 'Mycobacterium tuberculosis', 'Streptococcus pneumoniae'], answer: 2, meta: 'Assessment 2 – 2023', explanation: 'Coxsackie virus (viral meningitis) is the most likely cause of aseptic meningitis with elevated intracranial pressure but normal CSF protein and glucose. Bacterial meningitis (Haemophilus influenzae, Streptococcus pneumoniae) typically has decreased glucose and elevated protein. Tuberculous meningitis has decreased glucose and elevated protein. Listeria monocytogenes causes bacterial meningitis with decreased glucose.' },
    { id: 209, subject: 'Microbiology', text: 'Rabies virus reaches the central nervous system and spinal cord primarily through:', options: ['Bloodstream', 'Lymphatic vessels', 'Neurons', 'Cerebrospinal fluid', 'Respiratory droplets'], answer: 2, meta: 'Assessment 2 – 2023', explanation: 'The rabies virus reaches the CNS primarily through retrograde axonal transport along neurons. It enters peripheral nerves at the site of the bite and travels to the CNS via the spinal cord. It does not spread through the bloodstream, lymphatic vessels, CSF, or respiratory droplets. This neuronal spread is why rabies has a long incubation period.' },
    { id: 210, subject: 'Microbiology', text: 'Which of the following viruses mainly affects immunocompromised patients and can cause encephalitis?', options: ['Varicella-zoster virus', 'Cytomegalovirus (CMV)', 'Herpes simplex virus (HSV)', 'Epstein-Barr virus (EBV)', 'Enterovirus'], answer: 1, meta: 'Final 2 – 2024', explanation: 'Cytomegalovirus (CMV) mainly affects immunocompromised patients and can cause encephalitis, retinitis, and colitis. HSV can also cause encephalitis but in immunocompetent individuals. Varicella-zoster virus causes shingles, EBV causes infectious mononucleosis, and enteroviruses cause aseptic meningitis. CMV encephalitis is a significant concern in transplant recipients and HIV/AIDS patients.' },
    { id: 211, subject: 'Microbiology', text: 'Negri bodies are intracytoplasmic inclusions characteristic of which of the following infections?', options: ['Herpes simplex virus', 'Cytomegalovirus', 'Rabies', 'Varicella-zoster virus', 'Measles'], answer: 2, meta: 'Final 2 – 2024', explanation: 'Negri bodies are intracytoplasmic eosinophilic inclusions found in neurons of patients with rabies. They are pathognomonic for rabies infection. Herpes simplex virus causes Cowdry type A inclusions, CMV causes owl-eye inclusions, varicella-zoster causes multinucleated giant cells, and measles causes Warthin-Finkeldey cells.' },
    { id: 212, subject: 'Microbiology', text: 'Which of the following best describes the Sabin vaccine?', options: ['Inactivated (killed) poliovirus vaccine', 'Live attenuated oral poliovirus vaccine (Sabin)', 'Subunit hepatitis B vaccine', 'Conjugate Haemophilus influenzae type b vaccine', 'Toxoid vaccine (e.g., tetanus)'], answer: 1, meta: 'Final 2 – 2020 · Final 2 – 2019', explanation: 'The Sabin vaccine is a live attenuated oral poliovirus vaccine (OPV). It is given orally and provides both humoral and mucosal immunity. The Salk vaccine is an inactivated poliovirus vaccine (IPV) given by injection. OPV is cheaper and easier to administer but carries a risk of vaccine-associated paralytic poliomyelitis (VAPP).' },
    { id: 213, subject: 'Microbiology', text: 'A patient is scheduled for corneal transplantation. Which of the following infectious agents is a recognised risk for transmission through this procedure?', options: ['Bacteria', 'Viruses', 'Fungi', 'Parasites', 'Prions'], answer: 4, meta: 'Final 2 – 2019', explanation: 'Prions are a recognised risk for transmission through corneal transplantation. Prion diseases (such as Creutzfeldt-Jakob disease) can be transmitted via corneal grafts. Bacteria, viruses, fungi, and parasites are also risks, but prions are a specific concern because of their resistance to standard sterilization methods. Corneal transplantation requires careful screening of donors.' },
    { id: 214, subject: 'Microbiology', text: 'Which of the following is a key public health advantage of the Sabin vaccine?', options: ['Provides lifelong immunity after a single dose', 'Protects only the vaccinated individual', 'Herd immunity', 'Requires no cold chain for storage', 'Completely eliminates need for booster doses'], answer: 2, meta: 'Final 2 – 2018', explanation: 'The Sabin vaccine (OPV) provides herd immunity because it can be shed in the stool and immunise unvaccinated individuals through faecal-oral transmission. This is a key public health advantage. It does not provide lifelong immunity after a single dose, requires a cold chain, and does not eliminate the need for boosters. Herd immunity helps protect the unvaccinated population.' },
    { id: 215, subject: 'Microbiology', text: 'Which of the following statements about the Sabin vaccine is correct?', options: ['Can be safely given to immunocompromised patients', 'Provides only short-term immunity', 'Requires multiple booster doses every month', 'Not given to immunocompromised patients', 'Is an inactivated (killed) vaccine'], answer: 3, meta: 'Final 2 – 2018', explanation: 'The Sabin vaccine (live attenuated OPV) is not given to immunocompromised patients because of the risk of vaccine-associated paralytic poliomyelitis (VAPP). Immunocompromised patients should receive the inactivated polio vaccine (Salk/IPV). OPV provides long-term immunity, not short-term, and does not require monthly boosters. It is a live attenuated vaccine, not inactivated.' },
    { id: 216, subject: 'Microbiology', text: 'Coxsackie virus is best characterized by which of the following structural features?', options: ['Enveloped virus with helical nucleocapsid and segmented RNA genome', 'Enveloped virus with helical symmetry causing paramyxovirus infections', 'Partially double-stranded DNA virus with an envelope', 'Non-enveloped RNA virus with icosahedral symmetry', 'Enveloped double-stranded DNA virus with latent infection potential'], answer: 3, meta: 'Final 2 – 2018', explanation: 'Coxsackie virus is a non-enveloped RNA virus with icosahedral symmetry. It belongs to the Picornaviridae family, which are small, non-enveloped, positive-sense RNA viruses with icosahedral capsids. Enveloped viruses have helical or complex symmetry, and DNA viruses have different characteristics. Coxsackie virus is not enveloped and does not have a latent infection potential like herpesviruses.' },
    { id: 217, subject: 'Microbiology', text: 'Which areas of the brain are classically affected in herpes simplex virus (HSV) encephalitis?', options: ['Parietal and occipital lobes', 'Basal ganglia', 'Brainstem', 'Temporal and Frontal Lobes', 'Cerebellum'], answer: 3, meta: 'Final 2 – 2018', explanation: 'Herpes simplex virus (HSV) encephalitis classically affects the temporal and frontal lobes. The infection typically involves the medial temporal lobes, including the hippocampus and amygdala, and the inferior frontal lobes. This distribution is due to the virus spreading via the trigeminal nerve or olfactory tract. MRI often shows T2 hyperintensity in these regions.' },
    { id: 218, subject: 'Microbiology', text: 'A 35-year-old man comes to the emergency department after stepping on a rusty nail while gardening 3 days ago. He initially cleaned the wound at home but did not seek medical attention. Today, he complains of lockjaw, difficulty opening his mouth, and muscle spasms in his neck. He reports feeling generally unwell and has mild fever. On examination, his wound on the plantar surface of the foot appears small but dirty, with some surrounding redness. Vital signs show mild tachycardia and normal blood pressure. What is the first intervention?', options: ['Antibiotics', 'Antitoxin', 'Tetanus vaccination booster', 'Wound debridement', 'Muscle relaxants'], answer: 1, meta: 'Assessment 2 – 2023', explanation: 'The first intervention in tetanus is the administration of tetanus immune globulin (antitoxin) to neutralise circulating tetanus toxin. Antibiotics (metronidazole) and wound debridement are also important but are secondary interventions. The antitoxin is the priority to prevent further binding of the toxin to neurons. A tetanus vaccination booster is for prevention, not acute management. Muscle relaxants are used for symptom control after the antitoxin.' },
    { id: 219, subject: 'Microbiology', text: 'A 35-year-old man comes to the emergency department after stepping on a rusty nail while gardening. He complains of lockjaw, difficulty opening his mouth, and muscle spasms in his neck. He reports feeling generally unwell and has mild fever. Vital signs show mild tachycardia and normal blood pressure. What is the first intervention?', options: ['Administration of Antibiotics', 'Administration of Antitoxin', 'Administration of tetanus vaccination booster', 'Wound debridement', 'Administration of muscle relaxants'], answer: 1, meta: 'Assessment 2 – 2023', explanation: 'The first intervention in tetanus is the administration of tetanus immune globulin (antitoxin) to neutralise circulating tetanus toxin. Antibiotics (metronidazole) and wound debridement are also important but are secondary interventions. The antitoxin is the priority to prevent further binding of the toxin to neurons. A tetanus vaccination booster is for prevention, not acute management. Muscle relaxants are used for symptom control after the antitoxin.' },
    { id: 220, subject: 'Microbiology', text: 'Which of the following is the most common mode of infection in botulism?', options: ['Ingestion of undercooked meat contaminated with Clostridium perfringens', 'Consumption of raw seafood containing Vibrio toxins', 'Ingestion of canned or preserved foods containing preformed botulinum toxin', 'Drinking unpasteurized milk containing Listeria monocytogenes', 'Ingestion of improperly washed vegetables contaminated with Salmonella'], answer: 2, meta: 'Final 2 – 2024', explanation: 'The most common mode of infection in botulism is the ingestion of canned or preserved foods containing preformed botulinum toxin. Clostridium botulinum produces the toxin in anaerobic conditions, such as improperly canned foods. Foodborne botulism is caused by preformed toxin, not by the bacteria itself. Other options describe different bacterial infections.' },
    { id: 221, subject: 'Microbiology', text: 'Which of the following best describes the mechanism of action of Clostridium tetani toxin?', options: ['Enhances excitatory neurotransmission', 'Inhibits acetylcholine release at the neuromuscular junction', 'Blocks inhibitory synapses', 'Directly damages motor neurons', 'Causes demyelination of peripheral nerves'], answer: 2, meta: 'Final 2 – 2018', explanation: 'Clostridium tetani tetanospasmin blocks inhibitory synapses by binding to gangliosides and preventing the release of GABA and glycine from inhibitory interneurons. This leads to unopposed excitatory neurotransmission and muscle spasms. Botulinum toxin inhibits acetylcholine release at the neuromuscular junction, causing flaccid paralysis. Tetanus toxin does not directly damage motor neurons or cause demyelination.' },
    { id: 222, subject: 'Microbiology', text: 'Which of the following is the major capsular component of Haemophilus influenzae type b?', options: ['Lipoteichoic acid', 'Polyribitol phosphate', 'Peptidoglycan', 'Mycolic acid', 'Lipopolysaccharide'], answer: 1, meta: '', explanation: 'The major capsular component of Haemophilus influenzae type b is polyribitol phosphate (PRP). This is the antigen used in the Hib conjugate vaccine. Lipoteichoic acid is found in Gram-positive bacteria, peptidoglycan is in bacterial cell walls, mycolic acid is in mycobacteria, and lipopolysaccharide is in Gram-negative bacteria. PRP is specific to Hib.' },
    { id: 223, subject: 'Microbiology', text: 'A microbiologist isolates Gram-positive bacilli from a clinical specimen. The organism is Catalase Test positive. Which of the following laboratory findings would most strongly support identification of this organism?', options: ['Beta-hemolysis on blood agar', 'Growth at refrigeration temperature isn\'t possible (4 °C)', 'Intracellular growth in red blood cells', 'Formation of endospores', 'Tumbling Motility on microscopic examination'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'Tumbling motility on microscopic examination is a key feature of Listeria monocytogenes, which is a Gram-positive bacillus that is catalase positive. Listeria exhibits characteristic tumbling motility at room temperature. Beta-hemolysis is also a feature but is not as specific. Intracellular growth is a virulence factor, but tumbling motility is the most characteristic laboratory finding for Listeria. Endospore formation is typical of Clostridium and Bacillus.' },
    { id: 224, subject: 'Microbiology', text: 'A child presents with acute epiglottitis. Laboratory culture of a throat swab grows Gram-negative bacilli on chocolate agar. Which of the following organisms is the most likely cause?', options: ['Neisseria meningitidis', 'Streptococcus pneumoniae', 'Escherichia coli', 'Listeria monocytogenes', 'Haemophilus influenzae'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'Haemophilus influenzae type b is the most common cause of acute epiglottitis in children. It is a Gram-negative bacillus that grows on chocolate agar (which provides NAD and hemin). Neisseria meningitidis and Streptococcus pneumoniae are also Gram-negative/positive but are more commonly associated with meningitis. Escherichia coli is a Gram-negative bacillus but does not cause epiglottitis. Listeria monocytogenes is a Gram-positive bacillus.' },
    { id: 225, subject: 'Microbiology', text: 'Which population is primarily affected by Streptococcus agalactiae (Group B Streptococcus)?', options: ['Elderly adults', 'Teenagers', 'Neonates', 'Pregnant women only', 'Immunocompetent adults'], answer: 2, meta: 'Assessment 2 – 2023', explanation: 'Neonates are primarily affected by Streptococcus agalactiae (Group B Streptococcus). GBS is a leading cause of neonatal sepsis, pneumonia, and meningitis. Pregnant women are colonised with GBS and can transmit it to the newborn during delivery. Elderly adults and immunocompetent adults can also be affected but less commonly. Teenagers are not a primary population for GBS infection.' },
    { id: 226, subject: 'Microbiology', text: 'Which of the following pathogens is most commonly associated with epidemic meningitis?', options: ['Streptococcus pneumoniae', 'Haemophilus influenzae type b', 'Neisseria meningitidis', 'Listeria monocytogenes', 'Escherichia coli'], answer: 2, meta: 'Final 2 – 2024', explanation: 'Neisseria meningitidis is most commonly associated with epidemic meningitis. It causes outbreaks in crowded settings such as college dormitories and military barracks. Streptococcus pneumoniae is the most common cause of sporadic bacterial meningitis in adults. Haemophilus influenzae type b used to be a common cause but has decreased due to vaccination. Listeria monocytogenes is more common in the elderly and immunocompromised.' },
    { id: 227, subject: 'Microbiology', text: 'Which of the following bacteria is most likely associated with a polyribitol phosphate capsule?', options: ['Streptococcus pneumoniae', 'Neisseria meningitidis', 'Haemophilus influenzae type b', 'Escherichia coli', 'Listeria monocytogenes'], answer: 2, meta: 'Final 2 – 2020', explanation: 'Haemophilus influenzae type b has a polyribitol phosphate (PRP) capsule. This is a key virulence factor and the basis for the Hib conjugate vaccine. Streptococcus pneumoniae has a polysaccharide capsule but not PRP. Neisseria meningitidis has a polysaccharide capsule (serogroups). Escherichia coli has a polysaccharide capsule (K antigen). Listeria monocytogenes does not have a polysaccharide capsule.' },
    { id: 228, subject: 'Microbiology', text: 'A patient presents with fever, headache, neck stiffness, and photophobia. Gram stain of cerebrospinal fluid shows Gram-negative diplococci. The most likely mode of transmission of this organism is:', options: ['Fecal-oral route', 'Vector-borne (mosquito)', 'Inhalation of droplets from case or carrier', 'Sexual contact', 'Contaminated water ingestion'], answer: 2, meta: 'Final 2 – 2019', explanation: 'Neisseria meningitidis (Gram-negative diplococci) is transmitted by inhalation of respiratory droplets from an infected case or carrier. The organism colonises the nasopharynx and can spread through close contact. Fecal-oral transmission is typical of enteric pathogens, vector-borne transmission is for arboviruses, sexual contact is for Neisseria gonorrhoeae, and contaminated water is for enteric bacteria.' },
    { id: 229, subject: 'Microbiology', text: 'Which of the following best describes a key virulence factor of Listeria monocytogenes?', options: ['Exotoxin-mediated hemolysis', 'Capsule formation for anti-phagocytosis', 'Intracellular obligate living', 'Endospore formation', 'Biofilm production'], answer: 2, meta: 'Final 2 – 2019', explanation: 'Listeria monocytogenes is an intracellular pathogen that can live and multiply within host cells. This intracellular obligate living allows it to evade the immune system and cross the blood-brain barrier. It produces listeriolysin O (a hemolysin) to escape from phagosomes. Capsule formation is not a key virulence factor for Listeria, and it does not form endospores. Biofilm production is not a primary virulence factor.' },
    { id: 230, subject: 'Microbiology', text: 'Which of the following organisms expresses Factor H binding protein, allowing it to evade complement-mediated killing?', options: ['Streptococcus pneumoniae', 'Haemophilus influenzae', 'Escherichia coli', 'Neisseria meningitidis', 'Staphylococcus aureus'], answer: 3, meta: 'Final 2 – 2018', explanation: 'Neisseria meningitidis expresses Factor H binding protein (fHbp), which binds to human complement factor H and evades complement-mediated killing. This is a key virulence factor for the meningococcus. Streptococcus pneumoniae has a polysaccharide capsule for immune evasion. Haemophilus influenzae has a PRP capsule. Escherichia coli and Staphylococcus aureus have other mechanisms of immune evasion.' },
    { id: 231, subject: 'Microbiology', text: 'Which of the following organisms is a Gram-negative diplococcus commonly associated with meningitis?', options: ['Neisseria meningitidis', 'Streptococcus pneumoniae', 'Haemophilus influenzae', 'Moraxella catarrhalis', 'Escherichia coli'], answer: 0, meta: 'Final 2 – 2018', explanation: 'Neisseria meningitidis is a Gram-negative diplococcus commonly associated with meningitis. It is the most common cause of epidemic meningitis. Streptococcus pneumoniae is a Gram-positive diplococcus. Haemophilus influenzae is a Gram-negative bacillus. Moraxella catarrhalis is a Gram-negative diplococcus but is more commonly associated with respiratory infections. Escherichia coli is a Gram-negative bacillus.' },
    { id: 232, subject: 'Microbiology', text: 'Which of the following is the most important virulence factor of Streptococcus pneumoniae?', options: ['Pneumolysin', 'Polysaccharide capsule', 'Teichoic acid', 'IgA protease', 'M protein'], answer: 1, meta: 'Final 2 – 2018', explanation: 'The polysaccharide capsule is the most important virulence factor of Streptococcus pneumoniae. It prevents phagocytosis by the immune system. Pneumolysin is a toxin that damages host cells, teichoic acid is a cell wall component, IgA protease is found in Neisseria and Haemophilus, and M protein is found in Streptococcus pyogenes. The capsule is the basis for serotyping and pneumococcal vaccination.' },
    { id: 233, subject: 'Microbiology', text: 'In which of the following conditions is cerebrospinal fluid (CSF) glucose typically unaltered?', options: ['Bacterial meningitis', 'Tuberculous meningitis', 'Fungal meningitis', 'Acute viral meningitis', 'Brain abscess with meningeal involvement'], answer: 3, meta: 'Final 2 – 2024', explanation: 'In acute viral meningitis, CSF glucose is typically normal (unaltered). Bacterial, tuberculous, and fungal meningitis cause decreased CSF glucose due to increased glucose consumption by the pathogens and inflammatory cells. Brain abscess with meningeal involvement may also affect CSF glucose. Viral meningitis usually has normal glucose, mild elevation of protein, and lymphocytic pleocytosis.' },
    { id: 234, subject: 'Microbiology', text: 'What is the mode of transmission of Cryptococcus neoformans infection?', options: ['Ingestion of contaminated food', 'Inhalation of aerosolized droplets from infected patients', 'Direct skin inoculation through trauma', 'Inhalation of bird excreta with identification by India ink staining', 'Vector-borne transmission through insect bites'], answer: 3, meta: 'Final 2 – 2022', explanation: 'Cryptococcus neoformans is transmitted by inhalation of bird excreta (particularly pigeon droppings). The organism is identified in CSF by India ink staining, which shows encapsulated yeast cells. Ingestion of contaminated food, direct skin inoculation, and vector-borne transmission are not modes of transmission for Cryptococcus. Inhalation of aerosolized droplets from infected patients is not a typical mode of transmission.' },
    { id: 235, subject: 'Microbiology', text: 'The live attenuated vaccine used for prevention of Poliomyelitis is:', options: ['Salk vaccine', 'BCG vaccine', 'Sabin vaccine', 'MMR vaccine', 'Hepatitis B vaccine'], answer: 2, meta: '', explanation: 'The Sabin vaccine is a live attenuated oral poliovirus vaccine (OPV) used for the prevention of poliomyelitis. The Salk vaccine is an inactivated poliovirus vaccine (IPV). BCG is for tuberculosis, MMR is for measles, mumps, and rubella, and the Hepatitis B vaccine is a recombinant vaccine. OPV is given orally and provides both humoral and mucosal immunity.' },

    // ─── PATHOLOGY (236–315) ─────────────────────────────────────────────
    { id: 236, subject: 'Pathology', text: 'A 6-month-old infant is brought to the clinic due to an exaggerated startle response to loud noises and a noticeable regression in motor milestones. Physical examination reveals a "cherry-red" spot on the macula. This condition is primarily caused by the abnormal accumulation of which of the following substances?', options: ['Glucocerebroside', 'Sphingomyelin', 'GM2 ganglioside', 'Galactocerebroside', 'Ceramide trihexoside'], answer: 2, meta: '', explanation: 'Tay-Sachs disease is caused by the accumulation of GM2 ganglioside due to deficiency of hexosaminidase A. Clinical features include an exaggerated startle response, motor regression, and a cherry-red spot on the macula. Glucocerebroside accumulates in Gaucher disease, sphingomyelin in Niemann-Pick disease, galactocerebroside in Krabbe disease, and ceramide trihexoside in Fabry disease.' },
    { id: 237, subject: 'Pathology', text: 'A 25-year-old patient presents with chronic fatigue, bone pain, and significant enlargement of the spleen. Bone marrow biopsy reveals "wrinkled paper" appearing cells (macrophages laden with lipid). This clinical presentation is most consistent with a deficiency in an enzyme responsible for the breakdown of which of the following substances?', options: ['Glucocerebroside', 'Galactocerebroside', 'Sphingomyelin', 'GM1 ganglioside', 'Globotriaosylceramide'], answer: 0, meta: '', explanation: 'Gaucher disease is caused by a deficiency of glucocerebrosidase, leading to accumulation of glucocerebroside. Clinical features include chronic fatigue, bone pain, hepatosplenomegaly, and "wrinkled paper" (Gaucher) cells on bone marrow biopsy. Galactocerebroside accumulates in Krabbe disease, sphingomyelin in Niemann-Pick disease, GM1 ganglioside in GM1 gangliosidosis, and globotriaosylceramide in Fabry disease.' },
    { id: 238, subject: 'Pathology', text: 'A 52-year-old woman presents with gradually progressive headaches and focal neurological deficits. Brain imaging reveals a well-circumscribed extra-axial mass attached to the dura mater. Histological examination shows tumour cells arranged in whorled patterns with occasional calcified Psammoma Bodies. Which of the following is the most likely diagnosis?', options: ['Meningioma', 'Glioblastoma', 'Schwannoma', 'Oligodendroglioma', 'Medulloblastoma'], answer: 0, meta: 'Assessment 2 – 2020', explanation: 'Meningioma is a well-circumscribed, extra-axial mass attached to the dura mater. Histologically, it shows whorled patterns and psammoma bodies (calcifications). It is a slow-growing tumour. Glioblastoma is an intra-axial tumour with necrosis and pseudopalisading. Schwannoma is associated with the vestibular nerve, oligodendroglioma has a "fried-egg" appearance, and medulloblastoma is a primitive neuroectodermal tumour of the cerebellum.' },
    { id: 239, subject: 'Pathology', text: 'A 30-year-old patient presents with headache, fever, and focal neurological deficits. Brain imaging with contrast shows a ring-enhancing lesion in the cerebral hemisphere with surrounding oedema. Which of the following is the most likely diagnosis?', options: ['Glioblastoma', 'Meningioma', 'Chronic Brain Abscess', 'Oligodendroglioma', 'Pituitary Adenoma'], answer: 2, meta: 'Assessment 2 – 2020', explanation: 'A chronic brain abscess presents as a ring-enhancing lesion with surrounding oedema on imaging, accompanied by fever and focal neurological deficits. Glioblastoma is a ring-enhancing lesion but typically occurs in older patients without fever. Meningioma is extra-axial and dural-based. Oligodendroglioma is intra-axial with calcifications. Pituitary adenoma is in the sella turcica. The presence of fever suggests an infectious/inflammatory process.' },
    { id: 240, subject: 'Pathology', text: 'A 45-year-old patient presents with visual disturbances. Imaging reveals a glistening, elongated mass measuring approximately 20 cm in the left occipital lobe. On gross examination, the tumour has a "frog egg" or gelatinous appearance. Which of the following is the most likely diagnosis?', options: ['Meningioma', 'Glioblastoma Multiforme', 'Oligodendroglioma', 'Medulloblastoma', 'Frog Egg Appearance Tumor'], answer: 2, meta: 'Assessment 2 – 2020', explanation: 'Oligodendroglioma can present as a glistening, gelatinous mass with a "frog egg" appearance, often with calcifications. It is a slow-growing tumour in the cerebral hemispheres. Meningioma is extra-axial, glioblastoma is malignant with necrosis, medulloblastoma is in the posterior fossa, and "frog egg appearance tumour" is not a specific diagnosis. The occipital lobe location and gelatinous appearance suggest oligodendroglioma.' },
    { id: 241, subject: 'Pathology', text: 'A 65-year-old patient presents with slowness of movement, difficulty initiating voluntary movements, and bradykinesia. Neuropathological examination reveals intracytoplasmic eosinophilic inclusions in the Substantia Nigra. Which of the following clinical features is most characteristic of this condition?', options: ['Tremor at rest only', 'Muscle rigidity without bradykinesia', 'Rapid, involuntary movements', 'Cognitive decline as the initial symptom', 'Bradykinesia and slow movements'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'Parkinson\'s disease is characterised by bradykinesia (slow movements), resting tremor, rigidity, and postural instability. The most characteristic clinical feature is bradykinesia and slow movements. The neuropathological finding of Lewy bodies (intracytoplasmic eosinophilic inclusions) in the substantia nigra is classic. Tremor at rest is also a feature, but bradykinesia is the most characteristic.' },
    { id: 242, subject: 'Pathology', text: '28-year-old woman presents with intermittent episodes of muscle weakness, numbness in her limbs, and visual disturbances over the past several months. MRI shows lesions in the white matter of the brain and spinal cord. Laboratory studies reveal no evidence of infection. Which of the following best describes the characteristics of this disease?', options: ['Demyelinating disease affecting white matter', 'Neurodegenerative disease primarily affecting gray matter', 'Infectious disease-causing brain inflammation', 'Vascular disorder leading to ischemic brain lesions', 'Autoimmune disease targeting peripheral nerves'], answer: 0, meta: 'Assessment 2 – 2023', explanation: 'Multiple sclerosis is a demyelinating disease affecting white matter of the CNS. It presents with relapsing-remitting episodes of neurological deficits (muscle weakness, numbness, visual disturbances) and MRI shows white matter plaques. It is an autoimmune disease targeting CNS myelin (oligodendrocytes), not peripheral nerves. It is not a neurodegenerative disease, infectious disease, or vascular disorder.' },
    { id: 243, subject: 'Pathology', text: 'A 22-year-old professional basketball player suddenly collapses during a game after complaining of a severe headache. He becomes disoriented and shows signs of neurological deficit. Brain imaging reveals bleeding within the brain. Which of the following is the most likely site affected in this condition?', options: ['Basal ganglia', 'Circle of Willis', 'Cerebellum', 'Brainstem', 'Frontal cortex'], answer: 1, meta: 'Assessment 2 – 2023', explanation: 'Subarachnoid haemorrhage most commonly results from rupture of a saccular (berry) aneurysm in the Circle of Willis. The anterior communicating artery is the most common site. Basal ganglia haemorrhages are associated with hypertension. Cerebellar and brainstem haemorrhages are less common. Frontal cortex haemorrhages are associated with trauma or vascular malformations.' },
    { id: 244, subject: 'Pathology', text: 'Deletion of chromosomes 1p and 19q is most commonly associated with which of the following brain tumours?', options: ['Glioblastoma', 'Astrocytoma', 'Oligodendroglioma', 'Meningioma', 'Ependymoma'], answer: 2, meta: 'Assessment 2 – 2023', explanation: 'Deletion of chromosomes 1p and 19q is most commonly associated with oligodendroglioma. This genetic alteration is a favourable prognostic marker and is associated with chemosensitivity. Glioblastoma is associated with EGFR amplification, astrocytoma with TP53 mutations, meningioma with NF2 mutations, and ependymoma with 1q gain or chromosome 22 loss.' },
    { id: 245, subject: 'Pathology', text: 'A patient presents with hypotonia. Imaging shows a lesion affecting the left occipital lobe. Histological examination reveals changes in the basal ganglia. Which of the following microscopic findings is most likely in this patient?', options: ['Gliosis of caudate nucleus', 'Demyelination of corticospinal tract', 'Neurofibrillary tangles in hippocampus', 'Neuronal loss in substantia nigra', 'Microglial nodules in cerebral cortex'], answer: 3, meta: 'Final 2 – 2024', explanation: 'Hypotonia with a lesion affecting the left occipital lobe and changes in the basal ganglia suggests Huntington\'s disease (which presents with hypotonia in the early stages). Huntington\'s disease is characterised by neuronal loss and gliosis in the caudate nucleus and putamen. Neurofibrillary tangles are seen in Alzheimer\'s disease, demyelination in multiple sclerosis, neuronal loss in substantia nigra in Parkinson\'s disease, and microglial nodules in encephalitis.' },
    { id: 246, subject: 'Pathology', text: 'Cerebral infarction is an example of which type of necrosis?', options: ['Coagulative necrosis', 'Caseous necrosis', 'Liquefactive necrosis', 'Fat necrosis', 'Fibrinoid necrosis'], answer: 2, meta: 'Final 2 – 2024', explanation: 'Cerebral infarction is an example of liquefactive necrosis. The brain tissue undergoes liquefaction due to the release of lysosomal enzymes from leukocytes and the high lipid content of the brain, forming a cystic cavity. Coagulative necrosis is typical of ischaemia in solid organs (heart, kidney). Caseous necrosis is seen in tuberculosis, fat necrosis in pancreatitis, and fibrinoid necrosis in vasculitis.' },
    { id: 247, subject: 'Pathology', text: 'A patient presents with rapidly progressive neurological deficits. MRI shows a heterogeneous brain mass with central necrosis and surrounding oedema. Histopathology reveals areas of necrosis and microvascular proliferation. Which of the following is the most likely diagnosis?', options: ['Low-grade astrocytoma', 'Oligodendroglioma', 'Glioblastoma, grade IV', 'Ependymoma', 'Meningioma'], answer: 2, meta: 'Final 2 – 2024', explanation: 'Glioblastoma (grade IV) is characterised by a heterogeneous mass with central necrosis, surrounding oedema, and histopathological features of necrosis and microvascular proliferation (pseudopalisading). It is a rapidly growing, aggressive tumour. Low-grade astrocytoma has no necrosis, oligodendroglioma has calcifications, ependymoma has rosettes, and meningioma is extra-axial and dural-based.' },
    { id: 248, subject: 'Pathology', text: 'A patient presents with fever and signs of encephalitis. Imaging shows temporal lobe affection. Which of the following is the most likely mechanism of this condition?', options: ['Hematogenous spread to brain', 'Reactivation with axonal transport to temporal lobe (HSV)', 'Direct invasion from nasal cavity', 'Vector-borne transmission', 'Immune-mediated demyelination'], answer: 1, meta: 'Final 2 – 2022', explanation: 'Herpes simplex virus (HSV) encephalitis typically affects the temporal lobes. The mechanism is reactivation of latent HSV from the trigeminal ganglion with axonal transport to the temporal lobe. Hematogenous spread is less common for HSV. Direct invasion from the nasal cavity is seen in fungal infections. Vector-borne transmission is for arboviruses. Immune-mediated demyelination is seen in multiple sclerosis.' },
    { id: 249, subject: 'Pathology', text: 'A 28-year-old woman experiences recurrent episodes of paresthesia that resolve partially between attacks. The most likely diagnosis is:', options: ['Guillain-Barré syndrome', 'Peripheral neuropathy', 'Multiple sclerosis', 'Myasthenia gravis', 'Stroke'], answer: 2, meta: 'Final 2 – 2019 · Final 2 – 2020', explanation: 'Multiple sclerosis presents with recurrent episodes of neurological deficits (paresthesia, weakness) that resolve partially between attacks (relapsing-remitting pattern). Guillain-Barré syndrome is an acute, monophasic ascending paralysis. Peripheral neuropathy is progressive. Myasthenia gravis presents with fluctuating muscle weakness, and stroke is acute and focal. The relapsing-remitting pattern is classic for MS.' },
    { id: 250, subject: 'Pathology', text: 'A 7-year-old child presents with progressive headache, nausea, and unsteady gait over several months. On neurological examination, there is truncal ataxia and difficulty with coordination. MRI of the brain reveals a well-circumscribed cerebellar mass with cystic and solid components. Histological examination shows Rosenthal fibres within the lesion. The most likely diagnosis is:', options: ['Medulloblastoma', 'Ependymoma', 'Pilocytic astrocytoma', 'Oligodendroglioma', 'Hemangioblastoma'], answer: 2, meta: 'Final 2 – 2020', explanation: 'Pilocytic astrocytoma is a slow-growing cerebellar tumour in children, presenting with headache, nausea, and ataxia. It has cystic and solid components and Rosenthal fibres on histology. Medulloblastoma is a primitive neuroectodermal tumour with small round cells. Ependymoma has perivascular rosettes. Oligodendroglioma has "fried-egg" cells. Hemangioblastoma is associated with von Hippel-Lindau disease and has stromal cells.' },
    { id: 251, subject: 'Pathology', text: 'Which of the following are characteristic pathological features of Alzheimer\'s disease?', options: ['Lewy bodies and demyelination', 'Neuritic plaques and neurofibrillary tangles', 'Pick bodies and gliosis', 'Rosenthal fibers and cystic lesions', 'Spongiform changes and vacuolation'], answer: 1, meta: 'Final 2 – 2020', explanation: 'Alzheimer\'s disease is characterised by neuritic plaques (extracellular amyloid-β deposits) and neurofibrillary tangles (intracellular hyperphosphorylated tau). Lewy bodies are seen in Parkinson\'s disease and dementia with Lewy bodies. Pick bodies are seen in frontotemporal dementia. Rosenthal fibres are seen in pilocytic astrocytoma. Spongiform changes are seen in prion diseases.' },
    { id: 252, subject: 'Pathology', text: 'Which of the following cerebrospinal fluid (CSF) findings is most characteristic of bacterial meningitis?', options: ['Normal pressure, clear fluid, normal protein, normal glucose, lymphocytes predominance', 'Slightly elevated pressure, clear fluid, mildly increased protein, normal glucose, mixed cells', 'Increased pressure, cloudy CSF, increased protein, decreased glucose, neutrophil predominance', 'Elevated pressure, clear fluid, normal protein, decreased glucose, eosinophil predominance', 'Low pressure, xanthochromic fluid, normal protein, normal glucose, lymphocytes predominance'], answer: 2, meta: 'Final 2 – 2019', explanation: 'Bacterial meningitis is characterised by increased CSF pressure, cloudy appearance, elevated protein, decreased glucose, and neutrophil predominance. Viral meningitis has normal pressure, clear fluid, normal or mildly elevated protein, normal glucose, and lymphocytic predominance. Tuberculous meningitis has decreased glucose and elevated protein with lymphocytic predominance. Fungal meningitis has similar findings to tuberculous meningitis.' },
    { id: 253, subject: 'Pathology', text: 'A patient presents with a frontal lobe mass on imaging. Histological examination shows cells with a clear halo around the nucleus ("fried-egg" appearance) and a delicate network of capillaries. The most likely diagnosis is:', options: ['Astrocytoma', 'Oligodendroglioma', 'Ependymoma', 'Medulloblastoma', 'Meningioma'], answer: 1, meta: 'Final 2 – 2018 · Final 2 – 2019', explanation: 'Oligodendroglioma is characterised by "fried-egg" cells (clear halo around the nucleus) and a delicate network of capillaries (chicken wire). It is a slow-growing tumour in the cerebral hemispheres. Astrocytoma has fibrillary cells, ependymoma has perivascular rosettes, medulloblastoma has small round cells, and meningioma has whorls and psammoma bodies.' },
    { id: 254, subject: 'Pathology', text: 'A 5-year-old child presents with headache, vomiting, and gait instability. Imaging reveals a midline posterior fossa mass. Histology shows sheets of small, round, primitive cells with high nuclear-to-cytoplasmic ratio, consistent with an embryonal tumour. The most likely diagnosis is:', options: ['Medulloblastoma', 'Pilocytic astrocytoma', 'Ependymoma', 'Oligodendroglioma', 'Meningioma'], answer: 0, meta: 'Final 2 – 2019', explanation: 'Medulloblastoma is a primitive neuroectodermal tumour in the posterior fossa (cerebellum) in children. It consists of sheets of small, round, primitive cells with high nuclear-to-cytoplasmic ratio. Pilocytic astrocytoma is a cerebellar tumour with Rosenthal fibres, ependymoma has perivascular rosettes, oligodendroglioma has "fried-egg" cells, and meningioma is extra-axial.' },
    { id: 255, subject: 'Pathology', text: 'Chronic hypertension is most commonly associated with the formation of which type of cerebral aneurysm?', options: ['Berry (saccular) aneurysm', 'Fusiform aneurysm', 'Charcot-Bouchard aneurysm', 'Mycotic aneurysm', 'Dissecting aneurysm'], answer: 2, meta: 'Final 2 – 2018', explanation: 'Chronic hypertension is most commonly associated with Charcot-Bouchard aneurysms (microaneurysms) of the deep penetrating arteries, particularly in the basal ganglia and thalamus. These are a cause of hypertensive intracerebral haemorrhage. Berry (saccular) aneurysms are congenital, fusiform aneurysms are atherosclerotic, mycotic aneurysms are due to infection, and dissecting aneurysms are due to trauma or arteriopathy.' },
    { id: 256, subject: 'Pathology', text: 'Which of the following cells is primarily affected in a demyelinating disease that presents with muscle weakness and loss of sensation?', options: ['Schwann cells', 'Astrocytes', 'Microglia', 'Ependymal cells', 'Oligodendrocytes'], answer: 4, meta: 'Final 2 – 2018', explanation: 'In demyelinating diseases of the CNS (such as multiple sclerosis), oligodendrocytes are the cells primarily affected. These cells produce myelin in the CNS. Schwann cells are the myelin-producing cells in the PNS and are affected in peripheral neuropathies. Astrocytes, microglia, and ependymal cells are not directly responsible for myelin production.' },
    { id: 257, subject: 'Pathology', text: 'Which of the following functions is not related to sleep?', options: ['Memory consolidation', 'Hormone secretion', 'Muscle tone', 'Energy conservation', 'Brain plasticity'], answer: 2, meta: 'Final 2 – 2018', explanation: 'Muscle tone is not specifically related to sleep – muscle tone is present during wakefulness and is reduced during REM sleep but is not a primary function of sleep. Memory consolidation, hormone secretion (e.g., growth hormone), energy conservation, and brain plasticity are all functions related to sleep. Muscle tone is a function of the nervous system that is maintained during wakefulness and altered during sleep.' },
    { id: 258, subject: 'Pathology', text: 'Which of the following statements about Alzheimer\'s disease is correct?', options: ['It is commonly seen in females with Turner syndrome', 'Muscle weakness is a typical presenting feature', 'Male with Down syndrome has increased risk of developing the disease', 'It primarily affects motor neurons', 'It is associated with Fragile X syndrome'], answer: 2, meta: 'Final 2 – 2018', explanation: 'Individuals with Down syndrome (trisomy 21) have an increased risk of developing Alzheimer\'s disease due to the presence of an extra copy of the amyloid precursor protein (APP) gene on chromosome 21. This leads to early-onset Alzheimer\'s disease. Turner syndrome is not associated with Alzheimer\'s. Muscle weakness is not a typical presenting feature of Alzheimer\'s (it is cognitive decline). It does not primarily affect motor neurons (that is ALS). It is not associated with Fragile X syndrome.' },
    { id: 259, subject: 'Pathology', text: 'A 28-year-old woman presents with intermittent episodes of blurred vision, weakness of the limbs, and numbness over the past two years. The symptoms improve partially but recur after several months. MRI of the brain shows multiple demyelinating plaques in the white matter of the CNS. Which of the following is the most likely diagnosis?', options: ['Guillain-Barré Syndrome', 'Myasthenia Gravis', 'Amyotrophic Lateral Sclerosis', 'Multiple Sclerosis', 'Parkinson Disease'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Multiple sclerosis is the most likely diagnosis in a young woman with relapsing-remitting neurological symptoms (blurred vision, weakness, numbness) and MRI showing multiple demyelinating plaques in the CNS white matter. Guillain-Barré syndrome is an acute, monophasic ascending paralysis. Myasthenia gravis presents with fluctuating muscle weakness and fatigue. Amyotrophic lateral sclerosis presents with both upper and lower motor neuron signs without sensory involvement. Parkinson disease presents with motor symptoms such as tremor and bradykinesia.' },
    { id: 260, subject: 'Pathology', text: 'A 2-week-old neonate presents with flaccid paralysis, hypotonia, and poor feeding. The mother reports a recent upper respiratory infection during the third trimester. Cerebrospinal fluid analysis shows elevated protein with normal cell count. Which of the following is the most likely diagnosis?', options: ['Spinal muscular atrophy', 'Botulism', 'Guillain-Barré Syndrome', 'Myasthenia gravis', 'Poliomyelitis'], answer: 2, meta: 'Final 2 – Summer – 2022', explanation: 'Guillain-Barré syndrome (acute inflammatory demyelinating polyneuropathy) in a neonate can present with flaccid paralysis, hypotonia, and poor feeding. The CSF shows albuminocytologic dissociation (elevated protein with normal cell count). Maternal respiratory infection during the third trimester is a risk factor. Spinal muscular atrophy is a genetic condition, botulism causes descending paralysis, myasthenia gravis is autoimmune, and poliomyelitis is viral with CSF pleocytosis.' },
    { id: 261, subject: 'Pathology', text: 'Subarachnoid hemorrhage most commonly results from which of the following conditions?', options: ['Rupture of the middle meningeal artery following temporal bone fracture', 'Tearing of bridging veins due to acceleration–deceleration injury', 'Hypertensive rupture of small penetrating arteries within brain parenchyma', 'Rupture of a saccular (berry) aneurysm in the circle of Willis', 'Hemorrhage from fragile vessels in the germinal matrix'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Subarachnoid haemorrhage most commonly results from rupture of a saccular (berry) aneurysm in the Circle of Willis. Rupture of the middle meningeal artery causes an epidural haematoma. Tearing of bridging veins causes a subdural haematoma. Hypertensive rupture of small penetrating arteries causes an intracerebral haemorrhage (basal ganglia). Hemorrhage from fragile vessels in the germinal matrix causes an intraventricular haemorrhage in premature infants.' },
    { id: 262, subject: 'Pathology', text: 'Deficiency of which enzyme is responsible for Gaucher disease?', options: ['Hexosaminidase A – Tay-Sachs disease', 'Galactocerebrosidase – Krabbe disease', 'Arylsulfatase A – Metachromatic leukodystrophy', 'Glucocerebrosidase', 'Sphingomyelinase – Niemann-Pick disease'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Gaucher disease is caused by a deficiency of glucocerebrosidase, leading to accumulation of glucocerebroside. Hexosaminidase A deficiency causes Tay-Sachs disease, galactocerebrosidase deficiency causes Krabbe disease, arylsulfatase A deficiency causes metachromatic leukodystrophy, and sphingomyelinase deficiency causes Niemann-Pick disease. Glucocerebrosidase is the enzyme deficient in Gaucher disease.' },
    { id: 263, subject: 'Pathology', text: 'Which histopathological features are characteristic of glioblastoma multiforme (GBM)?', options: ['Perivascular lymphocytic cuffing – viral encephalitis', 'Rosenthal fibers – pilocytic astrocytoma', 'Homer-Wright rosettes – medulloblastoma', 'Necrosis and pseudopalisading', 'Ependymal rosettes – ependymoma'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Glioblastoma multiforme is characterised by necrosis and pseudopalisading (tumour cells arranged around areas of necrosis). This is a hallmark feature of grade IV astrocytoma. Perivascular lymphocytic cuffing is seen in viral encephalitis, Rosenthal fibres in pilocytic astrocytoma, Homer-Wright rosettes in medulloblastoma, and ependymal rosettes in ependymoma. Necrosis and pseudopalisading are specific to GBM.' },
    { id: 264, subject: 'Pathology', text: 'A 40 year old man presents with progressive involuntary movements, personality changes, and memory decline. Family history shows a similar disorder affecting multiple generations. Brain histopathology shows marked neuronal loss and gliosis in the caudate nucleus and putamen with cortical atrophy. Which genetic abnormality explains this disease?', options: ['CGG repeat expansion in FMR1 gene', 'CAG repeat deletion in gene coding for huntingtin protein', 'CAG repeat expansion in gene coding for huntingtin protein', 'Point mutation of gene encoding α-synuclein', 'Duplication mutation of gene encoding α-synuclein'], answer: 2, meta: 'Assessment 1 – 2023', explanation: 'Huntington\'s disease is an autosomal dominant disorder caused by a CAG repeat expansion in the huntingtin gene on chromosome 4. It presents with progressive involuntary movements (chorea), personality changes, memory decline, and neuronal loss in the caudate nucleus and putamen. CGG repeat expansion in FMR1 causes Fragile X syndrome, α-synuclein mutations cause Parkinson\'s disease, and deletions are not typical for Huntington\'s.' },
    { id: 265, subject: 'Pathology', text: 'A 65-year-old patient presents with difficulty initiating walking, and a shuffling gait. Examination shows a resting tremor and muscle stiffness. Brain histology reveals intracytoplasmic Lewy bodies and loss of neurons in the substantia nigra. What is the most prominent clinical feature?', options: ['Muscle rigidity', 'Resting tremor', 'Postural instability', 'Bradykinesia and slow movement', 'Cognitive decline'], answer: 3, meta: 'Assessment 1 – 2023 – Session 2', explanation: 'Parkinson\'s disease is characterised by bradykinesia (slow movements), resting tremor, rigidity, and postural instability. The most prominent clinical feature (cardinal feature) is bradykinesia and slow movement. Lewy bodies and loss of neurons in the substantia nigra are the pathological hallmarks. While resting tremor and rigidity are also important, bradykinesia is the most characteristic motor symptom.' },
    { id: 266, subject: 'Pathology', text: 'A 28-year-old woman presents with recurrent episodes of paresthesia and weakness that improve and then recur over time. Her symptoms have followed a relapsing-remitting pattern over the past two years. Which of the following is the most likely diagnosis?', options: ['Guillain-Barré syndrome', 'Myasthenia gravis', 'Multiple sclerosis', 'Amyotrophic lateral sclerosis', 'Parkinson disease'], answer: 2, meta: '', explanation: 'Multiple sclerosis is the most likely diagnosis in a young woman with a relapsing-remitting pattern of paresthesia and weakness. Guillain-Barré syndrome is an acute, monophasic illness. Myasthenia gravis presents with fluctuating muscle weakness and fatigue. Amyotrophic lateral sclerosis presents with progressive motor weakness without sensory involvement. Parkinson disease presents with motor symptoms such as tremor and bradykinesia.' },
    { id: 267, subject: 'Pathology', text: 'A 72-year-old man is brought by his family because of progressive memory loss, difficulty recognizing familiar people, and impaired daily functioning over the past 3 years. Neuropathological examination of his brain is most likely to reveal which of the following findings?', options: ['Demyelinated plaques in the white matter', 'Loss of Purkinje cells in the cerebellum', 'Neuritic plaques and neurofibrillary tangles', 'Degeneration of the caudate nucleus', 'Presence of Reed–Sternberg cells'], answer: 2, meta: '', explanation: 'Alzheimer\'s disease is characterised by progressive memory loss, difficulty recognizing familiar people, and impaired daily functioning. Neuropathological findings include neuritic plaques (extracellular amyloid-β) and neurofibrillary tangles (intracellular hyperphosphorylated tau). Demyelinated plaques are seen in multiple sclerosis, loss of Purkinje cells in cerebellar degeneration, degeneration of the caudate nucleus in Huntington\'s disease, and Reed–Sternberg cells in Hodgkin\'s lymphoma.' },
    { id: 268, subject: 'Pathology', text: 'A 5-year-old child presents with headache, vomiting, and gait instability. Imaging reveals a midline posterior fossa mass. Histology shows sheets of small, round, primitive cells with high nuclear-to-cytoplasmic ratio, consistent with an embryonal tumour. The most likely diagnosis is:', options: ['Medulloblastoma', 'Pilocytic astrocytoma', 'Ependymoma', 'Oligodendroglioma', 'Meningioma'], answer: 0, meta: 'Final 2 – 2019', explanation: 'Medulloblastoma is a primitive neuroectodermal tumour in the posterior fossa (cerebellum) in children. It consists of sheets of small, round, primitive cells with high nuclear-to-cytoplasmic ratio. Pilocytic astrocytoma is a cerebellar tumour with Rosenthal fibres, ependymoma has perivascular rosettes, oligodendroglioma has "fried-egg" cells, and meningioma is extra-axial.' },
    { id: 269, subject: 'Pathology', text: 'A 30-year-old patient presents with headache, fever, and focal neurological deficits. Brain imaging with contrast shows a ring-enhancing lesion in the cerebral hemisphere with surrounding oedema. Which of the following is the most likely diagnosis?', options: ['Glioblastoma', 'Meningioma', 'Chronic Brain Abscess', 'Oligodendroglioma', 'Pituitary Adenoma'], answer: 2, meta: 'Assessment 2 – 2020', explanation: 'A chronic brain abscess presents as a ring-enhancing lesion with surrounding oedema on imaging, accompanied by fever and focal neurological deficits. Glioblastoma is a ring-enhancing lesion but typically occurs in older patients without fever. Meningioma is extra-axial and dural-based. Oligodendroglioma is intra-axial with calcifications. Pituitary adenoma is in the sella turcica. The presence of fever suggests an infectious/inflammatory process.' },
    { id: 270, subject: 'Pathology', text: 'Cerebral infarction is an example of which type of necrosis?', options: ['Coagulative necrosis', 'Caseous necrosis', 'Liquefactive necrosis', 'Fat necrosis', 'Fibrinoid necrosis'], answer: 2, meta: 'Final 2 – 2024', explanation: 'Cerebral infarction is an example of liquefactive necrosis. The brain tissue undergoes liquefaction due to the release of lysosomal enzymes from leukocytes and the high lipid content of the brain, forming a cystic cavity. Coagulative necrosis is typical of ischaemia in solid organs (heart, kidney). Caseous necrosis is seen in tuberculosis, fat necrosis in pancreatitis, and fibrinoid necrosis in vasculitis.' },
    { id: 271, subject: 'Pathology', text: 'A patient presents with fever and signs of encephalitis. Imaging shows temporal lobe affection. Which of the following is the most likely mechanism of this condition?', options: ['Hematogenous spread to brain', 'Reactivation with axonal transport to temporal lobe (HSV)', 'Direct invasion from nasal cavity', 'Vector-borne transmission', 'Immune-mediated demyelination'], answer: 1, meta: 'Final 2 – 2022', explanation: 'Herpes simplex virus (HSV) encephalitis typically affects the temporal lobes. The mechanism is reactivation of latent HSV from the trigeminal ganglion with axonal transport to the temporal lobe. Hematogenous spread is less common for HSV. Direct invasion from the nasal cavity is seen in fungal infections. Vector-borne transmission is for arboviruses. Immune-mediated demyelination is seen in multiple sclerosis.' },
    { id: 272, subject: 'Pathology', text: 'Which of the following cerebrospinal fluid (CSF) findings is most characteristic of bacterial meningitis?', options: ['Normal pressure, clear fluid, normal protein, normal glucose, lymphocytes predominance', 'Slightly elevated pressure, clear fluid, mildly increased protein, normal glucose, mixed cells', 'Increased pressure, cloudy CSF, increased protein, decreased glucose, neutrophil predominance', 'Elevated pressure, clear fluid, normal protein, decreased glucose, eosinophil predominance', 'Low pressure, xanthochromic fluid, normal protein, normal glucose, lymphocytes predominance'], answer: 2, meta: 'Final 2 – 2019', explanation: 'Bacterial meningitis is characterised by increased CSF pressure, cloudy appearance, elevated protein, decreased glucose, and neutrophil predominance. Viral meningitis has normal pressure, clear fluid, normal or mildly elevated protein, normal glucose, and lymphocytic predominance. Tuberculous meningitis has decreased glucose and elevated protein with lymphocytic predominance. Fungal meningitis has similar findings to tuberculous meningitis.' },
    { id: 273, subject: 'Pathology', text: '28-year-old woman presents with intermittent episodes of muscle weakness, numbness in her limbs, and visual disturbances over the past several months. MRI shows lesions in the white matter of the brain and spinal cord. Laboratory studies reveal no evidence of infection. Which of the following best describes the characteristics of this disease?', options: ['Demyelinating disease affecting white matter', 'Neurodegenerative disease primarily affecting gray matter', 'Infectious disease-causing brain inflammation', 'Vascular disorder leading to ischemic brain lesions', 'Autoimmune disease targeting peripheral nerves'], answer: 0, meta: 'Assessment 2 – 2023', explanation: 'Multiple sclerosis is a demyelinating disease affecting white matter of the CNS. It presents with relapsing-remitting episodes of neurological deficits (muscle weakness, numbness, visual disturbances) and MRI shows white matter plaques. It is an autoimmune disease targeting CNS myelin (oligodendrocytes), not peripheral nerves. It is not a neurodegenerative disease, infectious disease, or vascular disorder.' },
    { id: 274, subject: 'Pathology', text: 'A 28-year-old woman experiences recurrent episodes of paresthesia that resolve partially between attacks. The most likely diagnosis is:', options: ['Guillain-Barré syndrome', 'Peripheral neuropathy', 'Multiple sclerosis', 'Myasthenia gravis', 'Stroke'], answer: 2, meta: 'Final 2 – 2019 · Final 2 – 2020', explanation: 'Multiple sclerosis presents with recurrent episodes of neurological deficits (paresthesia, weakness) that resolve partially between attacks (relapsing-remitting pattern). Guillain-Barré syndrome is an acute, monophasic ascending paralysis. Peripheral neuropathy is progressive. Myasthenia gravis presents with fluctuating muscle weakness, and stroke is acute and focal. The relapsing-remitting pattern is classic for MS.' },
    { id: 275, subject: 'Pathology', text: 'Which of the following are characteristic pathological features of Alzheimer\'s disease?', options: ['Lewy bodies and demyelination', 'Neuritic plaques and neurofibrillary tangles', 'Pick bodies and gliosis', 'Rosenthal fibers and cystic lesions', 'Spongiform changes and vacuolation'], answer: 1, meta: 'Final 2 – 2020', explanation: 'Alzheimer\'s disease is characterised by neuritic plaques (extracellular amyloid-β deposits) and neurofibrillary tangles (intracellular hyperphosphorylated tau). Lewy bodies are seen in Parkinson\'s disease and dementia with Lewy bodies. Pick bodies are seen in frontotemporal dementia. Rosenthal fibres are seen in pilocytic astrocytoma. Spongiform changes are seen in prion diseases.' },
    { id: 276, subject: 'Pathology', text: 'Which of the following cells is primarily affected in a demyelinating disease that presents with muscle weakness and loss of sensation?', options: ['Schwann cells', 'Astrocytes', 'Microglia', 'Ependymal cells', 'Oligodendrocytes'], answer: 4, meta: 'Final 2 – 2018', explanation: 'In demyelinating diseases of the CNS (such as multiple sclerosis), oligodendrocytes are the cells primarily affected. These cells produce myelin in the CNS. Schwann cells are the myelin-producing cells in the PNS and are affected in peripheral neuropathies. Astrocytes, microglia, and ependymal cells are not directly responsible for myelin production.' },
    { id: 277, subject: 'Pathology', text: 'Which of the following statements about Alzheimer\'s disease is correct?', options: ['It is commonly seen in females with Turner syndrome', 'Muscle weakness is a typical presenting feature', 'Male with Down syndrome has increased risk of developing the disease', 'It primarily affects motor neurons', 'It is associated with Fragile X syndrome'], answer: 2, meta: 'Final 2 – 2018', explanation: 'Individuals with Down syndrome (trisomy 21) have an increased risk of developing Alzheimer\'s disease due to the presence of an extra copy of the amyloid precursor protein (APP) gene on chromosome 21. This leads to early-onset Alzheimer\'s disease. Turner syndrome is not associated with Alzheimer\'s. Muscle weakness is not a typical presenting feature of Alzheimer\'s (it is cognitive decline). It does not primarily affect motor neurons (that is ALS). It is not associated with Fragile X syndrome.' },
    { id: 278, subject: 'Pathology', text: 'A 28-year-old woman presents with intermittent episodes of blurred vision, weakness of the limbs, and numbness over the past two years. The symptoms improve partially but recur after several months. MRI of the brain shows multiple demyelinating plaques in the white matter of the CNS. Which of the following is the most likely diagnosis?', options: ['Guillain-Barré Syndrome', 'Myasthenia Gravis', 'Amyotrophic Lateral Sclerosis', 'Multiple Sclerosis', 'Parkinson Disease'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Multiple sclerosis is the most likely diagnosis in a young woman with relapsing-remitting neurological symptoms (blurred vision, weakness, numbness) and MRI showing multiple demyelinating plaques in the CNS white matter. Guillain-Barré syndrome is an acute, monophasic ascending paralysis. Myasthenia gravis presents with fluctuating muscle weakness and fatigue. Amyotrophic lateral sclerosis presents with both upper and lower motor neuron signs without sensory involvement. Parkinson disease presents with motor symptoms such as tremor and bradykinesia.' },
    { id: 279, subject: 'Pathology', text: 'A 22-year-old basketball player suddenly develops a severe headache during a game. Imaging reveals a subarachnoid hemorrhage. Rupture of which of the following structures is the most likely cause?', options: ['Charcot-Bouchard aneurysm', 'Congenital berry aneurysm', 'Epidural hematoma', 'Bridging vein rupture', 'Middle meningeal artery rupture'], answer: 1, meta: '', explanation: 'Subarachnoid haemorrhage most commonly results from rupture of a congenital berry (saccular) aneurysm in the Circle of Willis. Charcot-Bouchard aneurysms are associated with hypertension and cause intracerebral haemorrhages. Epidural haematoma is caused by rupture of the middle meningeal artery. Bridging vein rupture causes subdural haematoma. The middle meningeal artery rupture causes an epidural haematoma, not a subarachnoid haemorrhage.' },
    { id: 280, subject: 'Pathology', text: 'A 32-year-old patient presents for a screening evaluation due to a family history of retinal hemangioblastomas and cerebellar tumours. Imaging reveals bilateral cystic renal masses suspicious for renal cell carcinoma. Which of the following genetic conditions is the most likely diagnosis?', options: ['Lynch syndrome', 'Von Hippel-Lindau disease', 'Cowden syndrome', 'Familial adenomatous polyposis', 'Neurofibromatosis type 1'], answer: 1, meta: '', explanation: 'Von Hippel-Lindau (VHL) disease is an autosomal dominant disorder associated with retinal hemangioblastomas, cerebellar haemangioblastomas, renal cell carcinoma, and pheochromocytoma. Lynch syndrome is associated with colorectal cancer, Cowden syndrome with hamartomas, familial adenomatous polyposis with colorectal polyps, and neurofibromatosis type 1 with neurofibromas and café-au-lait spots. The combination of retinal hemangioblastomas, cerebellar tumours, and renal cell carcinoma is classic for VHL.' },
    { id: 281, subject: 'Pathology', text: 'A pediatric patient presents with signs of cerebellar dysfunction such as ataxia and headache. Imaging suggests a slow-growing tumour of the cerebellum. Histopathological examination reveals biphasic patterns with Rosenthal fibers. Which of the following is the most likely diagnosis?', options: ['Medulloblastoma', 'Ependymoma', 'Pilocytic astrocytoma', 'Oligodendroglioma', 'Glioblastoma multiforme'], answer: 2, meta: '', explanation: 'Pilocytic astrocytoma is a slow-growing cerebellar tumour in children, presenting with ataxia and headache. It has biphasic patterns (solid and cystic) and Rosenthal fibres on histology. Medulloblastoma is a primitive neuroectodermal tumour with small round cells. Ependymoma has perivascular rosettes. Oligodendroglioma has "fried-egg" cells. Glioblastoma has necrosis and pseudopalisading. The presence of Rosenthal fibres is characteristic of pilocytic astrocytoma.' },

    // ─── PARASITOLOGY (282–340) ──────────────────────────────────────────
    { id: 282, subject: 'Parasitology', text: '12-year-old child develops sudden-onset headache, fever, stiff neck, and rapidly progressing coma after swimming in a warm freshwater lake. Cerebrospinal fluid examination shows motile trophozoites. Which of the following best describes the prognosis of Naegleria Acute Primary Amoebic Meningoencephalitis?', options: ['Usually self-limiting', 'Chronic with relapses', 'Mild and resolves with supportive care', 'Rarely serious, responds well to antibiotics', 'Usually fatal'], answer: 4, meta: 'Assessment 2 – 2020 · Assessment 2 – 2023', explanation: 'Naegleria fowleri causes primary amoebic meningoencephalitis (PAM), which is almost always fatal. The prognosis is extremely poor, with a mortality rate of over 95%. The infection progresses rapidly, often leading to death within days. It is not self-limiting, does not have relapses, and does not respond to antibiotics. Early treatment with amphotericin B may be attempted but is rarely successful.' },
    { id: 283, subject: 'Parasitology', text: 'A patient dies suddenly after swimming in a freshwater lake. Postmortem investigation reveals severe brain infection. Laboratory studies show a non-nutrient organism identified as Naegleria fowleri (formerly E. coli–type amoeba). Which of the following methods is most commonly used to confirm the diagnosis?', options: ['Non nutrient with E.Choli', 'Blood culture', 'CSF Gram stain', 'Serology for viral antibodies', 'Stool microscopy'], answer: 0, meta: 'Final 2 – 2024', explanation: 'Naegleria fowleri is diagnosed by culturing the organism on non-nutrient agar with Escherichia coli (E. coli) as a food source. The amoebae feed on the bacteria and can be identified. Blood culture, CSF Gram stain, serology, and stool microscopy are not used for the diagnosis of Naegleria fowleri. The organism is a free-living amoeba found in warm freshwater environments.' },
    { id: 284, subject: 'Parasitology', text: 'A 10-year-old boy is brought to the emergency department with high fever, severe headache, and vomiting. His parents report that his condition rapidly worsened over the past day, and he is now confused and irritable. On examination, he has neck stiffness and altered level of consciousness. Three days earlier, he had been swimming and diving in a warm freshwater lake. Which of the following is the most likely causative organism?', options: ['Acanthamoeba cyst', 'Entamoeba histolytica trophozoite', 'Ameboid trophozoite of Naegleria fowleri', 'Toxoplasma gondii tachyzoite', 'Cryptococcus neoformans'], answer: 2, meta: 'Final 2 – 2022', explanation: 'Naegleria fowleri causes primary amoebic meningoencephalitis (PAM) and is associated with swimming in warm freshwater lakes. The organism is an ameboid trophozoite that enters the brain through the olfactory nerve. Acanthamoeba causes granulomatous amoebic encephalitis (more chronic), Entamoeba histolytica causes intestinal amoebiasis, Toxoplasma gondii causes toxoplasmosis (immunocompromised), and Cryptococcus neoformans causes fungal meningitis. The rapid progression and history of swimming in warm freshwater point to Naegleria fowleri.' },
    { id: 285, subject: 'Parasitology', text: 'A patient who wears contact lenses presents with painful left eye keratitis. Microscopic examination of corneal scrapings reveals trophozoites and cysts. Which of the following represents the diagnostic stage of the causative organism?', options: ['Trophozoite only', 'Cyst only', 'Acanthamoeba trophozoite and cyst', 'Sporozoite', 'Oocyst'], answer: 2, meta: 'Final 2 – 2020', explanation: 'Acanthamoeba causes keratitis in contact lens wearers. The diagnostic stages are both trophozoites and cysts, which can be seen in corneal scrapings. Trophozoites are the active, feeding stage, and cysts are the dormant, resistant stage. Both stages are characteristic of Acanthamoeba. Sporozoites are for Plasmodium, oocysts are for Toxoplasma and Cryptosporidium, and trophozoites only is not sufficient because cysts are also a key diagnostic feature.' },
    { id: 286, subject: 'Parasitology', text: 'A patient develops rapidly progressive meningoencephalitis and dies after swimming in warm freshwater. Which of the following is the infective/diagnostic form of the causative organism?', options: ['Cyst of Acanthamoeba', 'Amoeboid trophozoite of Naegleria fowleri', 'Oocyst of Toxoplasma gondii', 'Sporozoite of Plasmodium falciparum', 'Cyst of Giardia lamblia'], answer: 1, meta: 'Final 2 – 2018', explanation: 'Naegleria fowleri causes primary amoebic meningoencephalitis (PAM). The infective and diagnostic form is the ameboid trophozoite, which enters the brain through the olfactory nerve. Acanthamoeba cysts are the infective form for granulomatous amoebic encephalitis and keratitis. Oocysts of Toxoplasma are for toxoplasmosis, sporozoites of Plasmodium are for malaria, and cysts of Giardia are for giardiasis.' },
    { id: 287, subject: 'Parasitology', text: 'Which of the following statements is true about granulomatous amoebic infections caused by Acanthamoeba?', options: ['They only infect the gastrointestinal tract', 'They are restricted to the CNS', 'Can infect eye, skin, and CNS', 'They are transmitted by mosquito bites', 'They only cause pulmonary infections'], answer: 2, meta: 'Final 2 – 2018', explanation: 'Acanthamoeba can cause granulomatous amoebic encephalitis (GAE), keratitis (eye infection), and skin infections. It is not restricted to the CNS; it can infect multiple sites. It does not infect the gastrointestinal tract, is not transmitted by mosquito bites, and does not cause pulmonary infections primarily. Acanthamoeba is found in soil and water and enters through skin wounds, the respiratory tract, or contact lenses.' },
    { id: 288, subject: 'Parasitology', text: 'Which of the following free-living amoebae is a flagellated protozoan that can cause primary amoebic meningoencephalitis (PAM)?', options: ['Acanthamoeba – non-flagellated, granulomatous infection', 'Balamuthia – non-flagellated, granulomatous infection', 'Naegleria fowleri – flagellated amoeba causing primary amoebic meningoencephalitis', 'Entamoeba histolytica – intestinal amoeba', 'Giardia lamblia – intestinal flagellate, non-CNS'], answer: 2, meta: 'Final 2 – Summer – 2022', explanation: 'Naegleria fowleri is a flagellated free-living amoeba that causes primary amoebic meningoencephalitis (PAM). It is the only free-living amoeba that has a flagellated stage. Acanthamoeba and Balamuthia are non-flagellated and cause granulomatous amoebic encephalitis (GAE). Entamoeba histolytica is an intestinal amoeba, and Giardia lamblia is an intestinal flagellate. Naegleria fowleri is the only one that causes PAM and has a flagellated form.' },
    { id: 289, subject: 'Parasitology', text: 'A 35-year-old Japanese man presents to the clinic with swelling around both eyes and complaints of redness and irritation in his eyes. He also notices small, firm nodules on the conjunctiva that have been slowly enlarging over the past few weeks. He reports mild itching but no significant pain. On further questioning, he mentions that he frequently catches and handles frogs while working in ponds in rural areas. Laboratory tests show mild eosinophilia, and imaging of the orbits reveals subcutaneous nodular lesions near the eyes. Which of the following is the most likely diagnosis?', options: ['Ocular cysticercosis', 'Neurocysticercosis', 'Sparganosis', 'Toxocariasis', 'Toxoplasmosis'], answer: 2, meta: 'Assessment 2 – 2023', explanation: 'Sparganosis is a parasitic infection caused by the plerocercoid larvae of Spirometra species (sparganum). It is acquired by handling frogs or drinking contaminated water containing infected copepods. Clinical features include subcutaneous nodules, ocular involvement, and eosinophilia. Ocular cysticercosis is caused by Taenia solium, neurocysticercosis is cerebral cysticercosis, toxocariasis is caused by Toxocara (visceral larva migrans), and toxoplasmosis is caused by Toxoplasma gondii. The history of handling frogs points to sparganosis.' },
    { id: 290, subject: 'Parasitology', text: 'A 40-year-old Chinese patient presents with visual disturbances. Imaging reveals a 20 cm elongated, glistening mass in the left occipital lobe. The patient reported that he drinks clean water. Histopathology confirms a parasitic etiology. Which of the following is the most likely diagnosis the source of infection?', options: ['Human', 'Dogs', 'Cyclops', 'Autoinfection', 'Frogs'], answer: 3, meta: 'Final 2 – 2024', explanation: 'This case describes sparganosis with a large (20 cm) elongated, glistening mass in the occipital lobe. Sparganosis is caused by plerocercoid larvae (sparganum) of Spirometra species. The infection can occur through autoinfection, ingestion of infected copepods (Cyclops), or handling frogs. The patient drinks clean water, so cyclops is less likely. The source of infection in this case is likely autoinfection (ingestion of infected material). The mass in the occipital lobe is consistent with cerebral sparganosis.' },
    { id: 291, subject: 'Parasitology', text: 'A patient is found to have cystic lesions containing a scolex and calcification on CT imaging. The infection is most likely acquired through which of the following?', options: ['Ingestion of larval cysts in undercooked beef', 'Ingestion of eggs of Taenia solium', 'Skin penetration by procercoid larvae in contaminated water', 'Inhalation of airborne parasitic spores', 'Ingestion of freshwater fish contaminated with cyclops'], answer: 1, meta: 'Final 2 – 2018 · Final 2 – 2020 · Final 2 – 2019', explanation: 'Cystic lesions containing a scolex and calcification are characteristic of neurocysticercosis, caused by Taenia solium. The infection is acquired by ingestion of Taenia solium eggs, which hatch in the intestine and form cysticercus larvae (cysticercus cellulosae) in various tissues, including the brain. Ingestion of larval cysts in undercooked beef causes taeniasis (intestinal infection with Taenia saginata). Skin penetration, inhalation, and ingestion of contaminated fish are not modes of transmission for Taenia solium.' },
    { id: 292, subject: 'Parasitology', text: 'Which of the following measures is most effective in preventing infection with Taenia solium?', options: ['Cooking pork thoroughly before consumption', 'Avoiding undercooked beef', 'Avoid direct contact with frogs', 'Avoiding drinking contaminated water', 'Boiling water before drinking'], answer: 0, meta: 'Final 2 – 2020', explanation: 'The most effective measure in preventing infection with Taenia solium is cooking pork thoroughly before consumption. This prevents the ingestion of cysticercus larvae (cysticercus cellulosae) in undercooked pork. Avoiding undercooked beef prevents Taenia saginata infection (taeniasis). Avoiding direct contact with frogs prevents sparganosis. Avoiding contaminated water prevents various infections. Boiling water is not specific for Taenia solium prevention.' },
    { id: 293, subject: 'Parasitology', text: 'Which of the following parasitic infections can involve autoinfection, leading to cysticercosis?', options: ['Cysticercus cellulosae', 'Taenia solium', 'Sparganum mansoni', 'Procercoid larvae', 'Toxoplasma gondii'], answer: 1, meta: 'Final 2 – Summer – 2022', explanation: 'Taenia solium can cause cysticercosis through autoinfection. Autoinfection occurs when a person with an adult Taenia solium tapeworm ingests eggs (from fecal-oral contamination), leading to the development of cysticercus larvae in tissues. Cysticercus cellulosae is the larval stage, not the infection itself. Sparganum mansoni is the larval stage of Spirometra, and procercoid larvae are part of the life cycle. Toxoplasma gondii does not cause cysticercosis.' },
    { id: 294, subject: 'Parasitology', text: 'A 30-year-old man presents with recurrent seizures and headaches. Brain imaging reveals multiple cystic lesions containing calcifications. He reports poor hygiene and exposure to contaminated food and water. The condition is most likely caused by ingestion of:', options: ['Encysted larvae in undercooked pork', 'Adult worms in contaminated meat', 'Taenia eggs', 'Hookworm filariform larvae', 'Amoebic trophozoites'], answer: 2, meta: '', explanation: 'Neurocysticercosis presents with recurrent seizures, headaches, and multiple cystic lesions with calcifications on brain imaging. The condition is caused by ingestion of Taenia solium eggs, which develop into cysticercus larvae in the brain. Encysted larvae in undercooked pork cause taeniasis (intestinal infection). Adult worms in contaminated meat, hookworm larvae, and amoebic trophozoites do not cause neurocysticercosis. Poor hygiene and contaminated food/water are risk factors for Taenia solium egg ingestion.' },
    // ─── MISSING QUESTIONS (295–340) ──────────────────────────────────
    { id: 295, subject: 'Pharmacology', text: 'Which of the following drugs is used for migraine prophylaxis and can also help improve insomnia?', options: ['Propranolol', 'Sumatriptan', 'Amitriptyline', 'Topiramate', 'Ergotamine'], answer: 2, meta: 'Final 2 – 2024', explanation: 'Amitriptyline is used for migraine prophylaxis and has sedative properties that can help improve insomnia. It is a tricyclic antidepressant that is effective for migraine prevention. Propranolol and topiramate are also used for migraine prophylaxis but do not significantly improve insomnia. Sumatriptan and ergotamine are acute treatments, not prophylactic.' },
    { id: 296, subject: 'Pharmacology', text: 'Which of the following drugs is commonly used for the management of panic attacks?', options: ['Fluoxetine', 'Sertraline', 'Alprazolam', 'Buspirone', 'Propranolol'], answer: 2, meta: 'Final 2 – 2019 · Final 2 – 2018', explanation: 'Alprazolam (a benzodiazepine) is commonly used for the acute management of panic attacks due to its rapid onset of action. Fluoxetine and sertraline are SSRIs used for long-term treatment of panic disorder. Buspirone is for generalised anxiety disorder, and propranolol is for performance anxiety and tremors.' },
    { id: 297, subject: 'Pharmacology', text: 'Which of the following drugs acts as a GABA agonist with anticonvulsant properties?', options: ['Zolpidem', 'Phenytoin', 'Carbamazepine', 'Valproate', 'Ethosuximide'], answer: 3, meta: 'Final 2 – 2018', explanation: 'Valproate (valproic acid) acts as a GABA agonist (increases GABA levels) and has broad-spectrum anticonvulsant properties. Zolpidem is a hypnotic, phenytoin is a sodium channel blocker, carbamazepine is a sodium channel blocker, and ethosuximide is a T-type calcium channel blocker. Valproate is used for various seizure types.' },
    { id: 298, subject: 'Pharmacology', text: 'Which of the following sedative–hypnotic drugs used for insomnia can have its effects reversed by flumazenil?', options: ['Phenobarbital', 'Zolpidem', 'Diphenhydramine', 'Melatonin', 'Chloral hydrate'], answer: 1, meta: 'Final 2 – Summer – 2022', explanation: 'Zolpidem (a non-benzodiazepine hypnotic) has its effects reversed by flumazenil because it binds to the benzodiazepine receptor. Phenobarbital is a barbiturate and is not reversed by flumazenil. Diphenhydramine is an antihistamine, melatonin is a hormone, and chloral hydrate is a sedative – none are reversed by flumazenil.' },
    { id: 299, subject: 'Pharmacology', text: 'A patient undergoing an endoscopic procedure becomes excessively sedated after receiving midazolam. He develops respiratory depression and decreased responsiveness. Which of the following is the most appropriate antidote?', options: ['Naloxone', 'Atropine', 'Physostigmine', 'Flumazenil', 'N-acetylcysteine'], answer: 3, meta: '', explanation: 'Flumazenil is the specific antidote for midazolam (benzodiazepine) toxicity, reversing respiratory depression and sedation. Naloxone is for opioids, atropine for cholinergic toxicity, physostigmine for anticholinergic toxicity, and N-acetylcysteine for paracetamol overdose.' },
    { id: 300, subject: 'Pharmacology', text: 'Which of the following local anesthetic agents uniquely provides both local anesthesia and a vasoconstrictive effect?', options: ['Lidocaine', 'Bupivacaine', 'Cocaine', 'Procaine', 'Tetracaine'], answer: 2, meta: 'Assessment 2 – 2019', explanation: 'Cocaine uniquely provides both local anaesthesia and vasoconstriction. It blocks sodium channels (local anaesthesia) and inhibits norepinephrine reuptake (vasoconstriction). Other local anaesthetics do not have intrinsic vasoconstrictive properties and are often combined with adrenaline. Lidocaine and bupivacaine are commonly used with vasoconstrictors added.' },
    { id: 301, subject: 'Pharmacology', text: 'Which of the following anesthetic agents is contraindicated in a patient with ischemic heart disease (IHD)?', options: ['Propofol', 'Midazolam', 'Isoflurane', 'Etomidate', 'Fentanyl'], answer: 2, meta: 'Final 2 – 2019', explanation: 'Isoflurane is relatively contraindicated in patients with ischemic heart disease because it can cause coronary steal syndrome, potentially worsening myocardial ischaemia. Propofol, midazolam, etomidate, and fentanyl are generally safe in IHD patients, though they require careful monitoring.' },
    { id: 302, subject: 'Pharmacology', text: 'Which of the following anesthetic agents is preferred in a patient with hypotension?', options: ['Propofol', 'Etomidate', 'Isoflurane', 'Ketamine', 'Midazolam'], answer: 3, meta: 'Final 2 – 2018', explanation: 'Ketamine is preferred in patients with hypotension because it maintains cardiovascular stability and can even stimulate the sympathetic nervous system, increasing blood pressure. Propofol, etomidate, and midazolam can cause hypotension. Isoflurane is an inhalational agent that can also cause hypotension.' },
    { id: 303, subject: 'Pharmacology', text: 'Which of the following intravenous anesthetic agents is particularly useful in patients with Bronchial Asthma and Hypotension?', options: ['Propofol', 'Ketamine', 'Thiopental', 'Etomidate', 'Midazolam'], answer: 1, meta: 'Assessment 2 – 2019', explanation: 'Ketamine is particularly useful in patients with bronchial asthma (because it has bronchodilatory properties) and hypotension (because it maintains cardiovascular stability). Propofol and thiopental can cause hypotension and bronchoconstriction. Etomidate can cause hypotension in some patients. Midazolam is not ideal for induction in asthmatic patients.' },
    { id: 304, subject: 'Pharmacology', text: 'A 35-year-old patient with bronchial asthma requires general anesthesia. Which of the following anesthetic agents is preferred due to its bronchodilatory effects and hemodynamic stability?', options: ['Propofol', 'Thiopental', 'Isoflurane', 'Midazolam', 'Ketamine'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'Ketamine is preferred in patients with bronchial asthma due to its bronchodilatory effects and hemodynamic stability. Propofol and thiopental can cause bronchoconstriction. Isoflurane is an inhalational agent that can cause bronchoconstriction. Midazolam is not ideal for induction. Ketamine is the best choice for asthmatic patients.' },
    { id: 305, subject: 'Pharmacology', text: 'A patient with hypotension is scheduled to undergo surgery. Which of the following anesthetic agents is most appropriate?', options: ['Propofol', 'Thiopental', 'Ketamine', 'Isoflurane', 'Midazolam'], answer: 2, meta: 'Assessment 2 – 2023', explanation: 'Ketamine is the most appropriate anesthetic agent in a patient with hypotension because it maintains cardiovascular stability and can increase blood pressure. Propofol, thiopental, and midazolam can cause hypotension. Isoflurane is an inhalational agent that can also cause hypotension.' },
    { id: 306, subject: 'Pharmacology', text: 'Which of the following anesthetic agents is preferred in patients with bronchial asthma and hypotension due to its bronchodilatory and cardiovascular properties?', options: ['Propofol', 'Thiopental', 'Midazolam', 'Ketamine', 'Halothane'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Ketamine is preferred in patients with bronchial asthma and hypotension because of its bronchodilatory and cardiovascular stimulatory properties. Propofol, thiopental, and midazolam can cause bronchoconstriction and hypotension. Halothane is an inhalational agent that can cause arrhythmias and is not preferred.' },
    { id: 307, subject: 'Pharmacology', text: 'Which of the following anesthetic agents can be used to treat cardiac arrhythmias due to its antiarrhythmic properties?', options: ['Lidocaine', 'Propofol', 'Ketamine', 'Etomidate', 'Sevoflurane'], answer: 0, meta: 'Final 2 – 2018', explanation: 'Lidocaine is used as an antiarrhythmic agent (Class IB) to treat ventricular arrhythmias. It is also used as a local anesthetic. Propofol, ketamine, etomidate, and sevoflurane do not have significant antiarrhythmic properties. Lidocaine works by blocking sodium channels and is effective in treating ventricular tachycardia and fibrillation.' },
    { id: 308, subject: 'Pharmacology', text: 'A patient with ischemic heart disease is scheduled for surgery under general anesthesia. Which of the following inhalational anesthetic agents is relatively contraindicated because it may precipitate coronary steal phenomenon?', options: ['Nitrous oxide', 'Sevoflurane', 'Desflurane', 'Isoflurane', 'Halothane'], answer: 3, meta: '', explanation: 'Isoflurane is relatively contraindicated in patients with ischemic heart disease because it can cause coronary steal phenomenon, potentially worsening myocardial ischaemia. Sevoflurane and desflurane are less likely to cause coronary steal. Nitrous oxide and halothane are not typically associated with coronary steal.' },
    { id: 309, subject: 'Pharmacology', text: 'Which of the following antiepileptic drugs is most commonly associated with Stevens–Johnson syndrome?', options: ['Valproic acid', 'Levetiracetam', 'Lamotrigine', 'Ethosuximide', 'Gabapentin'], answer: 2, meta: 'Assessment 2 – 2023', explanation: 'Lamotrigine is most commonly associated with Stevens–Johnson syndrome, a severe cutaneous adverse reaction. It is more likely to occur with rapid dose titration. Valproic acid can cause hepatotoxicity, levetiracetam can cause behavioural changes, ethosuximide can cause GI upset, and gabapentin can cause sedation.' },
    { id: 310, subject: 'Pharmacology', text: 'Which of the following antiepileptic drugs is considered the drug of choice for Trigeminal Neuralgia?', options: ['Phenytoin', 'Valproic Acid', 'Lamotrigine', 'Levetiracetam', 'Carbamazepine'], answer: 4, meta: 'Assessment 2 – 2019', explanation: 'Carbamazepine is the drug of choice for trigeminal neuralgia. It is effective in reducing the sharp, stabbing pain associated with this condition. Phenytoin, lamotrigine, and valproic acid can also be used but are not first-line. Levetiracetam is not typically used for trigeminal neuralgia.' },
    { id: 311, subject: 'Pharmacology', text: 'Which of the following drugs is commonly used for the prophylaxis of Migraine?', options: ['Sumatriptan', 'Propranolol', 'Ergotamine', 'Metoclopramide', 'Ibuprofen'], answer: 1, meta: 'Assessment 2 – 2019', explanation: 'Propranolol (a beta-blocker) is commonly used for the prophylaxis of migraine. It reduces the frequency and severity of migraine attacks. Sumatriptan and ergotamine are used for acute treatment, metoclopramide is used for nausea, and ibuprofen is used for mild acute pain.' },
    { id: 312, subject: 'Pharmacology', text: 'Which of the following drugs is commonly used for chronic migraine prophylaxis?', options: ['Sumatriptan', 'Topiramate', 'Amitriptyline', 'Propranolol', 'Ibuprofen'], answer: 1, meta: 'Final 2 – 2020', explanation: 'Topiramate is commonly used for chronic migraine prophylaxis. It is an antiepileptic drug that has been shown to reduce migraine frequency. Amitriptyline and propranolol are also used for migraine prophylaxis, but topiramate is specifically indicated for chronic migraine. Sumatriptan is for acute treatment, and ibuprofen is for mild pain.' },
    { id: 313, subject: 'Pharmacology', text: 'Which of the following drugs is considered the safest for treating absence seizures in children, with minimal impact on cognition and learning?', options: ['Valproate', 'Lamotrigine', 'Carbamazepine', 'Phenytoin', 'Ethosuximide'], answer: 4, meta: 'Final 2 – 2019', explanation: 'Ethosuximide is considered the safest and most effective drug for treating absence seizures in children. It has minimal impact on cognition and learning compared to valproate and lamotrigine. Carbamazepine and phenytoin are not effective for absence seizures. Valproate can affect cognition and learning.' },
    { id: 314, subject: 'Pharmacology', text: 'Which of the following drugs is first-line for the acute treatment of moderate to severe migraine attacks?', options: ['Acetaminophen', 'Ibuprofen', 'Propranolol', 'Sumatriptan', 'Topiramate'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Sumatriptan (a triptan) is first-line for the acute treatment of moderate to severe migraine attacks. Acetaminophen and ibuprofen are for mild pain. Propranolol and topiramate are for migraine prophylaxis (prevention), not acute treatment. Triptans are the most effective for acute migraine with moderate to severe pain.' },
    { id: 315, subject: 'Pharmacology', text: 'Which of the following Benzodiazepines is commonly used for the management of Status Epilepticus due to its rapid onset of action and reliable anticonvulsant effect?', options: ['Phenytoin', 'Clonazepam', 'Alprazolam', 'Carbamazepine', 'Lorazepam'], answer: 4, meta: 'Assessment 2 – 2019', explanation: 'Lorazepam is the benzodiazepine of choice for the management of status epilepticus due to its rapid onset of action and reliable anticonvulsant effect. Diazepam is also used but has a shorter duration of action. Phenytoin and carbamazepine are not used acutely. Clonazepam and alprazolam are not first-line for status epilepticus.' },
    { id: 316, subject: 'Pharmacology', text: 'Which of the following drugs is most commonly associated with gingival hyperplasia as a side effect?', options: ['Carbamazepine', 'Valproic Acid', 'Phenytoin', 'Ethosuximide', 'Phenobarbital'], answer: 2, meta: 'Final 2 – Summer – 2022', explanation: 'Phenytoin is most commonly associated with gingival hyperplasia (gum overgrowth) as a side effect. This is a well-known adverse effect of phenytoin, occurring in up to 50% of patients. Carbamazepine, valproic acid, ethosuximide, and phenobarbital are not typically associated with gingival hyperplasia.' },
    { id: 317, subject: 'Pharmacology', text: 'Which of the following drugs is commonly used for prophylaxis of migraine?', options: ['Amitriptyline', 'Topiramate', 'Propranolol', 'Sumatriptan', 'Ibuprofen'], answer: 0, meta: 'Final 2 – 2018', explanation: 'Amitriptyline (a tricyclic antidepressant) is commonly used for the prophylaxis of migraine. Topiramate and propranolol are also used for migraine prophylaxis. Sumatriptan is for acute treatment, and ibuprofen is for mild acute pain. Amitriptyline is effective for migraine prevention and is often used in patients with sleep disturbances.' },
    { id: 318, subject: 'Pharmacology', text: 'Which of the following drugs is associated with gingival hyperplasia and may be less suitable for certain patients, including females?', options: ['Valproate', 'Carbamazepine', 'Lamotrigine', 'Phenytoin', 'Ethosuximide'], answer: 3, meta: 'Final 2 – 2018', explanation: 'Phenytoin is associated with gingival hyperplasia and may be less suitable for certain patients, including females of childbearing age due to teratogenic effects. Valproate and carbamazepine are also teratogenic but not associated with gingival hyperplasia. Lamotrigine and ethosuximide are not associated with gingival hyperplasia.' },
    { id: 319, subject: 'Pharmacology', text: 'Which of the following drugs is commonly associated with dilutional hyponatremia as an adverse effect?', options: ['Phenytoin', 'Carbamazepine', 'Valproate', 'Ethosuximide', 'Lamotrigine'], answer: 1, meta: 'Final 2 – 2018', explanation: 'Carbamazepine is commonly associated with dilutional hyponatremia as an adverse effect. It causes syndrome of inappropriate antidiuretic hormone (SIADH), leading to hyponatremia. Phenytoin, valproate, ethosuximide, and lamotrigine are not typically associated with hyponatremia. Carbamazepine-induced hyponatremia is more common in elderly patients.' },
    { id: 320, subject: 'Pharmacology', text: 'A patient on long-term treatment for trigeminal neuralgia develops hyponatremia with low serum osmolality and symptoms of water intoxication. Which of the following drugs is most likely responsible?', options: ['Phenytoin', 'Valproic Acid', 'Lamotrigine', 'Levetiracetam', 'Carbamazepine'], answer: 4, meta: 'Assessment 2 – 2020', explanation: 'Carbamazepine is the most likely cause of hyponatremia in a patient on long-term treatment for trigeminal neuralgia. Carbamazepine causes SIADH, leading to water retention and hyponatremia. Phenytoin, valproic acid, lamotrigine, and levetiracetam are not typically associated with hyponatremia. Carbamazepine is the drug of choice for trigeminal neuralgia.' },
    { id: 321, subject: 'Pharmacology', text: 'What is the primary mechanism of action of sumatriptan?', options: ['5-HT2 receptor antagonism', 'Dopamine D2 receptor blockade', 'GABA-A receptor potentiation', '5-HT1B/1D receptor agonism', 'CGRP receptor antagonism'], answer: 3, meta: 'Assessment 2 – 2023', explanation: 'Sumatriptan is a 5-HT1B/1D receptor agonist. It works by stimulating these receptors, which causes vasoconstriction of intracranial blood vessels and reduces the release of vasoactive neuropeptides. CGRP receptor antagonists are a newer class for migraine treatment. 5-HT2 receptor antagonists are not used for migraine.' },
    { id: 322, subject: 'Pharmacology', text: 'A 35-year-old woman reports frequent, recurrent headache attacks occurring more than 10 days per month, associated with nausea and photophobia. Her physician decides to start a medication to reduce the frequency of future attacks rather than treat acute pain episodes. Which of the following drugs is most appropriate for prophylaxis of Chronic migraine?', options: ['Sumatriptan', 'Propranolol', 'Ergotamine', 'Metoclopramide', 'Aspirin'], answer: 1, meta: '', explanation: 'Propranolol is the most appropriate drug for the prophylaxis of chronic migraine. It is a first-line preventive treatment. Sumatriptan and ergotamine are for acute treatment. Metoclopramide is for nausea. Aspirin is for mild acute pain. Propranolol reduces the frequency and severity of migraine attacks over time.' },
    { id: 323, subject: 'Pharmacology', text: 'Which of the following antidepressant drugs is associated with a low incidence of sexual dysfunction?', options: ['Fluoxetine', 'Paroxetine', 'Amitriptyline', 'Sertraline', 'Bupropion'], answer: 4, meta: 'Assessment 2 – 2023', explanation: 'Bupropion is associated with a low incidence of sexual dysfunction compared to SSRIs. Fluoxetine, paroxetine, and sertraline (SSRIs) are commonly associated with sexual dysfunction. Amitriptyline (a tricyclic antidepressant) can also cause sexual dysfunction but less commonly than SSRIs. Bupropion is often used as an alternative when sexual side effects occur with SSRIs.' },
    { id: 324, subject: 'Pharmacology', text: 'Which antidepressant is associated with minimal sexual dysfunction compared to SSRIs?', options: ['Fluoxetine', 'Sertraline', 'Paroxetine', 'Mirtazapine', 'Venlafaxine'], answer: 3, meta: 'Final 2 – Summer – 2022', explanation: 'Mirtazapine is associated with minimal sexual dysfunction compared to SSRIs. It is a noradrenergic and specific serotonergic antidepressant (NaSSA) that has a lower incidence of sexual side effects. Fluoxetine, sertraline, and paroxetine are SSRIs with significant sexual dysfunction. Venlafaxine is an SNRI that can also cause sexual dysfunction.' },
    { id: 325, subject: 'Pharmacology', text: 'Which of the following antidepressants is least likely to cause sexual dysfunction?', options: ['Fluoxetine', 'Sertraline', 'Paroxetine', 'Mirtazapine', 'Venlafaxine'], answer: 3, meta: 'Assessment 2 – 2019 · Assessment 2 – 2020', explanation: 'Mirtazapine is the least likely to cause sexual dysfunction among the listed antidepressants. It has a different mechanism of action (NaSSA) compared to SSRIs and SNRIs. Fluoxetine, sertraline, paroxetine, and venlafaxine all have higher rates of sexual dysfunction. Mirtazapine is often used when sexual side effects are a concern.' },
    { id: 326, subject: 'Pharmacology', text: 'Which of the following antidepressants is least likely to cause sexual dysfunction in patients?', options: ['Fluoxetine', 'Mirtazapine', 'Sertraline', 'Paroxetine', 'Venlafaxine'], answer: 1, meta: 'Assessment 2 – 2020', explanation: 'Mirtazapine is the least likely to cause sexual dysfunction among the listed antidepressants. It is a NaSSA with a lower incidence of sexual side effects compared to SSRIs and SNRIs. Fluoxetine, sertraline, paroxetine, and venlafaxine all have higher rates of sexual dysfunction. Mirtazapine is often used when sexual side effects are a concern.' },
    { id: 327, subject: 'Pharmacology', text: 'Which of the following drugs is used both as an antidepressant and for smoking cessation?', options: ['Bupropion', 'Fluoxetine', 'Sertraline', 'Mirtazapine', 'Amitriptyline'], answer: 0, meta: 'Final 2 – 2018', explanation: 'Bupropion is used both as an antidepressant and for smoking cessation. It works as a dopamine and norepinephrine reuptake inhibitor. Fluoxetine, sertraline, and paroxetine are SSRIs used for depression and anxiety. Mirtazapine is a NaSSA used for depression. Amitriptyline is a tricyclic antidepressant used for depression, migraine prophylaxis, and neuropathy.' },
    { id: 328, subject: 'Pharmacology', text: 'Which of the following drugs is an antidepressant that is not an SSRI?', options: ['Fluoxetine', 'Mirtazapine', 'Sertraline', 'Escitalopram', 'Paroxetine'], answer: 1, meta: 'Final 2 – 2018', explanation: 'Mirtazapine is an antidepressant that is not an SSRI – it is a NaSSA (noradrenergic and specific serotonergic antidepressant). Fluoxetine, sertraline, escitalopram, and paroxetine are all SSRIs. Mirtazapine has a different mechanism of action and side effect profile.' },
    { id: 329, subject: 'Pharmacology', text: 'A 30-year-old woman with relapsing–remitting multiple sclerosis continues to have relapses despite first-line disease-modifying therapy. Her neurologist decides to escalate treatment and starts a monthly intravenous therapy. Which of the following is the most likely drug?', options: ['Interferon-β', 'Fingolimod', 'Natalizumab', 'Glatiramer acetate', 'Teriflunomide'], answer: 2, meta: '', explanation: 'Natalizumab is a monthly intravenous therapy used as second-line treatment for relapsing-remitting multiple sclerosis when first-line therapies have failed. It is a monoclonal antibody against α4-integrin. Interferon-β and glatiramer acetate are first-line therapies. Fingolimod and teriflunomide are oral therapies.' },
    { id: 330, subject: 'Pharmacology', text: 'A 74-year-old patient with moderate Alzheimer disease is already receiving donepezil but shows progressive cognitive decline. The physician adds a drug that acts as an NMDA receptor antagonist to further improve symptoms. Which of the following drugs was most likely added?', options: ['Rivastigmine', 'Galantamine', 'Memantine', 'Selegiline', 'Fluoxetine'], answer: 2, meta: '', explanation: 'Memantine is an NMDA receptor antagonist used in moderate to severe Alzheimer\'s disease. It is often added to donepezil (a cholinesterase inhibitor) when cognitive decline progresses. Rivastigmine and galantamine are also cholinesterase inhibitors and would not be added if the patient is already on donepezil. Selegiline is used in Parkinson\'s disease, and fluoxetine is an SSRI.' },
    { id: 331, subject: 'Pharmacology', text: 'A 74-year-old woman with Alzheimer\'s disease is started on therapy to improve her cognitive symptoms. After a few days, she develops abdominal cramps and frequent loose stools. Which of the following drugs is most likely responsible for this adverse effect?', options: ['Memantine', 'Rivastigmine', 'Haloperidol', 'Fluoxetine'], answer: 1, meta: '', explanation: 'Rivastigmine (and other cholinesterase inhibitors) commonly cause gastrointestinal side effects, including abdominal cramps and diarrhoea. These are dose-dependent and can be minimised by starting at a low dose and titrating slowly. Memantine is less likely to cause GI symptoms. Haloperidol is an antipsychotic, and fluoxetine is an SSRI – both are not used for Alzheimer\'s cognitive symptoms.' },
    { id: 332, subject: 'Pharmacology', text: 'A patient presents with progressive muscle weakness, muscle wasting, fasciculations, and both upper and lower motor neuron signs, while sensory function remains intact. Which of the following drugs is used to slow disease progression in this condition?', options: ['Levodopa', 'Riluzole', 'Neostigmine', 'Diazepam'], answer: 1, meta: '', explanation: 'Riluzole is used to slow disease progression in Amyotrophic Lateral Sclerosis (ALS), which presents with both upper and lower motor neuron signs without sensory involvement. Levodopa is used in Parkinson\'s disease, neostigmine in myasthenia gravis, and diazepam as a muscle relaxant. Riluzole is the only drug approved to slow ALS progression.' },
    { id: 333, subject: 'Pharmacology', text: 'Which of the following antipsychotic medications is most associated with the potentially life-threatening side effect of agranulocytosis, requiring mandatory hematologic monitoring?', options: ['Olanzapine', 'Haloperidol', 'Risperidone', 'Clozapine', 'Aripiprazole'], answer: 3, meta: '', explanation: 'Clozapine is most associated with agranulocytosis, requiring mandatory hematologic monitoring (regular blood counts). Olanzapine, risperidone, and aripiprazole are second-generation antipsychotics with a lower risk of agranulocytosis. Haloperidol is a first-generation antipsychotic that can cause extrapyramidal side effects but not typically agranulocytosis.' },
    { id: 334, subject: 'Pharmacology', text: 'Which of the following antipsychotic drugs is most commonly associated with agranulocytosis and therefore requires regular blood count monitoring?', options: ['Haloperidol', 'Chlorpromazine', 'Risperidone', 'Olanzapine', 'Clozapine'], answer: 4, meta: '', explanation: 'Clozapine is most commonly associated with agranulocytosis and therefore requires regular blood count monitoring. It is the most effective antipsychotic for treatment-resistant schizophrenia but has a significant risk of agranulocytosis (1-2%). Haloperidol, chlorpromazine, risperidone, and olanzapine have lower risks of agranulocytosis.' },
    { id: 335, subject: 'Pharmacology', text: 'A patient who has been receiving long-term antipsychotic therapy develops repetitive involuntary orofacial movements suggestive of tardive dyskinesia, an extrapyramidal side effect. Which of the following drugs is the most likely cause?', options: ['Clozapine', 'Fluoxetine', 'Haloperidol', 'Diazepam', 'Lithium'], answer: 2, meta: '', explanation: 'Haloperidol (a typical antipsychotic) is most likely to cause tardive dyskinesia after long-term use. Tardive dyskinesia is a late-onset extrapyramidal side effect. Clozapine has the lowest risk of extrapyramidal side effects. Fluoxetine is an SSRI, diazepam is a benzodiazepine, and lithium is a mood stabilizer – none are typically associated with tardive dyskinesia.' },
    { id: 336, subject: 'Pharmacology', text: 'A patient experiencing severe nausea and vomiting after consuming alcohol while being treated for substance abuse is likely experiencing a reaction caused by which medication?', options: ['Naltrexone', 'Acamprosate', 'Disulfiram', 'Methadone', 'Buprenorphine'], answer: 2, meta: '', explanation: 'Disulfiram causes a severe reaction (nausea, vomiting, flushing, palpitations) when alcohol is consumed. It inhibits aldehyde dehydrogenase, leading to acetaldehyde accumulation. Naltrexone reduces alcohol craving, acamprosate helps maintain abstinence, methadone is used for opioid dependence, and buprenorphine is an opioid partial agonist.' },
    { id: 337, subject: 'Pharmacology', text: 'A man who recently decided to quit smoking is prescribed a medication to reduce nicotine craving and decrease relapse rates during smoking cessation therapy. Which of the following drugs was most likely prescribed?', options: ['Methadone', 'Naloxone', 'Disulfiram', 'Varenicline', 'Bupropion'], answer: 3, meta: '', explanation: 'Varenicline is the most effective medication for smoking cessation. It is a partial agonist at the α4β2 nicotinic acetylcholine receptor, reducing nicotine craving and withdrawal symptoms. Bupropion is also used for smoking cessation but is less effective than varenicline. Methadone is for opioid dependence, naloxone for opioid overdose, and disulfiram for alcohol dependence.' },
    { id: 338, subject: 'Pharmacology', text: 'A 28-year-old pregnant woman at 39 weeks\' gestation is found to be colonised with Streptococcus agalactiae (Group B Streptococcus). She is admitted in active labour. To prevent neonatal infection, which of the following interventions is most appropriate?', options: ['Administer ampicillin antepartum at 36 weeks during routine prenatal screening', 'Administer ampicillin intrapartum at the time of delivery', 'Give the newborn a dose of ampicillin immediately after birth', 'Delay antibiotic prophylaxis until after delivery to avoid maternal hypotension', 'Administer a single oral dose of penicillin to the mother at 38 weeks'], answer: 1, meta: 'Assessment 2 – 2019', explanation: 'The most appropriate intervention is to administer ampicillin intrapartum (during labour) to prevent neonatal Group B Streptococcus infection. Intrapartum antibiotic prophylaxis (IAP) is the standard of care for GBS-positive mothers. Antepartum antibiotics are not effective, and post-delivery treatment of the newborn is less effective.' },
    { id: 339, subject: 'Pharmacology', text: 'A 67-year-old patient presents with acute bacterial meningitis. Empiric therapy is started before culture results are available. Which of the following regimens is the recommended first-line empiric treatment for adults in this age group?', options: ['Ampicillin alone', 'Vancomycin alone', 'Ceftazidime + Gentamicin', 'Vancomycin + Ampicillin + Ceftriaxone', 'Penicillin G + Ciprofloxacin'], answer: 3, meta: 'Assessment 2 – 2020', explanation: 'The recommended empiric treatment for bacterial meningitis in adults >50 years is Vancomycin + Ampicillin + Ceftriaxone. This covers Streptococcus pneumoniae (vancomycin + ceftriaxone), Neisseria meningitidis (ceftriaxone), and Listeria monocytogenes (ampicillin), which is more common in older adults. Ceftazidime + gentamicin is not first-line for meningitis.' },
    { id: 340, subject: 'Pharmacology', text: 'Which of the following drugs is primarily used for the treatment of cognitive symptoms in Alzheimer\'s disease?', options: ['Donepezil', 'Memantine', 'Galantamine', 'Rivastigmine', 'Selegiline'], answer: 0, meta: 'Assessment 2 – 2020', explanation: 'Donepezil is a cholinesterase inhibitor used primarily for the treatment of cognitive symptoms in Alzheimer\'s disease. Memantine is an NMDA receptor antagonist used in moderate to severe Alzheimer\'s. Galantamine and rivastigmine are also cholinesterase inhibitors. Selegiline is used in Parkinson\'s disease.' }
];

